-- Poems batch 29
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('670009c2-a701-4140-aa31-b4973f76d632','隋宮','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u4e03\u8a00\u5f8b\u8bd7", "\u8bbd\u523a", "\u548f\u53f2"]','紫泉宮殿鎖煙霞，欲取蕪城作帝家。',64,'全唐诗/poet.tang.29000.json','["紫泉宮殿鎖煙霞，欲取蕪城作帝家。", "玉璽不緣歸日角，錦帆應是到天涯。", "于今腐草無螢火，終古垂楊有暮鴉。", "地下若逢陳後主，豈宜重問後庭花。"]'),
('7c73c112-1a3d-4408-ae4f-dba739d0bf7a','二月二日','李商隱','唐','唐诗','tang','','[]','二月二日江上行，東風日暖聞吹笙。',64,'全唐诗/poet.tang.29000.json','["二月二日江上行，東風日暖聞吹笙。", "花鬚柳眼各無賴，紫蝶黃蜂俱有情。", "萬里憶歸元亮井，三年從事亞夫營。", "新灘莫悟遊人意，更作風簷夜雨聲。"]'),
('131c9f87-273f-4684-9b67-bd7b58ad4008','籌筆驛','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u4e03\u8a00\u5f8b\u8bd7", "\u5178\u6545", "\u5199\u4eba", "\u548f\u53f2\u6000\u53e4"]','猿鳥猶疑畏簡書，風雲常爲護儲胥。',64,'全唐诗/poet.tang.29000.json','["猿鳥猶疑畏簡書，風雲常爲護儲胥。", "徒令上將揮神筆，終見降王走傳車。", "管樂有才終不忝，關張無命欲何如。", "他年錦里經祠廟，梁父吟成恨有餘。"]'),
('3caf535b-7cdd-40bb-8d50-9b25cb6831a8','屏風','李商隱','唐','唐诗','tang','','[]','六曲連環接翠帷，高樓半夜酒醒時。',32,'全唐诗/poet.tang.29000.json','["六曲連環接翠帷，高樓半夜酒醒時。", "掩燈遮霧密如此，雨落月明俱不知。"]'),
('e0b2be49-3f48-48c4-9e8a-43ec3dd42a36','春日','李商隱','唐','唐诗','tang','','[]','欲入盧家白玉堂，新春催破舞衣裳。',32,'全唐诗/poet.tang.29000.json','["欲入盧家白玉堂，新春催破舞衣裳。", "蝶銜紅蘂蜂銜粉，共助青樓一日忙。"]'),
('e525ae0b-4ca6-4a73-b50b-b703fab31cf5','武侯廟古柏','李商隱','唐','唐诗','tang','','[]','蜀相階前柏，龍蛇捧閟宮。',72,'全唐诗/poet.tang.29000.json','["蜀相階前柏，龍蛇捧閟宮。", "陰成外江畔，老向惠陵東。", "大樹思馮異，甘棠憶召公。", "葉凋湘燕雨，枝拆海鵬風。", "玉壘經綸遠，金刀歷數終。", "誰將出師表，一爲問昭融。"]'),
('3d80def6-d6de-4742-83e5-e5faef51cdcd','風','李商隱','唐','唐诗','tang','','[]','撩釵盤孔雀，惱帶拂鴛鴦。',24,'全唐诗/poet.tang.29000.json','["撩釵盤孔雀，惱帶拂鴛鴦。", "蘿薦誰教近，齋時鎖洞房。"]'),
('602939e3-7d7a-4513-8351-57542a010c1b','即日','李商隱','唐','唐诗','tang','','[]','一歲林花即日休，江間亭下悵淹留。',64,'全唐诗/poet.tang.29000.json','["一歲林花即日休，江間亭下悵淹留。", "重吟細把真無奈，已落猶開未放愁。", "山色正來銜小苑，春陰只欲傍高樓。", "金鞍忽散銀壺漏，更醉誰家白玉鉤。"]'),
('87beeed5-93f8-4ac6-a8e0-6bc7e42957c2','九成宮','李商隱','唐','唐诗','tang','','[]','十二層城閬苑西，平時避暑拂虹霓。',64,'全唐诗/poet.tang.29000.json','["十二層城閬苑西，平時避暑拂虹霓。", "雲隨夏后雙龍尾，風逐周王八駿蹄。", "吳岳曉光連翠巘，甘泉晚景上丹梯。", "荔枝盧橘沾恩幸，鸞鵲天書濕紫泥。"]'),
('84119cd7-ee93-4fb0-b56a-ab630f224665','少將','李商隱','唐','唐诗','tang','','[]','族亞齊安陸，風高漢武威。',48,'全唐诗/poet.tang.29000.json','["族亞齊安陸，風高漢武威。", "煙波別墅醉，花月後門歸。", "青海聞傳箭，天山報合圍。", "一朝攜劍起，上馬即如飛。"]'),
('04da453a-1a99-4019-ab79-410a591fc650','詠史','李商隱','唐','唐诗','tang','','[]','歷覽前賢國與家，成由勤儉破由奢。',64,'全唐诗/poet.tang.29000.json','["歷覽前賢國與家，成由勤儉破由奢。", "何須琥珀方爲枕，豈得真珠始是車。", "運去不逢青海馬，力窮難拔蜀山蛇。", "幾人曾預南薰曲，終古蒼梧哭翠華。"]'),
('55c9cbab-ff67-47db-9d3c-d9b7e6fe2495','贈白道者','李商隱','唐','唐诗','tang','','[]','十二樓前再拜辭，靈風正滿碧桃枝。',32,'全唐诗/poet.tang.29000.json','["十二樓前再拜辭，靈風正滿碧桃枝。", "壺中若是有天地，又向壺中傷別離。"]'),
('3410e7ce-df3a-4ab8-bea3-7f681661b240','無題二首 一','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5bb4\u996e", "\u4e03\u8a00\u5f8b\u8bd7", "\u7231\u60c5", "\u76f8\u601d", "\u611f\u6168"]','昨夜星辰昨夜風，畫樓西畔桂堂東。',64,'全唐诗/poet.tang.29000.json','["昨夜星辰昨夜風，畫樓西畔桂堂東。", "身無綵鳳雙飛翼，心有靈犀一點通。", "隔座送鉤春酒暖，分曹射覆蠟燈紅。", "嗟余聽鼓應官去，走馬蘭臺類斷蓬。"]'),
('13345c36-ff7f-4c93-87e4-037d648d3c55','無題二首 二','李商隱','唐','唐诗','tang','','[]','聞到閶門萼綠華，昔年相望抵天涯。',32,'全唐诗/poet.tang.29000.json','["聞到閶門萼綠華，昔年相望抵天涯。", "豈知一夜秦樓客，偷看吳王苑內花。"]'),
('738b365c-fd9a-4d86-acd7-8e5bd6ce92c6','漢宮詞','李商隱','唐','唐诗','tang','','[]','青雀西飛竟未迴，君王長在集靈臺。',32,'全唐诗/poet.tang.29000.json','["青雀西飛竟未迴，君王長在集靈臺。", "侍臣最有相如渴，不賜金莖露一杯。"]'),
('7377e34a-1aab-47e3-a6dd-376c98a5d6b7','無題四首 一','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u8bb0\u68a6", "\u4e03\u8a00\u5f8b\u8bd7", "\u7231\u60c5"]','來是空言去絕踪，月斜樓上五更鐘。',64,'全唐诗/poet.tang.29000.json','["來是空言去絕踪，月斜樓上五更鐘。", "夢爲遠別啼難喚，書被催成墨未濃。", "蠟照半籠金翡翠，麝熏微度繡芙蓉。", "劉郎已恨蓬山遠，更隔蓬山一萬重。"]'),
('811a5f9e-0df5-46f1-a587-0d4df7bca5a0','無題四首 二','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u76f8\u601d", "\u5973\u5b50", "\u7231\u60c5", "\u4e03\u8a00\u5f8b\u8bd7"]','颯颯東風細雨來，芙蓉塘外有輕雷。',64,'全唐诗/poet.tang.29000.json','["颯颯東風細雨來，芙蓉塘外有輕雷。", "金蟾齧鏁燒香入，玉虎牽絲汲井迴。", "賈氏窺簾韓掾少，宓妃留枕魏王才。", "春心莫共花爭發，一寸相思一寸灰。"]'),
('b8338c17-7f29-4d64-9c17-2e5eb4c4fa9d','無題四首 三','李商隱','唐','唐诗','tang','','[]','含情春晼晚，暫見夜闌干。',48,'全唐诗/poet.tang.29000.json','["含情春晼晚，暫見夜闌干。", "樓響將登怯，簾烘欲過難。", "多羞釵上燕，真媿鏡中鸞。", "歸去橫塘曉，華星送寶鞍。"]'),
('b47c2562-516b-44b9-a754-a332867d99af','無題四首 四','李商隱','唐','唐诗','tang','','[]','何處哀箏隨急管，櫻花永巷垂楊岸。',64,'全唐诗/poet.tang.29000.json','["何處哀箏隨急管，櫻花永巷垂楊岸。", "東家老女嫁不售，白日當天三月半。", "溧陽公主年十四，清明暖後同墻看。", "歸來展轉到五更，梁間燕子聞長歎。"]'),
('29db6b06-b7c0-46fa-8c3c-68a2ebec9f50','赴職梓潼留別畏之員外同年','李商隱','唐','唐诗','tang','','[]','佳兆聯翩遇鳳凰，雕文羽帳紫金牀。',64,'全唐诗/poet.tang.29000.json','["佳兆聯翩遇鳳凰，雕文羽帳紫金牀。", "桂花香處同高第，柿葉翻時獨悼亡。", "烏鵲失棲長不定，鴛鴦何事自相將。", "京華庸蜀三千里，送到咸陽見夕陽。"]'),
('0ef6c707-a77b-4e22-8257-7b5ab458d3e1','桂林路中作','李商隱','唐','唐诗','tang','','[]','地暖無秋色，江晴有暮暉。',48,'全唐诗/poet.tang.29000.json','["地暖無秋色，江晴有暮暉。", "空餘蟬嘒嘒，猶向客依依。", "村小犬相護，沙平僧獨歸。", "欲成西北望，又見鷓鴣飛。"]'),
('59c8f6e0-c96b-4d3d-82e7-c57919c0930d','無題','李商隱','唐','唐诗','tang','','[]','照梁初有情，出水舊知名。',48,'全唐诗/poet.tang.29000.json','["照梁初有情，出水舊知名。", "帬衩芙蓉小，釵茸翡翠輕。", "錦長書鄭重，眉細恨分明。", "莫近彈碁局，中心最不平。"]'),
('611f55f2-54f8-4b74-b65b-3703ace42ed6','蝶三首 一','李商隱','唐','唐诗','tang','','[]','初來小苑中，稍與瑣闈通。',48,'全唐诗/poet.tang.29000.json','["初來小苑中，稍與瑣闈通。", "遠恐芳塵斷，輕憂豔雪融。", "只知防皓露，不覺逆尖風。", "迴首雙飛燕，乘時入綺櫳。"]'),
('c5fbee39-67c1-4b49-b193-5cb7e3f1d95e','蝶三首 二','李商隱','唐','唐诗','tang','','[]','長眉畫了繡簾開，碧玉行收白玉臺。',32,'全唐诗/poet.tang.29000.json','["長眉畫了繡簾開，碧玉行收白玉臺。", "爲問翠釵釵上鳳，不知香頸爲誰迴。"]'),
('404f4b36-a6ca-4c67-b4b3-a4d2a349eb15','蝶三首 三','李商隱','唐','唐诗','tang','','[]','壽陽公主嫁時妝，八字宮眉捧額黃。',32,'全唐诗/poet.tang.29000.json','["壽陽公主嫁時妝，八字宮眉捧額黃。", "見我佯羞頻照影，不知身屬冶遊郎。"]'),
('4e936cb1-f405-4848-bfbd-8db8f74f898a','無題二首 一','李商隱','唐','唐诗','tang','','["\u5c11\u5973", "\u5199\u4eba", "\u7231\u60c5"]','八歲偷照鏡，長眉已能畫。',60,'全唐诗/poet.tang.29000.json','["八歲偷照鏡，長眉已能畫。", "十歲去踏青，芙蓉作帬衩。", "十二學彈箏，銀甲不曾卸。", "十四藏六親，懸知猶未嫁。", "十五泣春風，背面鞦韆下。"]'),
('6072a95b-6994-4c35-96e2-4577d586ba28','無題二首 二','李商隱','唐','唐诗','tang','','[]','幽人不倦賞，秋暑貴招邀。',48,'全唐诗/poet.tang.29000.json','["幽人不倦賞，秋暑貴招邀。", "竹碧轉悵望，池清尤寂寥。", "露花終裛濕，風蝶強嬌饒。", "此地如攜手，兼君不自聊。"]'),
('400ba099-a00e-45ee-96b5-f0ff089c098c','王十二兄與畏之員外相訪見招小飲時予以悼亡日近不去因寄','李商隱','唐','唐诗','tang','','[]','謝傅門庭舊末行，今朝歌管屬檀郎。',64,'全唐诗/poet.tang.29000.json','["謝傅門庭舊末行，今朝歌管屬檀郎。", "更無人處簾垂地，欲拂塵時簟竟牀。", "嵇氏幼男猶可憫，左家嬌女豈能忘。", "秋霖腹疾俱難遣，萬里西風夜正長。"]'),
('91f95b30-c42f-470a-9df8-dd6284fca474','隋宮','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u7edd\u53e5", "\u548f\u53f2\u6000\u53e4", "\u8bbd\u523a"]','乘興南遊不戒嚴，九重誰省諫書函。',32,'全唐诗/poet.tang.29000.json','["乘興南遊不戒嚴，九重誰省諫書函。", "春風舉國裁宮錦，半作障泥半作帆。"]'),
('da157c27-d317-4205-9cdc-a254445659fc','落花','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u548f\u7269", "\u4e94\u8a00\u5f8b\u8bd7", "\u5199\u82b1", "\u6292\u6000", "\u82b1"]','高閣客竟去，小園花亂飛。',48,'全唐诗/poet.tang.29000.json','["高閣客竟去，小園花亂飛。", "參差連曲陌，迢遰送斜暉。", "腸斷未忍掃，眼穿仍欲歸。", "芳心向春盡，所得是沾衣。"]'),
('18ed9e1d-38bc-4f8e-86d1-a2fa4c0d10e0','月','李商隱','唐','唐诗','tang','','["\u591c\u665a", "\u6708\u4eae", "\u5199\u666f"]','池上與橋邊，難忘復可憐。',48,'全唐诗/poet.tang.29000.json','["池上與橋邊，難忘復可憐。", "簾開最明夜，簟卷已涼天。", "流處水花急，吐時雲葉鮮。", "姮娥無粉黛，只是逞嬋娟。"]'),
('55e6a23b-20c1-4e46-aba5-c3ef7526c3c9','贈宗魯笻竹杖','李商隱','唐','唐诗','tang','','[]','大夏資輕策，全溪贈所思。',48,'全唐诗/poet.tang.29000.json','["大夏資輕策，全溪贈所思。", "靜憐穿樹遠，滑想過苔遲。", "鶴怨朝還望，僧閑暮有期。", "風流真底事，常欲傍清羸。"]'),
('2bf8bd2e-3d1e-4c96-bc33-568180867267','垂柳','李商隱','唐','唐诗','tang','','[]','娉婷小苑中，婀娜曲池東。',48,'全唐诗/poet.tang.29000.json','["娉婷小苑中，婀娜曲池東。", "朝佩皆垂地，仙衣盡帶風。", "七賢寧占竹，三品且饒松。", "腸斷靈和殿，先皇玉座空。"]'),
('97352008-84fa-451b-988c-d2b84a372506','曲池','李商隱','唐','唐诗','tang','','[]','日下繁香不自持，月中流豔與誰期。',64,'全唐诗/poet.tang.29000.json','["日下繁香不自持，月中流豔與誰期。", "迎憂急鼓疎鐘斷，分隔休燈滅燭時。", "張蓋欲判江灩灩，迴頭更望柳絲絲。", "從來此地黃昏散，未信河梁是別離。"]'),
('f07565e0-7e86-444a-b796-8e4070b9d6c0','代應二首 一','李商隱','唐','唐诗','tang','','[]','溝水分流西復東，九秋霜月五更風。',32,'全唐诗/poet.tang.29000.json','["溝水分流西復東，九秋霜月五更風。", "離鸞別鳳今何在，十二玉樓空更空。"]'),
('fe66a669-912c-4ed8-97a0-fc63a0319093','代應二首 二','李商隱','唐','唐诗','tang','','[]','昨夜雙鉤敗，今朝百草輸。',24,'全唐诗/poet.tang.29000.json','["昨夜雙鉤敗，今朝百草輸。", "關西狂小吏，惟喝遶牀盧。"]'),
('86ea8175-fabb-425d-85fd-6987c2dae0fd','席上作','李商隱','唐','唐诗','tang','','[]','淡雲輕雨拂高唐，玉殿秋來夜正長。',32,'全唐诗/poet.tang.29000.json','["淡雲輕雨拂高唐，玉殿秋來夜正長。", "料得也應憐宋玉，一生惟事楚襄王。"]'),
('4cdd870a-88c1-48d6-859e-fec3185ae0df','訪隱者不遇成二絕 一','李商隱','唐','唐诗','tang','','[]','秋水悠悠浸墅扉，夢中來數覺來稀。',32,'全唐诗/poet.tang.29000.json','["秋水悠悠浸墅扉，夢中來數覺來稀。", "玄蟬去盡葉黃落，一樹冬青人未歸。"]'),
('9d3b643d-0b60-427c-91f3-6068cbf682f2','訪隱者不遇成二絕 二','李商隱','唐','唐诗','tang','','[]','城郭休過識者稀，哀猿啼處有柴扉。',32,'全唐诗/poet.tang.29000.json','["城郭休過識者稀，哀猿啼處有柴扉。", "滄江白日樵漁路，日暮歸來雨滿衣。"]'),
('3350502f-b765-424c-8c79-dd0050d04233','破鏡','李商隱','唐','唐诗','tang','','[]','玉匣清光不復持，菱花散亂月輪虧。',32,'全唐诗/poet.tang.29000.json','["玉匣清光不復持，菱花散亂月輪虧。", "秦臺一照山雞後，便是孤鸞罷舞時。"]'),
('461e8253-fbe1-46e1-a40f-1b107a6db31f','無題','李商隱','唐','唐诗','tang','','[]','紫府仙人號寶燈，雲漿未飲結成冰。',32,'全唐诗/poet.tang.29000.json','["紫府仙人號寶燈，雲漿未飲結成冰。", "如何雪月交光夜，更在瑤臺十二層。"]'),
('b16a2371-bbd0-4322-828e-da45e2632bd5','贈庾十二朱版','李商隱','唐','唐诗','tang','','[]','固漆投膠不可開，贈君珍重抵瓊瑰。',32,'全唐诗/poet.tang.29000.json','["固漆投膠不可開，贈君珍重抵瓊瑰。", "君王曉坐金鑾殿，只待相如草詔來。"]'),
('b2346dbc-f057-4e05-87b3-6b725a70ded8','李花','李商隱','唐','唐诗','tang','','[]','李徑獨來數，愁情相與懸。',48,'全唐诗/poet.tang.29000.json','["李徑獨來數，愁情相與懸。", "自明無月夜，強笑欲風天。", "減粉與園籜，分香沾渚蓮。", "徐妃久已嫁，猶自玉爲鈿。"]'),
('15ed6ad5-cc7e-43a1-a843-42b442ff9ed3','柳','李商隱','唐','唐诗','tang','','["\u67f3\u6811", "\u4f24\u6000"]','曾逐東風拂舞筵，樂遊春苑斷腸天。',32,'全唐诗/poet.tang.29000.json','["曾逐東風拂舞筵，樂遊春苑斷腸天。", "如何肯到清秋日，已帶斜陽又帶蟬。"]'),
('9c899576-0b49-42c3-8fe2-b3af2c1a7aac','三月十日流杯亭','李商隱','唐','唐诗','tang','','[]','身屬中軍少得歸，木蘭花盡失春期。',32,'全唐诗/poet.tang.29000.json','["身屬中軍少得歸，木蘭花盡失春期。", "偷隨柳絮到城外，行過水西聞子規。"]'),
('5bfdfaf3-7ec6-459b-9c62-d04f3b755ba2','過招國李家南園二首 一','李商隱','唐','唐诗','tang','','[]','潘岳無妻客爲愁，新人來坐舊妝樓。',32,'全唐诗/poet.tang.29000.json','["潘岳無妻客爲愁，新人來坐舊妝樓。", "春風猶自疑聯句，雪絮相和飛不休。"]'),
('1bc0c393-aa7d-4ab6-b8f0-a189be3fb151','過招國李家南園二首 二','李商隱','唐','唐诗','tang','','[]','長亭歲盡雪如波，此去秦關路幾多。',32,'全唐诗/poet.tang.29000.json','["長亭歲盡雪如波，此去秦關路幾多。", "惟有夢中相近分，臥來無睡欲如何。"]'),
('cff5da44-589d-4c35-bf38-674d74dc4d1f','留贈畏之 一','李商隱','唐','唐诗','tang','','[]','清時無事奏明光，不遣當關報早霜。',64,'全唐诗/poet.tang.29000.json','["清時無事奏明光，不遣當關報早霜。", "中禁詞臣尋引領，左川歸客自迴腸。", "郎君下筆驚鸚鵡，侍女吹笙弄鳳凰。", "空寄大羅天上事，衆仙同日詠霓裳。"]'),
('26d9723f-501f-407f-98a9-2486bc9e160e','留贈畏之 二','李商隱','唐','唐诗','tang','','[]','待得郎來月已低，寒暄不道醉如泥。',32,'全唐诗/poet.tang.29000.json','["待得郎來月已低，寒暄不道醉如泥。", "五更又欲向何處，騎馬出門烏夜啼。"]'),
('63fd26bc-6b80-4094-bd9d-27a4ec35bef3','留贈畏之 三','李商隱','唐','唐诗','tang','','[]','戶外重陰黯不開，含羞迎夜復臨臺。',32,'全唐诗/poet.tang.29000.json','["戶外重陰黯不開，含羞迎夜復臨臺。", "瀟湘浪上有煙景，安得好風吹汝來。"]'),
('974914ee-1fc0-4952-a863-820bad2e4065','爲有','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u7edd\u53e5", "\u6028\u60c5"]','爲有雲屏無限嬌，鳳城寒盡怕春宵。',32,'全唐诗/poet.tang.29000.json','["爲有雲屏無限嬌，鳳城寒盡怕春宵。", "無端嫁得金龜壻，辜負香衾事早朝。"]'),
('ed79f9bc-d5d1-4251-b22d-d091e0758a3f','無題','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u4e03\u8a00\u5f8b\u8bd7", "\u516b\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5916)", "\u521d\u4e2d\u53e4\u8bd7", "\u7231\u60c5"]','相見時難別亦難，東風無力百花殘。',64,'全唐诗/poet.tang.29000.json','["相見時難別亦難，東風無力百花殘。", "春蠶到死絲方盡，蠟炬成灰淚始乾。", "曉鏡但愁雲鬢改，夜吟應覺月光寒。", "蓬山此去無多路，青鳥殷勤爲探看。"]'),
('f7d541d4-757c-4759-9c36-64649e5e7c20','碧城三首 一','李商隱','唐','唐诗','tang','','[]','碧城十二曲闌干，犀辟塵埃玉辟寒。',64,'全唐诗/poet.tang.29000.json','["碧城十二曲闌干，犀辟塵埃玉辟寒。", "閬苑有書多附鶴，女牀無樹不棲鸞。", "星沉海底當窗見，雨過河源隔座看。", "若是曉珠明又定，一生長樹水晶盤。"]'),
('fe4d5a74-8e5f-421c-84df-e7f3cd53c8a2','碧城三首 二','李商隱','唐','唐诗','tang','','[]','對影聞聲已可憐，玉池荷葉正田田。',64,'全唐诗/poet.tang.29000.json','["對影聞聲已可憐，玉池荷葉正田田。", "不逢蕭史休回首，莫見洪崖又拍肩。", "紫鳳放嬌銜楚佩，赤鱗狂舞撥湘絃。", "鄂君悵望舟中夜，繡被焚香獨自眠。"]'),
('1c1782ad-fa9d-458c-94ef-a8f3ad8b38ff','碧城三首 三','李商隱','唐','唐诗','tang','','[]','七夕來時先有期，洞房簾箔至今垂。',64,'全唐诗/poet.tang.29000.json','["七夕來時先有期，洞房簾箔至今垂。", "玉輪顧兔初生魄，鐵網珊瑚未有枝。", "檢與神方教駐景，收將鳳紙寫相思。", "武皇內傳分明在，莫道人間總不知。"]'),
('d4a7c497-cd2a-4d23-a086-4343f9821125','對雪二首 一','李商隱','唐','唐诗','tang','','[]','寒氣先侵玉女扉，清光旋透省郎闈。',64,'全唐诗/poet.tang.29000.json','["寒氣先侵玉女扉，清光旋透省郎闈。", "梅花大庾嶺頭發，柳絮章臺街裏飛。", "欲舞定隨曹植馬，有情應濕謝莊衣。", "龍山萬里無多遠，留待行人二月歸。"]'),
('25b4f480-f96d-4a3e-b343-8d327d413d3d','對雪二首 二','李商隱','唐','唐诗','tang','','[]','旋撲珠簾過粉墻，輕於柳絮重於霜。',64,'全唐诗/poet.tang.29000.json','["旋撲珠簾過粉墻，輕於柳絮重於霜。", "已隨江令誇瓊樹，又入盧家妬玉堂。", "侵夜可能爭桂魄，忍寒應欲試梅妝。", "關河凍合東西路，腸斷斑騅送陸郎。"]'),
('aeaf48a2-a37f-4ae2-8fe0-da74da693b95','蜂','李商隱','唐','唐诗','tang','','[]','小苑華池爛熳通，後門前檻思無窮。',64,'全唐诗/poet.tang.29000.json','["小苑華池爛熳通，後門前檻思無窮。", "宓妃腰細纔勝露，趙后身輕欲倚風。", "紅壁寂寥崖蜜盡，碧簾迢遰霧巢空。", "青陵粉碟休離恨，長定相逢二月中。"]'),
('28028f84-29d9-4a60-ba22-81bc988b9f22','公子','李商隱','唐','唐诗','tang','','[]','外戚封侯自有恩，平明通籍九華門。',32,'全唐诗/poet.tang.29000.json','["外戚封侯自有恩，平明通籍九華門。", "金唐公主年應小，二十君王未許婚。"]'),
('6be98d11-1f5f-46ea-971e-61d4de82b8b9','賦得雞','李商隱','唐','唐诗','tang','','[]','稻粱猶足活諸雛，妬敵專場好自娛。',32,'全唐诗/poet.tang.29000.json','["稻粱猶足活諸雛，妬敵專場好自娛。", "可要五更驚曉夢，不辭風雪爲陽烏。"]'),
('77ad6636-67fe-4c9c-a0ba-bbed4c3f147f','明神','李商隱','唐','唐诗','tang','','[]','明神司過豈令冤，暗室由來有禍門。',32,'全唐诗/poet.tang.29000.json','["明神司過豈令冤，暗室由來有禍門。", "莫爲無人欺一物，他時須慮石能言。"]'),
('cc1ce54a-dd77-4db2-98f2-9c606c71c408','辛未七夕','李商隱','唐','唐诗','tang','','["\u4e03\u5915\u60c5\u4eba\u8282", "\u5b64\u72ec", "\u4e03\u5915\u8282"]','恐是仙家好別離，故教迢遰作佳期。',64,'全唐诗/poet.tang.29000.json','["恐是仙家好別離，故教迢遰作佳期。", "由來碧落銀河畔，可要金風玉露時。", "清漏漸移相望久，微雲未接過來遲。", "豈能無意酬烏鵲，惟與蜘蛛乞巧絲。"]'),
('3c70eb9a-a78c-4acf-9077-e5ab2a231459','壬申七夕','李商隱','唐','唐诗','tang','','["\u4e03\u5915\u60c5\u4eba\u8282", "\u4e03\u5915\u8282"]','已駕七香車，心心待曉霞。',48,'全唐诗/poet.tang.29000.json','["已駕七香車，心心待曉霞。", "風輕惟響珮，日薄不嫣花。", "桂嫩傳香遠，榆高送影斜。", "成都過卜肆，曾妬識靈槎。"]'),
('73f08183-ce53-4eba-823f-4813f07ddfba','壬申閏秋題贈鳥鵲','李商隱','唐','唐诗','tang','','[]','繞樹無衣月正高，鄴城新淚濺雲袍。',32,'全唐诗/poet.tang.29000.json','["繞樹無衣月正高，鄴城新淚濺雲袍。", "幾年始得逢秋閏，兩度填河莫告勞。"]'),
('27bae607-f1b8-44c7-bc78-d73454e6c3a4','端居','李商隱','唐','唐诗','tang','','["\u601d\u4e61"]','遠書歸夢兩悠悠，只有空牀敵素秋。',32,'全唐诗/poet.tang.29000.json','["遠書歸夢兩悠悠，只有空牀敵素秋。", "堦下青苔與紅樹，雨中寥落月中愁。"]'),
('386e25f8-f6b7-4054-aed1-eb82c64c5126','夜半','李商隱','唐','唐诗','tang','','[]','三更三點萬家眠，露欲爲霜月墮煙。',32,'全唐诗/poet.tang.29000.json','["三更三點萬家眠，露欲爲霜月墮煙。", "鬬鼠上堂蝙蝠出，玉琴時動倚窗絃。"]'),
('60de2318-4bff-455c-84d4-7ea4d1ef1af0','玉山','李商隱','唐','唐诗','tang','','[]','玉山高與閬風齊，玉水清流不貯泥。',64,'全唐诗/poet.tang.29000.json','["玉山高與閬風齊，玉水清流不貯泥。", "何處更求回日馭，此中兼有上天梯。", "珠容百斛龍休睡，桐拂千尋鳳要棲。", "聞道神仙有才子，赤簫吹罷好相攜。"]'),
('232ba85c-9279-47c0-9c86-6a4e10e0ebed','張惡子廟','李商隱','唐','唐诗','tang','','[]','下馬捧椒漿，迎神白玉堂。',24,'全唐诗/poet.tang.29000.json','["下馬捧椒漿，迎神白玉堂。", "如何鐵如意，獨自與姚萇。"]'),
('b44a7fc3-3890-4221-aed2-2fc9343c5285','雨','李商隱','唐','唐诗','tang','','[]','摵摵度瓜園，依依傍竹軒。',48,'全唐诗/poet.tang.29000.json','["摵摵度瓜園，依依傍竹軒。", "秋池不自冷，風葉共成喧。", "窗迥有時見，簷高相續翻。", "侵宵送書雁，應爲稻粱恩。"]'),
('2b0ce34d-ac0b-46f7-9e30-c7433a73d83a','菊','李商隱','唐','唐诗','tang','','["\u83ca\u82b1"]','暗暗淡淡紫，融融冶冶黃。',48,'全唐诗/poet.tang.29000.json','["暗暗淡淡紫，融融冶冶黃。", "陶令籬邊色，羅含宅裏香。", "幾時禁重露，實是怯殘陽。", "願泛金鸚鵡，升君白玉堂。"]'),
('0de5c9dc-8bd5-45db-bfbe-efba1c3e0db7','牡丹','李商隱','唐','唐诗','tang','','["\u7261\u4e39", "\u548f\u7269\u8bd7", "\u7231\u60c5", "\u548f\u7269", "\u76f8\u601d"]','錦幃初卷衛夫人，繡被猶堆越鄂君。',64,'全唐诗/poet.tang.29000.json','["錦幃初卷衛夫人，繡被猶堆越鄂君。", "垂手亂翻雕玉佩，招腰爭舞鬱金帬。", "石家蠟燭何曾剪，荀令香爐可待熏。", "我是夢中傳彩筆，欲書花葉寄朝雲。"]'),
('948ef71c-c0b8-4388-bdd8-3c983068f1a4','北樓','李商隱','唐','唐诗','tang','','[]','春物豈相干，人生只強歡。',48,'全唐诗/poet.tang.29000.json','["春物豈相干，人生只強歡。", "花猶曾斂夕，酒竟不知寒。", "異城東風濕，中華上象寬。", "此樓堪北望，輕命倚危欄。"]'),
('ffb33b2d-d22c-41df-8a4b-c8ff7ffc9a80','擬沈下賢','李商隱','唐','唐诗','tang','','[]','千二百輕鸞，春衫瘦著寬。',48,'全唐诗/poet.tang.29000.json','["千二百輕鸞，春衫瘦著寬。", "倚風行稍急，含雪語應寒。", "帶火遺金斗，兼珠碎玉盤。", "河陽看花過，曾不問潘安。"]'),
('bcc367cf-fd08-48b7-b0cd-88b01ee5f1a0','蝶','李商隱','唐','唐诗','tang','','[]','飛來繡戶陰，穿過畫樓深。',48,'全唐诗/poet.tang.29000.json','["飛來繡戶陰，穿過畫樓深。", "重傅秦臺粉，輕塗漢殿金。", "相兼惟柳絮，所得是花心。", "可要凌孤客，邀爲子夜吟。"]'),
('92d31d11-8416-4a65-a109-6378a1493b82','飲席代官妓贈兩從事','李商隱','唐','唐诗','tang','','[]','新人橋上著春衫，舊主江邊側帽簷。',32,'全唐诗/poet.tang.29000.json','["新人橋上著春衫，舊主江邊側帽簷。", "願得化爲紅綬帶，許教雙鳳一時銜。"]'),
('c87356ef-797e-4aac-9e68-821a85a083e3','代魏宮私贈','李商隱','唐','唐诗','tang','','[]','來時西館阻佳期，去後漳河隔夢思。',32,'全唐诗/poet.tang.29000.json','["來時西館阻佳期，去後漳河隔夢思。", "知有宓妃無限意，春松秋菊可同時。"]'),
('1b534565-9537-4df2-80ad-760cf04a103f','代元城吳令暗爲荅','李商隱','唐','唐诗','tang','','[]','背闕歸藩路欲分，水邊風日半西曛。',32,'全唐诗/poet.tang.29000.json','["背闕歸藩路欲分，水邊風日半西曛。", "荆王枕上原無夢，莫枉陽臺一片雲。"]'),
('7559e729-f9be-41c3-bf80-0ed4ecb17029','牡丹','李商隱','唐','唐诗','tang','','[]','壓逕復緣溝，當窗又映樓。',48,'全唐诗/poet.tang.29000.json','["壓逕復緣溝，當窗又映樓。", "終銷一國破，不啻萬金求。", "鸞鳳戲三島，神仙居十洲。", "應憐萱草淡，却得號忘憂。"]'),
('1779cc74-d2b3-4a4c-8710-2b662ccfb5d6','百果嘲櫻桃','李商隱','唐','唐诗','tang','','[]','珠實雖先熟，瓊莩縱早開。',24,'全唐诗/poet.tang.29000.json','["珠實雖先熟，瓊莩縱早開。", "流鸎猶故在，爭得諱含來。"]'),
('5b82bef3-d729-4452-890c-8be9d694c621','櫻桃答','李商隱','唐','唐诗','tang','','[]','衆果莫相誚，天生名品高。',24,'全唐诗/poet.tang.29000.json','["衆果莫相誚，天生名品高。", "何因古樂府，惟有鄭櫻桃。"]'),
('5b309451-8607-4b72-a535-613629f02a24','曉坐','李商隱','唐','唐诗','tang','','[]','後閤罷朝眠，前墀思黯然。',48,'全唐诗/poet.tang.29000.json','["後閤罷朝眠，前墀思黯然。", "梅應未假雪，柳自不勝煙。", "淚續淺深綆，腸危高下絃。", "紅顏無定所，得失在當年。"]'),
('e2b3de24-67b2-4a7c-bb8b-f6d6b2e23772','詠史','李商隱','唐','唐诗','tang','','[]','北湖南埭水漫漫，一片降旗百尺竿。',32,'全唐诗/poet.tang.29000.json','["北湖南埭水漫漫，一片降旗百尺竿。", "三百年間同曉夢，鍾山何處有龍盤。"]'),
('eb757832-9421-4b38-9fa1-aa6430df8909','一片','李商隱','唐','唐诗','tang','','[]','一片非煙隔九枝，蓬巒仙仗儼雲旗。',64,'全唐诗/poet.tang.29000.json','["一片非煙隔九枝，蓬巒仙仗儼雲旗。", "天泉水暖龍吟細，露畹春多鳳舞遲。", "榆莢散來星斗轉，桂花尋去月輪移。", "人間桑海朝朝變，莫遣佳期更後期。"]'),
('7fd3021e-687c-4b6f-a99d-8dd78f1e32db','日射','李商隱','唐','唐诗','tang','','["\u6292\u60c5", "\u5987\u5973", "\u95fa\u6028"]','日射紗窗風撼扉，香羅拭手春事違。',32,'全唐诗/poet.tang.29000.json','["日射紗窗風撼扉，香羅拭手春事違。", "迴廊四合掩寂寞，碧鸚鵡對紅薔薇。"]'),
('5be81cf2-65d6-440e-b7cb-8668b2988a4b','題鵝','李商隱','唐','唐诗','tang','','[]','眠沙臥水自成羣，曲岸殘陽極浦雲。',32,'全唐诗/poet.tang.29000.json','["眠沙臥水自成羣，曲岸殘陽極浦雲。", "那解將心憐孔翠，羈雌長共故雄分。"]'),
('a18daa1a-b079-4351-930b-1af9af91aab8','華清宮','李商隱','唐','唐诗','tang','','[]','朝元閣迥羽衣新，首按昭陽第一人。',32,'全唐诗/poet.tang.29000.json','["朝元閣迥羽衣新，首按昭陽第一人。", "當日不來高處舞，可能天下有胡塵。"]'),
('470ddf3b-fee4-453b-b329-5b3d26032af3','梓潼望長卿山至巴西復懷譙秀','李商隱','唐','唐诗','tang','','[]','梓潼不見馬相如，更欲南行問酒壚。',32,'全唐诗/poet.tang.29000.json','["梓潼不見馬相如，更欲南行問酒壚。", "行到巴西覓譙秀，巴西惟是有寒蕪。"]'),
('a4d65f0b-8de2-4f25-baf9-4ea04c0e01e7','齊宮詞','李商隱','唐','唐诗','tang','','[]','永壽兵來夜不扃，金蓮無復印中庭。',32,'全唐诗/poet.tang.29000.json','["永壽兵來夜不扃，金蓮無復印中庭。", "梁臺歌管三更罷，猶自風搖九子鈴。"]'),
('0595cc72-4707-4448-91c3-18935d916119','十一月中旬至扶風界見梅花','李商隱','唐','唐诗','tang','','["\u6885\u82b1", "\u548f\u7269", "\u548f\u7269\u8bd7"]','匝路亭亭豔，非時裛裛香。',48,'全唐诗/poet.tang.29000.json','["匝路亭亭豔，非時裛裛香。", "素娥惟與月，青女不饒霜。", "贈遠虛盈手，傷離適斷腸。", "爲誰成早秀，不待作年芳。"]'),
('ea6f4493-38e2-4f75-b674-1f894fa50bc4','青陵臺','李商隱','唐','唐诗','tang','','[]','青陵臺畔日光斜，萬古貞魂倚暮霞。',32,'全唐诗/poet.tang.29000.json','["青陵臺畔日光斜，萬古貞魂倚暮霞。", "莫訝韓憑爲蛺蝶，等閑飛上別枝花。"]'),
('c54c5f69-81c1-4dcf-8fab-3278f96f7467','東還','李商隱','唐','唐诗','tang','','[]','自有仙才自不知，十年長夢採華芝。',32,'全唐诗/poet.tang.29000.json','["自有仙才自不知，十年長夢採華芝。", "秋風動地黃雲暮，歸去嵩陽尋舊師。"]'),
('95842e47-54e0-44dd-8b90-dbd1c2514ae3','酬崔八早梅有贈兼示之作','李商隱','唐','唐诗','tang','','[]','知訪寒梅過野塘，久留金勒爲迴腸。',64,'全唐诗/poet.tang.29000.json','["知訪寒梅過野塘，久留金勒爲迴腸。", "謝郎衣袖初翻雪，荀令熏爐更換香。", "何處拂胸資蝶粉，幾時塗額藉蜂黃。", "維摩一室雖多病，亦要天花作道場。"]'),
('a8643adc-fc9c-4440-82b0-6512fe87fa06','春風','李商隱','唐','唐诗','tang','','[]','春風雖自好，春物太昌昌。',36,'全唐诗/poet.tang.29000.json','["春風雖自好，春物太昌昌。", "若教春有意，惟遣一枝芳。", "我意殊春意，先春已斷腸。"]'),
('0650447b-602d-4fd1-b0c0-967d7eb4c8b1','蜀桐','李商隱','唐','唐诗','tang','','[]','玉壘高桐拂玉繩，上含非霧下含冰。',32,'全唐诗/poet.tang.29000.json','["玉壘高桐拂玉繩，上含非霧下含冰。", "枉教紫鳳無棲處，斵作秋琴彈壞陵。"]'),
('d374f3b2-fae5-4555-98b3-557f3aebe0dd','漢宮','李商隱','唐','唐诗','tang','','[]','通靈夜醮達清晨，承露盤晞甲帳春。',32,'全唐诗/poet.tang.29000.json','["通靈夜醮達清晨，承露盤晞甲帳春。", "王母不來方朔去，更須重見李夫人。"]'),
('c72c50c4-02c9-4291-802d-066c8879269c','判春','李商隱','唐','唐诗','tang','','[]','一桃復一李，井上占年芳。',48,'全唐诗/poet.tang.29000.json','["一桃復一李，井上占年芳。", "笑處如臨鏡，窺時不隱墻。", "敢言西子短，誰覺宓妃長。", "珠玉終相類，同名作夜光。"]'),
('fc96d1c5-e131-4a00-97d5-aeded8c681a5','促漏','李商隱','唐','唐诗','tang','','[]','促漏遙鐘動靜聞，報章重疊杳難分。',64,'全唐诗/poet.tang.29000.json','["促漏遙鐘動靜聞，報章重疊杳難分。", "舞鸞鏡匣收殘黛，睡鴨香爐換夕熏。", "歸去定知還向月，夢來何處更爲雲？", "南塘漸暖蒲堪結，兩兩鴛鴦護水紋。"]'),
('7b01e157-57bd-44b7-924b-f1ef462cd9d9','江東','李商隱','唐','唐诗','tang','','[]','驚魚撥刺燕翩翾，獨自江東上釣船。',32,'全唐诗/poet.tang.29000.json','["驚魚撥刺燕翩翾，獨自江東上釣船。", "今日春光太漂蕩，謝家輕絮沈郎錢。"]'),
('6e9d07db-3d09-4952-9ba2-fd457d7861df','讀任彥昇碑','李商隱','唐','唐诗','tang','','[]','任昉當年有美名，可憐才調最縱橫。',32,'全唐诗/poet.tang.29000.json','["任昉當年有美名，可憐才調最縱橫。", "梁臺初建應惆悵，不得蕭公作騎兵。"]'),
('0d040a94-a0dc-4759-b374-26278998fef9','荷花','李商隱','唐','唐诗','tang','','["\u5199\u82b1", "\u5973\u5b50", "\u7231\u60c5", "\u76f8\u9047", "\u82b1"]','都無色可並，不奈此香何。',48,'全唐诗/poet.tang.29000.json','["都無色可並，不奈此香何。", "瑤席乘涼設，金羈落晚過。", "迴衾燈照綺，渡韈水沾羅。", "預想前秋別，離居夢櫂歌。"]'),
('fca78594-17b3-4873-95d3-5e4fe01bdda0','五松驛','李商隱','唐','唐诗','tang','','[]','獨下長亭念過秦，五松不見見輿薪。',32,'全唐诗/poet.tang.29000.json','["獨下長亭念過秦，五松不見見輿薪。", "只應既斬斯高後，尋被樵人用斧斤。"]'),
('679d385c-da9a-45a5-b415-56cae6f635a8','灞岸','李商隱','唐','唐诗','tang','','[]','山東今歲點行頻，幾處冤魂哭虜塵。',32,'全唐诗/poet.tang.29000.json','["山東今歲點行頻，幾處冤魂哭虜塵。", "灞水橋邊倚華表，平時二月有東巡。"]'),
('ca1f6f35-b075-48c5-8419-dedc291da4d3','送臻師二首 一','李商隱','唐','唐诗','tang','','[]','昔去靈山非拂席，今來滄海欲求珠。',32,'全唐诗/poet.tang.29000.json','["昔去靈山非拂席，今來滄海欲求珠。", "楞伽頂上清涼池，善眼仙人憶我無。"]'),
('60cb7f6e-8832-4e13-9571-4099f2db9a66','送臻師二首 二','李商隱','唐','唐诗','tang','','[]','苦海迷途去未因，東方過此幾微塵。',32,'全唐诗/poet.tang.29000.json','["苦海迷途去未因，東方過此幾微塵。", "何當百億蓮花上，一一蓮花見佛身。"]'),
('91489186-6dbb-4bb5-a120-ac3fa7403e42','七夕','李商隱','唐','唐诗','tang','','[]','鸞扇斜分鳳幄開，星橋橫過鵲飛迴。',32,'全唐诗/poet.tang.29000.json','["鸞扇斜分鳳幄開，星橋橫過鵲飛迴。", "爭將世上無期別，換得年年一度來。"]'),
('5361c2f5-ccc3-4eae-9c40-1b137e5fd475','謝先輩防記念拙詩甚多異日偶有此寄','李商隱','唐','唐诗','tang','','[]','曉用雲添句，寒將雪命篇。',96,'全唐诗/poet.tang.29000.json','["曉用雲添句，寒將雪命篇。", "良辰多自感，作者豈皆然。", "熟寢初同鶴，含嘶欲並蟬。", "題詩長不展，得處定應偏。", "南浦無窮樹，西樓不住煙。", "改成人寂寂，寄與路綿綿。", "星勢寒垂地，河聲曉上天。", "夫君自有恨，聊借此中傳。"]'),
('2c5d1dd9-3209-4697-9a64-99a55d5e24f2','馬嵬二首 一','李商隱','唐','唐诗','tang','','[]','冀馬燕犀動地來，自埋紅粉自成灰。',32,'全唐诗/poet.tang.29000.json','["冀馬燕犀動地來，自埋紅粉自成灰。", "君王若道能傾國，玉輦何由過馬嵬。"]'),
('eb485152-2e04-4d29-a43a-842210b44203','馬嵬二首 二','李商隱','唐','唐诗','tang','','["\u7231\u60c5", "\u8bbd\u523a"]','海外徒聞更九州，他生未卜此生休。',64,'全唐诗/poet.tang.29000.json','["海外徒聞更九州，他生未卜此生休。", "空聞虎旅傳宵柝，無復雞人報曉籌。", "此日六軍同駐馬，當時七夕笑牽牛。", "如何四紀爲天子，不及盧家有莫愁。"]'),
('46f3e05a-fdcd-4592-952f-0cddcc4d04ba','可歎','李商隱','唐','唐诗','tang','','["\u7231\u60c5", "\u611f\u4f24", "\u611f\u53f9"]','幸會東城宴未迴，年華憂共水相催。',64,'全唐诗/poet.tang.29000.json','["幸會東城宴未迴，年華憂共水相催。", "梁家宅裏秦宮入，趙后樓中赤鳳來。", "冰簟且眠金鏤枕，瓊筵不醉玉交杯。", "宓妃愁坐芝田館，用盡陳王八斗才。"]'),
('1aa6eaa7-302d-4639-ab43-1f008853d38d','望喜驛別嘉陵江水二絕 一','李商隱','唐','唐诗','tang','','[]','嘉陵江水此東流，望喜樓中憶閬州。',32,'全唐诗/poet.tang.29000.json','["嘉陵江水此東流，望喜樓中憶閬州。", "若到閬中還赴海，閬州應更有高樓。"]'),
('a2938ba1-a4b2-4b78-9068-42274058808f','望喜驛別嘉陵江水二絕 二','李商隱','唐','唐诗','tang','','[]','千里嘉陵江水色，含煙帶月碧於藍。',32,'全唐诗/poet.tang.29000.json','["千里嘉陵江水色，含煙帶月碧於藍。", "今朝相送東流後，猶自驅車更向南。"]'),
('e556e770-7e3a-4061-8c3e-8bcd9ee4fb48','別薛嵒賓','李商隱','唐','唐诗','tang','','[]','曙爽行將拂，晨清坐欲凌。',72,'全唐诗/poet.tang.29000.json','["曙爽行將拂，晨清坐欲凌。", "別離真不那，風物正相仍。", "漫水任誰照，衰花淺自矜。", "還將兩袖淚，同向一窗燈。", "桂樹乖真隱，芸香是小懲。", "清規無以況，且用玉壺冰。"]'),
('6a50539b-3413-4202-b9e8-030f8147e53a','富平少侯','李商隱','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u548f\u53f2\u6000\u53e4"]','七國三邊未到憂，十三身襲富平候。',64,'全唐诗/poet.tang.29000.json','["七國三邊未到憂，十三身襲富平候。", "不收金彈拋林外，却惜銀牀在井頭。", "綵樹轉燈珠錯落，繡檀迴枕玉雕鎪。", "當關不報侵晨客，新得佳人字莫愁。"]'),
('416f5819-44ca-416d-ab50-193ae2c237cb','腸','李商隱','唐','唐诗','tang','','[]','有懷非惜恨，不奈寸腸何。',96,'全唐诗/poet.tang.29000.json','["有懷非惜恨，不奈寸腸何。", "即席迴彌久，前時斷固多。", "熱應翻急燒，冷欲徹微波。", "隔樹澌澌雨，通池點點荷。", "倦程山向背，望國闕嵯峨。", "故念飛書及，新懽借夢過。", "染筠休伴淚，繞雪莫追歌。", "擬問陽臺事，年深楚語訛。"]'),
('c61209a6-77c3-4793-8bc5-c1b476791e2d','贈宇文中丞','李商隱','唐','唐诗','tang','','[]','欲構中天正急材，自緣煙水戀平臺。',32,'全唐诗/poet.tang.29000.json','["欲構中天正急材，自緣煙水戀平臺。", "人間只有嵇延祖，最望山公啓事來。"]'),
('3213aad6-a6a1-4398-9798-5722e36db868','曉起','李商隱','唐','唐诗','tang','','[]','擬杯當曉起，呵鏡可微寒。',48,'全唐诗/poet.tang.29000.json','["擬杯當曉起，呵鏡可微寒。", "隔箔山櫻熟，褰帷桂燭殘。", "書長爲報晚，夢好更尋難。", "影響輸雙蝶，偏過舊畹蘭。"]'),
('3fde46a2-ddcf-46ed-8a36-6e980c7c7e57','閨情','李商隱','唐','唐诗','tang','','[]','紅露花房白蜜脾，黃蜂紫蝶兩參差。',32,'全唐诗/poet.tang.29000.json','["紅露花房白蜜脾，黃蜂紫蝶兩參差。", "春窗一覺風流夢，却是同袍不得知。"]'),
('2628ac9d-9580-4bbd-bbbb-f18d88111367','月夕','李商隱','唐','唐诗','tang','','[]','草下陰蟲葉上霜，朱欄迢遰壓湖光。',32,'全唐诗/poet.tang.29000.json','["草下陰蟲葉上霜，朱欄迢遰壓湖光。", "兔寒蟾冷桂花白，此夜姮娥應斷腸。"]'),
('8960b02a-c182-4559-820f-ff5de87fe7af','杏花','李商隱','唐','唐诗','tang','','[]','上國昔相值，亭亭如欲言。',120,'全唐诗/poet.tang.29000.json','["上國昔相值，亭亭如欲言。", "異鄉今暫賞，眽眽豈無恩。", "援少風多力，墻高月有痕。", "爲含無限意，遂對不勝繁。", "仙子玉京路，主人金谷園。", "幾時辭碧落，誰伴過黃昏。", "鏡拂鉛華膩，爐藏桂燼溫。", "終應催竹葉，先擬詠桃根。", "莫學啼成血，從教夢寄魂。", "吳王採香徑，失路入煙村。"]'),
('039da037-7d76-4ada-9506-457d36bdcc9b','燈','李商隱','唐','唐诗','tang','','[]','皎潔終無倦，煎熬亦自求。',96,'全唐诗/poet.tang.29000.json','["皎潔終無倦，煎熬亦自求。", "花時隨酒遠，雨後背窗休。", "冷暗黃茅驛，暄明紫桂樓。", "錦囊名畫揜，玉局敗碁收。", "何處無佳夢，誰人不隱憂。", "影隨簾押轉，光信簟文流。", "客自勝潘岳，儂今定莫愁。", "固應留半燄，廻照下幃羞。"]'),
('9dc78c4f-f31c-42db-a185-ee62444ba3c8','清河','李商隱','唐','唐诗','tang','','[]','舟小迴仍數，樓危凭亦頻。',48,'全唐诗/poet.tang.29000.json','["舟小迴仍數，樓危凭亦頻。", "燕來從及社，蝶舞太侵晨。", "絳雪除煩後，霜梅取味新。", "年華無一事，只是自傷春。"]'),
('e1e1d9d3-c1a9-43ca-a688-4a31348db4d4','韈','李商隱','唐','唐诗','tang','','[]','嘗聞宓妃韈，渡水欲生塵。',24,'全唐诗/poet.tang.29000.json','["嘗聞宓妃韈，渡水欲生塵。", "好借常娥著，清秋踏月輪。"]'),
('503fd3f8-0607-410d-849a-859887ed55b1','追代盧家人嘲堂內','李商隱','唐','唐诗','tang','','[]','道却橫波字，人前莫謾羞。',24,'全唐诗/poet.tang.29000.json','["道却橫波字，人前莫謾羞。", "只應同楚水，長短入淮流。"]'),
('23436570-7e46-47a8-ac49-80f23ed0a704','代應','李商隱','唐','唐诗','tang','','[]','本來銀漢是紅墻，隔得盧家白玉堂。',32,'全唐诗/poet.tang.29000.json','["本來銀漢是紅墻，隔得盧家白玉堂。", "誰與王昌報消息，盡知三十六鴛鴦。"]'),
('6f74f106-fbf2-40f7-aa71-d3e108bc6c23','離亭賦得折楊柳二首 一','李商隱','唐','唐诗','tang','','[]','暫憑樽酒送無憀，莫損愁眉與細腰。',32,'全唐诗/poet.tang.29000.json','["暫憑樽酒送無憀，莫損愁眉與細腰。", "人世死前惟有別，春風爭擬惜長條。"]'),
('ff15f45a-2833-422f-bb24-5353d22f5547','離亭賦得折楊柳二首 二','李商隱','唐','唐诗','tang','','[]','含煙惹霧每依依，萬緒千條拂落暉。',32,'全唐诗/poet.tang.29000.json','["含煙惹霧每依依，萬緒千條拂落暉。", "爲報行人休盡折，半留相送半迎歸。"]'),
('b9910f88-11a2-424c-bfc2-88c386f476b5','寄永道士','李商隱','唐','唐诗','tang','','[]','共上雲山獨下遲，陽臺白道細如絲。',32,'全唐诗/poet.tang.29000.json','["共上雲山獨下遲，陽臺白道細如絲。", "君今併倚三珠樹，不記人間落葉時。"]'),
('4de022e2-321e-4983-b4f6-c94e07c2f299','華州周大夫宴席','李商隱','唐','唐诗','tang','','[]','郡齋何用酒如泉，飲德先時已醉眠。',32,'全唐诗/poet.tang.29000.json','["郡齋何用酒如泉，飲德先時已醉眠。", "若共門人推禮分，戴崇爭得及彭宣。"]'),
('fa48daca-5999-4ed4-9f70-61209c5b0bc4','荆山','李商隱','唐','唐诗','tang','','[]','壓河連華勢孱顏，鳥沒雲歸一望間。',32,'全唐诗/poet.tang.29000.json','["壓河連華勢孱顏，鳥沒雲歸一望間。", "楊僕移關三百里，可能全是爲荆山。"]'),
('1f1b3f06-88c8-4313-ae2b-644908adcff9','次陝州先寄源從事','李商隱','唐','唐诗','tang','','["\u9ec4\u6cb3"]','離思羈愁日欲晡，東周西雍此分塗。',32,'全唐诗/poet.tang.29000.json','["離思羈愁日欲晡，東周西雍此分塗。", "迴鑾佛寺高多少，望盡黃河一曲無。"]'),
('bfce5f03-6022-43e0-af8b-e8bef9b87524','過鄭廣文舊居','李商隱','唐','唐诗','tang','','[]','宋玉平生恨有餘，遠循三楚弔三閭。',32,'全唐诗/poet.tang.29000.json','["宋玉平生恨有餘，遠循三楚弔三閭。", "可憐留著臨江宅，異代應教庾信居。"]'),
('6cc92d2c-5bba-4cf8-a369-1557fe556342','東下三旬苦于風土馬上戲作','李商隱','唐','唐诗','tang','','[]','路遶函關東復東，身騎征馬逐驚蓬。',32,'全唐诗/poet.tang.29000.json','["路遶函關東復東，身騎征馬逐驚蓬。", "天池遼闊誰相待，日日虛乘九萬風。"]'),
('a1e816b7-c6bf-4bf2-8158-d060202159ea','莫愁','李商隱','唐','唐诗','tang','','[]','雪中梅下與誰期，梅雪相兼一萬枝。',32,'全唐诗/poet.tang.29000.json','["雪中梅下與誰期，梅雪相兼一萬枝。", "若是石城無艇子，莫愁還自有愁時。"]'),
('f224ed41-9d7f-4875-8823-781e34046348','夢令狐學士','李商隱','唐','唐诗','tang','','[]','山驛荒涼白竹扉，殘燈向曉夢清暉。',32,'全唐诗/poet.tang.29000.json','["山驛荒涼白竹扉，殘燈向曉夢清暉。", "右銀臺路雪三尺，鳳詔裁成當直歸。"]'),
('008d34f0-4019-42f0-9134-d86aed22d6a8','涉洛川','李商隱','唐','唐诗','tang','','[]','通谷陽林不見人，我來遺恨古時春。',32,'全唐诗/poet.tang.29000.json','["通谷陽林不見人，我來遺恨古時春。", "宓妃漫結無窮恨，不爲君王殺灌均。"]'),
('167b14c9-a053-43a6-bbbf-da8a86ae688c','有感','李商隱','唐','唐诗','tang','','[]','中路因循我所長，古來才命兩相妨。',32,'全唐诗/poet.tang.29000.json','["中路因循我所長，古來才命兩相妨。", "勸君莫強安蛇足，一醆芳醪不得嘗。"]'),
('0218871b-e34d-419a-a72d-589772fd04cd','宮妓','李商隱','唐','唐诗','tang','','[]','珠箔輕明拂玉墀，披香新殿鬬腰支。',32,'全唐诗/poet.tang.29000.json','["珠箔輕明拂玉墀，披香新殿鬬腰支。", "不須看盡魚龍戲，終遣君王怒偃師。"]'),
('38b35bd3-eec3-43c5-852e-00f5910caca7','宮辭','李商隱','唐','唐诗','tang','','[]','君恩如水向東流，得寵憂移失寵愁。',32,'全唐诗/poet.tang.29000.json','["君恩如水向東流，得寵憂移失寵愁。", "莫向尊前奏花落，涼風只在殿西頭。"]'),
('44f79086-d6ad-44d5-9380-6648cabaa331','代贈二首 一','李商隱','唐','唐诗','tang','','["\u601d\u5ff5", "\u5973\u5b50"]','樓上黃昏欲望休，玉梯橫絕月中鉤。',32,'全唐诗/poet.tang.29000.json','["樓上黃昏欲望休，玉梯橫絕月中鉤。", "芭蕉不展丁香結，同向春風各自愁。"]'),
('51f2bb0f-3b09-4b4d-9c4f-a416190e8ae6','代贈二首 二','李商隱','唐','唐诗','tang','','[]','東南日出照高樓，樓上離人唱石州。',32,'全唐诗/poet.tang.29000.json','["東南日出照高樓，樓上離人唱石州。", "總把春山掃眉黛，不知供得幾多愁。"]'),
('1f6bf355-ab52-4a0a-a42f-8d99bc7b63a4','楚吟','李商隱','唐','唐诗','tang','','["\u6292\u60c5", "\u548f\u53f2", "\u5199\u666f", "\u6000\u624d\u4e0d\u9047"]','山上離宮宮上樓，樓前宮畔暮江流。',32,'全唐诗/poet.tang.29000.json','["山上離宮宮上樓，樓前宮畔暮江流。", "楚天長短黃昏雨，宋玉無愁亦自愁。"]'),
('2161a569-6250-4886-9500-2168821b62be','瑤池','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u7edd\u53e5", "\u795e\u8bdd", "\u8bbd\u523a"]','瑤池阿母綺窗開，黃竹歌聲動地哀。',32,'全唐诗/poet.tang.29000.json','["瑤池阿母綺窗開，黃竹歌聲動地哀。", "八駿日行三萬里，穆王何事不重來。"]'),
('b90f8b9a-5601-4c98-8462-1ea656ab2340','柳','李商隱','唐','唐诗','tang','','[]','爲有橋邊拂面香，何曾自敢占流光。',32,'全唐诗/poet.tang.29000.json','["爲有橋邊拂面香，何曾自敢占流光。", "後庭玉樹承恩澤，不信年華有斷腸。"]'),
('5dcd9b4a-7516-43e3-82a6-cc47ce7dfe94','寄在朝鄭曹獨孤李四同年','李商隱','唐','唐诗','tang','','[]','昔歲陪遊舊跡多，風光今日兩蹉跎。',32,'全唐诗/poet.tang.29000.json','["昔歲陪遊舊跡多，風光今日兩蹉跎。", "不因醉本蘭亭在，兼忘當年舊永和。"]'),
('d7cf50f2-f8d9-4620-83c7-723857af815e','南朝','李商隱','唐','唐诗','tang','','[]','地險悠悠天險長，金陵王氣應瑤光。',32,'全唐诗/poet.tang.29000.json','["地險悠悠天險長，金陵王氣應瑤光。", "休誇此地分天下，只得徐妃半面妝。"]'),
('8849cd61-b181-4847-885d-8aea2e5165ca','題漢祖廟','李商隱','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u548f\u53f2\u6000\u53e4"]','乘運應須宅八荒，男兒安在戀池隍。',32,'全唐诗/poet.tang.29000.json','["乘運應須宅八荒，男兒安在戀池隍。", "君王自起新豐後，項羽何曾在故鄉。"]'),
('607cacdd-9888-4281-b43b-071bd9085ec1','韓冬郎即席爲詩相送一座盡驚他日余方追吟連宵侍坐裴回久之句有老成之風因成二絕寄酬兼呈畏之員外 一','李商隱','唐','唐诗','tang','','[]','十歲裁詩走馬成，冷灰殘燭動離情。',32,'全唐诗/poet.tang.29000.json','["十歲裁詩走馬成，冷灰殘燭動離情。", "桐花萬里丹山路，雛鳳清於老鳳聲。"]'),
('a194afaa-dde6-4cf5-809b-c82206f19989','韓冬郎即席爲詩相送一座盡驚他日余方追吟連宵侍坐裴回久之句有老成之風因成二絕寄酬兼呈畏之員外 二','李商隱','唐','唐诗','tang','','[]','劒棧風檣各苦辛，別時冰雪到時春。',32,'全唐诗/poet.tang.29000.json','["劒棧風檣各苦辛，別時冰雪到時春。", "爲憑何遜休聯句，瘦盡東陽姓沈人。"]'),
('68a964c1-09a8-462f-9432-f6138e4391be','評事翁寄賜餳粥走筆爲答','李商隱','唐','唐诗','tang','','[]','粥香餳白杏花天，省對流鸎坐綺筵。',32,'全唐诗/poet.tang.29000.json','["粥香餳白杏花天，省對流鸎坐綺筵。", "今日寄來春已老，鳳樓迢遞憶鞦韆。"]'),
('dc7a0c41-e77b-4b71-b57c-367b2021f941','東阿王','李商隱','唐','唐诗','tang','','[]','國事分明屬灌均，西陵魂斷夜來人。',32,'全唐诗/poet.tang.29000.json','["國事分明屬灌均，西陵魂斷夜來人。", "君王不得爲天子，半爲當時賦洛神。"]'),
('6665561f-223d-440e-88f2-428f3f252899','聖女祠','李商隱','唐','唐诗','tang','','[]','松篁臺殿蕙香幃，龍護瑤窗鳳掩扉。',64,'全唐诗/poet.tang.29000.json','["松篁臺殿蕙香幃，龍護瑤窗鳳掩扉。", "無質易迷三里霧，不寒長著五銖衣。", "人間定有崔羅什，天上應無劉武威。", "寄問釵頭雙白燕，每朝珠館幾時歸。"]'),
('ebc12e85-7dfc-40a5-a3a2-1ab451c8c388','獨居有懷','李商隱','唐','唐诗','tang','','[]','麝重愁風逼，羅疎畏月侵。',96,'全唐诗/poet.tang.29000.json','["麝重愁風逼，羅疎畏月侵。", "怨魂迷恐斷，嬌喘細疑沈。", "數急芙蓉帶，頻抽翡翠簪。", "柔情終不遠，遙妬已先深。", "浦冷鴛鴦去，園空蛺蝶尋。", "蠟花長遞淚，箏柱鎮移心。", "覓使嵩雲暮，回頭灞岸陰。", "只聞涼葉院，露井近寒砧。"]'),
('875539c2-cf3b-4697-8216-9512aa6a15eb','過景陵','李商隱','唐','唐诗','tang','','[]','武皇精魄久仙昇，帳殿淒涼煙霧凝。',32,'全唐诗/poet.tang.29000.json','["武皇精魄久仙昇，帳殿淒涼煙霧凝。", "俱是蒼生留不得，鼎湖何異魏西陵。"]'),
('b5773a5b-1124-49b5-8154-1dbd684b1d62','臨發崇讓宅紫薇','李商隱','唐','唐诗','tang','','[]','一樹濃姿獨看來，秋庭暮雨類輕埃。',64,'全唐诗/poet.tang.29000.json','["一樹濃姿獨看來，秋庭暮雨類輕埃。", "不先搖落應爲有，已欲別離休更開。", "桃綬含情依露井，柳綿相憶隔章臺。", "天涯地角同榮謝，豈要移根上苑栽。"]'),
('54da7f86-44e4-4057-a4f0-b2db15b336d6','及第東歸次灞上却寄同年','李商隱','唐','唐诗','tang','','[]','芳桂當年各一枝，行期未分壓春期。',64,'全唐诗/poet.tang.29000.json','["芳桂當年各一枝，行期未分壓春期。", "江魚朔雁長相憶，秦樹嵩雲自不知。", "下苑經過勞想像，東門送餞又差池。", "灞陵柳色無離恨，莫枉長條贈所思。"]'),
('2186935c-d029-4ee0-b0b1-4f6341b0323b','野菊','李商隱','唐','唐诗','tang','','["\u548f\u7269", "\u6292\u60c5", "\u83ca\u82b1", "\u548f\u7269\u8bd7", "\u5bc2\u5bde"]','苦竹園南椒塢邊，微香冉冉淚涓涓。',64,'全唐诗/poet.tang.29000.json','["苦竹園南椒塢邊，微香冉冉淚涓涓。", "已悲節物同寒雁，忍委芳心與暮蟬。", "細路獨來當此夕，清尊相伴省他年。", "紫雲新苑移花處，不取霜栽近御筵。"]'),
('4c7a33cd-54a7-47bb-b92d-d4bdd4b879cd','板橋曉別','李商隱','唐','唐诗','tang','','["\u79bb\u522b", "\u5199\u666f"]','回望高城落曉河，長亭窗戶壓微波。',32,'全唐诗/poet.tang.29000.json','["回望高城落曉河，長亭窗戶壓微波。", "水仙欲上鯉魚去，一夜芙蓉紅淚多。"]'),
('4a37bce0-71e0-41b2-bbbd-73c069c2cdbc','過伊僕射舊宅','李商隱','唐','唐诗','tang','','[]','朱邸方酬力戰功，華筵俄歎逝波窮。',64,'全唐诗/poet.tang.29000.json','["朱邸方酬力戰功，華筵俄歎逝波窮。", "回廊簷斷燕飛去，小閣塵凝人語空。", "幽淚欲乾殘菊露，餘香猶入敗荷風。", "何能更涉瀧江去，獨立寒流弔楚宮。"]'),
('be7bd924-05fe-4c56-b766-2e5abc43d886','關門柳','李商隱','唐','唐诗','tang','','[]','永定河邊一行柳，依依長發故年春。',32,'全唐诗/poet.tang.29000.json','["永定河邊一行柳，依依長發故年春。", "東來西去人情薄，不爲清陰減路塵。"]'),
('d94bd685-56c2-4226-a759-c3ae97956296','酬別令狐補闕','李商隱','唐','唐诗','tang','','[]','惜別夏仍半，回途秋已期。',72,'全唐诗/poet.tang.29000.json','["惜別夏仍半，回途秋已期。", "那脩直諫草，更賦贈行詩。", "錦段知無報，青萍肯見疑。", "人生有通塞，公等繫安危。", "警露鶴辭侶，吸風蟬抱枝。", "彈冠如不問，又到掃門時。"]'),
('a3112b33-9adf-4261-a6f7-9c3cf7f15a41','銀河吹笙','李商隱','唐','唐诗','tang','','["\u8ffd\u5fc6", "\u7231\u60c5", "\u6000\u5ff5"]','悵望銀河吹玉笙，樓寒院冷接平明。',64,'全唐诗/poet.tang.29000.json','["悵望銀河吹玉笙，樓寒院冷接平明。", "重衾幽夢他年斷，別樹羈雌昨夜驚。", "月榭故香因雨發，風簾殘燭隔霜清。", "不須浪作緱山意，湘瑟秦簫自有情。"]'),
('85bdc827-ec2d-40d6-bc96-75a92744a451','與同年李定言曲水閑話戲作','李商隱','唐','唐诗','tang','','[]','海燕參差溝水流，同君身世屬離憂。',64,'全唐诗/poet.tang.29000.json','["海燕參差溝水流，同君身世屬離憂。", "相攜花下非秦贅，對泣春天類楚囚。", "碧草暗侵穿苑路，珠簾不捲枕江樓。", "莫驚五勝埋香骨，地下傷春亦白頭。"]'),
('926ed9c9-7fab-45a1-b8e8-72971937173d','彭城公薨後贈杜二十七勝李十七潘二君竝與愚同出故尚書安平公門下','李商隱','唐','唐诗','tang','','[]','梁山兖水約從公，兩地參差一旦空。',32,'全唐诗/poet.tang.29000.json','["梁山兖水約從公，兩地參差一旦空。", "謝墅庾村相弔後，自今歧路各西東。"]'),
('1e36705c-24cf-4e35-a9ee-c994edd8c443','聞歌','李商隱','唐','唐诗','tang','','[]','斂笑凝眸意欲歌，高雲不動碧嵯峨。',64,'全唐诗/poet.tang.29000.json','["斂笑凝眸意欲歌，高雲不動碧嵯峨。", "銅臺罷望歸何處，玉輦忘還事幾多。", "青冢路邊南雁盡，細腰宮裏北人過。", "此聲腸斷非今日，香灺燈光奈爾何。"]'),
('9b00f413-2151-4371-afc6-27fbd40bba2f','贈華陽宋真人兼寄清都劉先生','李商隱','唐','唐诗','tang','','[]','淪謫千年別帝宸，至今猶謝蘂珠人。',64,'全唐诗/poet.tang.29000.json','["淪謫千年別帝宸，至今猶謝蘂珠人。", "但驚茅許同仙籍，不道劉盧是世親。", "玉撿賜書迷鳳篆，金華歸駕冷龍鱗。", "不因杖屨逢周史，徐甲何曾有此身。"]'),
('b0e0fed4-bbf2-434e-aee8-f6a82c722c85','楚宮二首 一','李商隱','唐','唐诗','tang','','[]','十二峰前落照微，高唐宮暗坐迷歸。',32,'全唐诗/poet.tang.29000.json','["十二峰前落照微，高唐宮暗坐迷歸。", "朝雲暮雨長相接，猶自君王恨見稀。"]'),
('fdbf77fd-ed38-490f-a090-ba7040273f83','楚宮二首 二','李商隱','唐','唐诗','tang','','[]','月姊曾逢下彩蟾，傾城消息隔重簾。',64,'全唐诗/poet.tang.29000.json','["月姊曾逢下彩蟾，傾城消息隔重簾。", "已聞佩響知腰細，更辨絃聲覺指纖。", "暮雨自歸山悄悄，秋河不動夜厭厭。", "王昌且在牆東住，未必金堂得免嫌。"]'),
('f332ec60-421a-49e0-addd-94ed01d9f3d9','和友人戲贈二首 一','李商隱','唐','唐诗','tang','','[]','東望花樓會不同，西來雙燕信休通。',64,'全唐诗/poet.tang.29000.json','["東望花樓會不同，西來雙燕信休通。", "仙人掌冷三霄露，玉女窗虛五夜風。", "翠袖自隨回雪轉，燭房尋類外庭空。", "殷勤莫使清香透，牢合金魚鏁桂叢。"]'),
('ce27db7e-0077-41a1-9872-f7aecc077d40','和友人戲贈二首 二','李商隱','唐','唐诗','tang','','[]','迢遰青門有幾關，柳梢樓角見南山。',64,'全唐诗/poet.tang.29000.json','["迢遰青門有幾關，柳梢樓角見南山。", "明珠可貫須爲佩，白璧堪裁且作環。", "子夜休歌團扇揜，新正未破剪刀閑。", "猿啼鶴怨終年事，未抵熏爐一夕間。"]'),
('66b33383-1aa5-4ec3-8f69-021007fc14ca','題二首後重有戲贈任秀才','李商隱','唐','唐诗','tang','','[]','一丈紅薔擁翠筠，羅窗不識繞街塵。',64,'全唐诗/poet.tang.29000.json','["一丈紅薔擁翠筠，羅窗不識繞街塵。", "峽中尋覓長逢雨，月裏依稀更有人。", "虛爲錯刀留遠客，枉緣書札損文鱗。", "遙知小閣還斜照，羨殺烏龍臥錦茵。"]'),
('c802da18-34e9-40bf-ac0d-350c23fa0aeb','有感二首 一','李商隱','唐','唐诗','tang','','[]','九服歸元化，三靈叶睿圖。',96,'全唐诗/poet.tang.29000.json','["九服歸元化，三靈叶睿圖。", "如何本初輩，自取屈氂誅。", "有甚當車泣，因勞下殿趨。", "何成奏雲物，直是滅萑苻。", "證逮符書密，辭連性命俱。", "竟緣尊漢相，不早辨胡雛。", "鬼籙分朝部，軍烽照上都。", "敢云堪慟哭，未免怨洪爐。"]'),
('f73b9375-ef5e-4a4b-9b94-6367a4054385','有感二首 二','李商隱','唐','唐诗','tang','','[]','丹陛猶敷奏，彤庭歘戰爭。',96,'全唐诗/poet.tang.29000.json','["丹陛猶敷奏，彤庭歘戰爭。", "臨危對盧植，始悔用龐萌。", "御仗收前殿，兵徒劇背城。", "蒼黃五色棒，掩遏一陽生。", "古有清君側，今非乏老成。", "素心雖未易，此舉太無名。", "誰瞑銜冤目，寧吞欲絕聲。", "近聞開壽讌，不廢用咸英。"]'),
('06609c06-2c71-4ec5-a1ac-89e76d2c3428','重有感','李商隱','唐','唐诗','tang','','["\u7231\u56fd"]','玉帳牙旗得上遊，安危須共主君憂。',64,'全唐诗/poet.tang.29000.json','["玉帳牙旗得上遊，安危須共主君憂。", "竇融表已來關右，陶侃軍宜次石頭。", "豈有蛟龍愁失水，更無鷹隼與高秋。", "晝號夜哭兼幽顯，早晚星關雪涕收。"]'),
('c068b506-f9b7-48de-a916-1aefb2ace2d2','壽安公主出降','李商隱','唐','唐诗','tang','','[]','溈水聞貞媛，常山索銳師。',48,'全唐诗/poet.tang.29000.json','["溈水聞貞媛，常山索銳師。", "昔憂迷帝力，今分送王姬。", "事等和強虜，恩殊睦本枝。", "四郊多壘在，此禮恐無時。"]'),
('314bff28-4e76-4516-a388-3d49878c69f4','夕陽樓','李商隱','唐','唐诗','tang','','[]','花明柳暗繞天愁，上盡重城更上樓。',32,'全唐诗/poet.tang.29000.json','["花明柳暗繞天愁，上盡重城更上樓。", "欲問孤鴻向何處，不知身世自悠悠。"]'),
('8331c76b-a250-4d07-9c28-b8a456e0974c','春雨','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u96e8", "\u4e03\u8a00\u5f8b\u8bd7", "\u7231\u60c5", "\u96e8"]','悵臥新春白袷衣，白門寥落意多違。',64,'全唐诗/poet.tang.29000.json','["悵臥新春白袷衣，白門寥落意多違。", "紅樓隔雨相望冷，珠箔飄燈獨自歸。", "遠路應悲春晼晚，殘宵猶得夢依稀。", "玉璫緘札何由達，萬里雲羅一雁飛。"]'),
('d5c1800d-add5-46ba-b1a7-2a1efbee7f99','中元作','李商隱','唐','唐诗','tang','','[]','絳節飄颻宮國來，中元朝拜上清回。',64,'全唐诗/poet.tang.29000.json','["絳節飄颻宮國來，中元朝拜上清回。", "羊權須得金條脫，溫嶠終虛玉鏡臺。", "曾省驚眠聞雨過，不知迷路爲花開。", "有娀未抵瀛洲遠，青雀如何鴆鳥媒。"]'),
('7ec99484-1412-4b81-9f94-c42d559dfd54','鴛鴦','李商隱','唐','唐诗','tang','','[]','雌去雄飛萬里天，雲羅滿眼淚潸然。',32,'全唐诗/poet.tang.29000.json','["雌去雄飛萬里天，雲羅滿眼淚潸然。", "不須長結風波願，鎖向金籠始兩全。"]'),
('f1ed72b6-15e2-4576-895d-52a917386936','楚宮','李商隱','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u60bc\u4ea1", "\u548f\u53f2\u6000\u53e4"]','湘波如淚色漻繆，楚厲迷魂逐恨遙。',64,'全唐诗/poet.tang.29000.json','["湘波如淚色漻繆，楚厲迷魂逐恨遙。", "楓樹夜猿愁自斷，女蘿山鬼語相邀。", "空歸腐敗猶難復，更困腥臊豈易招。", "但使故鄉三戶在，綵絲誰惜懼長蛟。"]'),
('682b6406-99cc-4a58-9b4a-6f2163a36178','妓席暗記送同年獨孤雲之武昌','李商隱','唐','唐诗','tang','','["\u957f\u6c5f"]','疊嶂千重呌恨猿，長江萬里洗離魂。',32,'全唐诗/poet.tang.29000.json','["疊嶂千重呌恨猿，長江萬里洗離魂。", "武昌若有山頭石，爲拂蒼苔檢淚痕。"]'),
('1dfafe07-1bbd-40d0-b70c-a3f7a94fe995','宿晉昌亭聞驚禽','李商隱','唐','唐诗','tang','','[]','羇緒鰥鰥夜景侵，高窗不掩見驚禽。',64,'全唐诗/poet.tang.29000.json','["羇緒鰥鰥夜景侵，高窗不掩見驚禽。", "飛來曲渚煙方合，過盡南塘樹更深。", "胡馬嘶和榆塞笛，楚猿吟雜橘村砧。", "失羣掛木知何限，遠隔天涯共此心。"]'),
('ac26a868-7b6b-4c47-a71b-d718683af67a','深宮','李商隱','唐','唐诗','tang','','[]','金殿銷香閉綺櫳，玉壺傳點咽銅龍。',64,'全唐诗/poet.tang.29000.json','["金殿銷香閉綺櫳，玉壺傳點咽銅龍。", "狂飆不惜蘿陰薄，清露偏知桂葉濃。", "斑竹嶺邊無限淚，景陽宮裏及時鐘。", "豈知爲雨爲雲處，只有高唐十二峰。"]'),
('ef3d063c-4403-49de-9e11-9c9be8eda363','明禪師院酬從兄見寄','李商隱','唐','唐诗','tang','','[]','貞吝嫌茲世，會心馳本原。',48,'全唐诗/poet.tang.29000.json','["貞吝嫌茲世，會心馳本原。", "人非四禪縛，地絕一塵喧。", "霜露欹高木，星河壓故園。", "撕遊儻爲勝，九折幸回軒。"]'),
('d157abb5-7728-4c43-aa0a-c19b8ac2b0b5','寄裴衡','李商隱','唐','唐诗','tang','','[]','別地蕭條極，如何更獨來。',48,'全唐诗/poet.tang.29000.json','["別地蕭條極，如何更獨來。", "秋應爲黃葉，雨不厭青苔。", "沈約只能瘦，潘仁豈是才。", "雜情堪底寄，惟有冷於灰。"]'),
('fc87ee7a-6346-4d3f-b76e-30bf5b091e66','即日','李商隱','唐','唐诗','tang','','[]','小苑試春衣，高樓倚暮暉。',48,'全唐诗/poet.tang.29000.json','["小苑試春衣，高樓倚暮暉。", "夭桃惟是笑，舞蝶不空飛。", "赤嶺久無耗，鴻門猶合圍。", "幾家緣錦字，含淚坐鴛機。"]'),
('8f8ea85f-aab0-4a42-bfff-339542425d29','淮陽路','李商隱','唐','唐诗','tang','','[]','荒村倚廢營，投宿旅魂驚。',48,'全唐诗/poet.tang.29000.json','["荒村倚廢營，投宿旅魂驚。", "斷雁高仍急，寒溪曉更清。", "昔年嘗聚盜，此日頗分兵。", "猜貳誰先致，三朝事始平。"]'),
('c9ff794b-ce5f-43fe-8ba8-9d3f42eafacf','崇讓宅東亭醉後沔然有作','李商隱','唐','唐诗','tang','','[]','曲岸風雷罷，東亭霽日涼。',120,'全唐诗/poet.tang.29000.json','["曲岸風雷罷，東亭霽日涼。", "新秋仍酒困，幽興暫江鄉。", "搖落真何遽，交親或未忘。", "一帆彭蠡月，數雁塞門霜。", "俗態雖多累，仙標發近狂。", "聲名佳句在，身世玉琴張。", "萬古山空碧，無人鬢免黃。", "驊騮憂老大，鶗鴂妬芬芳。", "密竹沉虛籟，孤蓮泊晚香。", "如何此幽勝，淹臥劇清漳。"]'),
('fe966059-d9e0-41b0-8776-ff745cf877bc','晚晴','李商隱','唐','唐诗','tang','','["\u5199\u666f", "\u590f\u5929", "\u6292\u60c5", "\u767b\u9ad8"]','深居俯夾城，春去夏猶清。',48,'全唐诗/poet.tang.29000.json','["深居俯夾城，春去夏猶清。", "天意憐幽草，人間重晚晴。", "併添高閣迥，微注小窗明。", "越鳥巢乾後，歸飛體更輕。"]'),
('32525dbe-5358-4fec-8d82-ae7b34119853','迎寄韓魯州','李商隱','唐','唐诗','tang','','[]','積雨晚騷騷，相思正鬱陶。',48,'全唐诗/poet.tang.29000.json','["積雨晚騷騷，相思正鬱陶。", "不知人萬里，時有燕雙高。", "寇盜纏三輔，莓苔滑百牢。", "聖朝推衛霍，歸日動仙曹。"]'),
('5aa573a4-f08e-4447-a053-f7723607d3e5','武夷山','李商隱','唐','唐诗','tang','','["\u5199\u5c71", "\u63cf\u5199\u5c71"]','只得流霞酒一杯，空中簫鼓幾時回。',32,'全唐诗/poet.tang.29000.json','["只得流霞酒一杯，空中簫鼓幾時回。", "武夷洞裏生毛竹，老盡曾孫更不來。"]'),
('13076522-b29a-42a4-b49f-ffff7ebb164b','一片','李商隱','唐','唐诗','tang','','[]','一片瓊英價動天，連城十二昔虛傳。',32,'全唐诗/poet.tang.29000.json','["一片瓊英價動天，連城十二昔虛傳。", "良工巧費真爲累，楮葉成來不直錢。"]'),
('d8759c08-8fe1-4c91-ad4c-7ce9603884f6','寄成都高苗二從事','李商隱','唐','唐诗','tang','','[]','紅蓮幕下紫棃新，命斷湘南病渴人。',32,'全唐诗/poet.tang.29000.json','["紅蓮幕下紫棃新，命斷湘南病渴人。", "今日問君能寄否，二江風水接天津。"]'),
('382a6a9a-c67a-4a12-ac97-0003bd0f8c89','鄭州獻從叔舍人褎','李商隱','唐','唐诗','tang','','[]','蓬島煙霞閬苑鐘，三官箋奏附金龍。',64,'全唐诗/poet.tang.29000.json','["蓬島煙霞閬苑鐘，三官箋奏附金龍。", "茅君奕世仙曹貴，許掾全家道氣濃。", "絳簡尚參黃紙案，丹爐猶用紫泥封。", "不知他日華陽洞，許上經樓第幾重。"]'),
('c4adfa07-0b3d-4434-a8b7-a89634852932','西南行却寄相送者','李商隱','唐','唐诗','tang','','[]','百里陰雲覆雪泥，行人只在雪雲西。',32,'全唐诗/poet.tang.29000.json','["百里陰雲覆雪泥，行人只在雪雲西。", "明朝驚破還鄉夢，定是陳倉碧野雞。"]'),
('4cffdb3f-f281-4e30-9aa5-2a7ddd22027d','四皓廟','李商隱','唐','唐诗','tang','','[]','羽翼殊勳棄若遺，皇天有運我無時。',32,'全唐诗/poet.tang.29000.json','["羽翼殊勳棄若遺，皇天有運我無時。", "廟前便接山門路，不長青松長紫芝。"]'),
('0584bca6-3fb6-43d8-945b-11800654fe0f','題白石蓮花寄楚公','李商隱','唐','唐诗','tang','','[]','白石蓮花誰所共，六時長捧佛前燈。',64,'全唐诗/poet.tang.29000.json','["白石蓮花誰所共，六時長捧佛前燈。", "空庭苔蘚饒霜露，時夢西山老病僧。", "大海龍宮無限地，諸天雁塔幾多層。", "漫誇鶖子真羅漢，不會牛車是上乘。"]'),
('1c2467a6-24a4-4556-847a-13818099dacb','[安定]城樓','李商隱','唐','唐诗','tang','','[]','迢遰高城百尺樓，綠楊枝外盡汀洲。',64,'全唐诗/poet.tang.29000.json','["迢遰高城百尺樓，綠楊枝外盡汀洲。", "賈生年少虛垂淚，王粲春來更遠遊。", "永憶江湖歸白髮，欲回天地入扁舟。", "不知腐鼠成滋味，猜意鴛雛竟未休。"]'),
('80c97c16-3012-4f56-aced-493434184fd6','隋宮守歲','李商隱','唐','唐诗','tang','','[]','消息東郊木帝回，宮中行樂有新梅。',64,'全唐诗/poet.tang.29000.json','["消息東郊木帝回，宮中行樂有新梅。", "沈香甲煎爲庭燎，玉液瓊蘇作壽杯。", "遙望露盤疑是月，遠聞鼉鼓欲驚雷。", "昭陽第一傾城客，不踏金蓮不肯來。"]'),
('f5a258f1-bcce-41a0-bee1-e6e785f30ca7','利州江潭作','李商隱','唐','唐诗','tang','','[]','神劒飛來不易銷，碧潭珍重駐蘭橈。',64,'全唐诗/poet.tang.29000.json','["神劒飛來不易銷，碧潭珍重駐蘭橈。", "自攜明月移燈疾，欲就行雲散錦遙。", "河伯軒窗通貝闕，水宮帷箔卷冰綃。", "他時燕脯無人寄，雨滿空城蕙葉雕。"]'),
('321aa72d-3178-42d4-9b63-be26a0bb3b3e','即目','李商隱','唐','唐诗','tang','','[]','地寬樓已迥，人更迥於樓。',96,'全唐诗/poet.tang.29000.json','["地寬樓已迥，人更迥於樓。", "細意經春物，傷酲屬暮愁。", "望賒殊易斷，恨久欲難收。", "大埶真無利，多情豈自由。", "空園兼樹廢，敗港擁花流。", "書去青楓驛，鴻歸杜若洲。", "單棲應分定，辭疾索誰憂。", "更替林鵶恨，驚頻去不休。"]'),
('290595ea-c887-4b90-aeb7-76eecf3ba58f','相思','李商隱','唐','唐诗','tang','','[]','相思樹上合歡枝，紫鳳青鸞共羽儀。',32,'全唐诗/poet.tang.29000.json','["相思樹上合歡枝，紫鳳青鸞共羽儀。", "腸斷秦臺吹管客，日西春盡到來遲。"]'),
('ae1df834-6ec8-4338-bb9c-09a923b2943d','茂陵','李商隱','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u548f\u53f2\u6000\u53e4", "\u8bbd\u523a"]','漢家天馬出蒲梢，苜蓿榴花遍近郊。',64,'全唐诗/poet.tang.29000.json','["漢家天馬出蒲梢，苜蓿榴花遍近郊。", "內苑只知含鳳觜，屬車無復插雞翹。", "玉桃偷得憐方朔，金屋脩成貯阿嬌。", "誰料蘇卿老歸國，茂陵松栢雨蕭蕭。"]'),
('c26081b2-47fd-4098-a10f-61df2879aec8','鏡檻','李商隱','唐','唐诗','tang','','[]','鏡檻芙蓉入，香臺翡翠過。',192,'全唐诗/poet.tang.29000.json','["鏡檻芙蓉入，香臺翡翠過。", "撥弦驚火鳳，交扇拂天鵝。", "隱忍陽城笑，喧傳郢市歌。", "仙眉瓊作葉，佛髻鈿爲螺。", "五里無因霧，三秋只見河。", "月中供藥剩，海上得綃多。", "玉集胡沙割，犀留聖水磨。", "斜門穿戲蝶，小閣鎖飛蛾。", "騎襜侵韉卷，車帷約幰鈋。", "傳書兩行雁，取酒一封駞。", "橋迥涼風壓，溝橫夕照和。", "待烏燕太子，駐馬魏東阿。", "想像鋪芳褥，依稀解醉羅。", "散時簾隔露，臥後幕生波。", "梯穩從攀桂，弓調任射莎。", "豈能拋斷夢，聽鼓事朝珂。"]'),
('f61bba78-f169-4a11-884c-c70979076412','送鄭大台文南覲','李商隱','唐','唐诗','tang','','[]','黎辟灘聲五月寒，南風無處附平安。',32,'全唐诗/poet.tang.29000.json','["黎辟灘聲五月寒，南風無處附平安。", "君懷一匹胡威絹，爭拭酬恩淚得乾。"]'),
('2a3ec8d9-9b38-4d86-9b23-077176008e7d','風','李商隱','唐','唐诗','tang','','[]','迥拂來鴻急，斜催別燕高。',48,'全唐诗/poet.tang.29000.json','["迥拂來鴻急，斜催別燕高。", "已寒休慘淡，更遠尚呼號。", "楚色分西塞，夷音接下牢。", "歸舟天外有，一爲戒波濤。"]'),
('24b9a540-7a2c-4dba-8327-ed533a0adbf6','洞庭魚','李商隱','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭魚可拾，不假更垂罾。',48,'全唐诗/poet.tang.29000.json','["洞庭魚可拾，不假更垂罾。", "鬧若雨前蟻，多於秋後蠅。", "豈思鱗作簟，仍計腹爲燈。", "浩蕩天池路，翱翔欲化鵬。"]'),
('e3dfd440-d250-4f79-9131-0a9877afe5db','天涯','李商隱','唐','唐诗','tang','','["\u7f81\u65c5", "\u6292\u60c5", "\u82e6\u75db", "\u5199\u9e1f", "\u6625\u5929", "\u9e1f"]','春日在天涯，天涯日又斜。',24,'全唐诗/poet.tang.29000.json','["春日在天涯，天涯日又斜。", "鶯啼如有淚，爲溼最高花。"]'),
('a5fa4a45-19ce-4b9a-9aa6-25a77a94651e','喜舍弟羲叟及第上禮部魏公','李商隱','唐','唐诗','tang','','[]','國以斯文重，公仍內署來。',48,'全唐诗/poet.tang.29000.json','["國以斯文重，公仍內署來。", "風標森太華，星象逼中台。", "朝滿遷鸎侶，門多吐鳳才。", "寧同魯司寇，惟鑄一顏回。"]'),
('441652b5-bc89-4f25-a7e2-e0c8830bbe91','哀箏','李商隱','唐','唐诗','tang','','[]','延頸全同鶴，柔腸素怯猿。',48,'全唐诗/poet.tang.29000.json','["延頸全同鶴，柔腸素怯猿。", "湘波無限淚，蜀魄有餘冤。", "輕幰長無道，哀箏不出門。", "何由問香炷，翠幕自黃昏。"]'),
('27785d86-ef4c-45b6-b06f-10ef16ab04bc','自南山北歸經分水嶺','李商隱','唐','唐诗','tang','','[]','水急愁無地，山深故有雲。',48,'全唐诗/poet.tang.29000.json','["水急愁無地，山深故有雲。", "那通極目望，又作斷腸分。", "鄭驛來雖及，燕臺哭不聞。", "猶餘遺意在，許刻鎮南勳。"]'),
('f3a53f7d-75b7-46ba-afb0-7518a6f595b1','舊頓','李商隱','唐','唐诗','tang','','[]','東人望幸久咨嗟，四海於今是一家。',32,'全唐诗/poet.tang.29000.json','["東人望幸久咨嗟，四海於今是一家。", "猶鎖平時舊行殿，盡無宮戶有宮鴉。"]'),
('f963bac2-1690-4563-b26d-0c23a1935f53','代董秀才却扇','李商隱','唐','唐诗','tang','','[]','莫將畫扇出帷來，遮掩春山滯上才。',32,'全唐诗/poet.tang.29000.json','["莫將畫扇出帷來，遮掩春山滯上才。", "若道團圓似明月，此中須放桂花開。"]'),
('ed66d98b-17ba-4efe-976c-4d8f598c44d1','有感','李商隱','唐','唐诗','tang','','[]','非關宋玉有微辭，却是襄王夢覺遲。',32,'全唐诗/poet.tang.29000.json','["非關宋玉有微辭，却是襄王夢覺遲。", "一自高唐賦成後，楚天雲雨盡堪疑。"]'),
('4b2238ab-7c28-4e12-a086-43562c51b81f','驪山有感','李商隱','唐','唐诗','tang','','[]','驪岫飛泉泛暖香，九龍呵護玉蓮房。',32,'全唐诗/poet.tang.29000.json','["驪岫飛泉泛暖香，九龍呵護玉蓮房。", "平明每幸長生殿，不從金輿惟壽王。"]'),
('26219a47-f414-4a7f-a0e8-45f48438f28f','別智玄法師','李商隱','唐','唐诗','tang','','[]','雲鬢無端怨別離，十年移易住山期。',32,'全唐诗/poet.tang.29000.json','["雲鬢無端怨別離，十年移易住山期。", "東西南北皆垂淚，却是楊朱真本師。"]'),
('9254f723-ac73-44c0-b6e6-e673b89f4af0','贈孫綺新及第','李商隱','唐','唐诗','tang','','[]','長樂遙聽上苑鐘，綵衣稱慶桂香濃。',32,'全唐诗/poet.tang.29000.json','["長樂遙聽上苑鐘，綵衣稱慶桂香濃。", "陸機始擬誇文賦，不覺雲間有士龍。"]'),
('058b45cb-6338-49d2-af61-fb3d05980bdc','代秘書贈弘文館諸校書','李商隱','唐','唐诗','tang','','[]','清切曹司近玉除，比來秋興復何如。',32,'全唐诗/poet.tang.29000.json','["清切曹司近玉除，比來秋興復何如。", "崇文館裏丹霜後，無限紅棃憶校書。"]'),
('245493d5-ed57-489e-aa36-45d6947f3cab','亂石','李商隱','唐','唐诗','tang','','[]','虎踞龍蹲縱復橫，星光漸減雨痕生。',32,'全唐诗/poet.tang.29000.json','["虎踞龍蹲縱復橫，星光漸減雨痕生。", "不須併礙東西路，哭殺廚頭阮步兵。"]'),
('c3b72999-28de-457a-a344-dc400d52943f','日日','李商隱','唐','唐诗','tang','','[]','日日春光鬬日光，山城斜路杏花香。',32,'全唐诗/poet.tang.29000.json','["日日春光鬬日光，山城斜路杏花香。", "幾時心緒渾無事，得及游絲百尺長。"]'),
('f00479ca-fd1b-4a9e-bd7d-7e471a4e6464','過楚宮','李商隱','唐','唐诗','tang','','[]','巫峽迢迢舊楚宮，至今雲雨暗丹楓。',32,'全唐诗/poet.tang.29000.json','["巫峽迢迢舊楚宮，至今雲雨暗丹楓。", "微生盡戀人間樂，只有襄王憶夢中。"]'),
('8db70485-e8b8-422d-b87f-1c59c536325e','龍池','李商隱','唐','唐诗','tang','','[]','龍池賜酒敞雲屏，羯鼓聲高衆樂停。',32,'全唐诗/poet.tang.29000.json','["龍池賜酒敞雲屏，羯鼓聲高衆樂停。", "夜半宴歸宮漏永，薛王沉醉壽王醒。"]'),
('d6f1b7a8-b400-46f5-b7d7-2061ace55322','涙','李商隱','唐','唐诗','tang','','[]','永巷長年怨綺羅，離情終日思風波。',64,'全唐诗/poet.tang.29000.json','["永巷長年怨綺羅，離情終日思風波。", "湘江竹上痕無限，峴首碑前灑幾多。", "人去紫臺秋入塞，兵殘楚帳夜聞歌。", "朝來灞水橋邊問，未抵青袍送玉珂。"]'),
('f9d86129-5463-42d3-9e96-3150f126ccad','十字水期韋潘侍御同年不至時韋寓居水次故郭汾寧宅','李商隱','唐','唐诗','tang','','[]','伊水濺濺相背流，朱欄畫閣幾人遊。',64,'全唐诗/poet.tang.29000.json','["伊水濺濺相背流，朱欄畫閣幾人遊。", "漆燈夜照真無數，蠟炬晨炊竟未休。", "顧我有懷同大夢，期君不至更沉憂。", "西園碧樹今誰主，與近高窗臥聽秋。"]'),
('5f1d1587-07a6-452c-9264-3c55e26b173c','流鸎','李商隱','唐','唐诗','tang','','["\u548f\u7269", "\u6292\u60c5", "\u8eab\u4e16", "\u5199\u9e1f", "\u548f\u7269\u8bd7", "\u9e1f"]','流鸎飄蕩復參差，渡陌臨流不自持。',48,'全唐诗/poet.tang.29000.json','["流鸎飄蕩復參差，渡陌臨流不自持。", "巧囀豈能無本意，良辰未必有佳期。", "風朝露夜陰晴裏，萬戶千門開閉時。"]'),
('a3df8e68-d875-4db2-a709-c07eb8bae466','出關宿盤豆館對叢蘆有感','李商隱','唐','唐诗','tang','','[]','蘆葉梢梢夏景深，郵亭暫欲灑塵襟。',64,'全唐诗/poet.tang.29000.json','["蘆葉梢梢夏景深，郵亭暫欲灑塵襟。", "昔年曾是江南客，此日初爲關外心。", "思子臺邊風自急，玉孃湖上月應沈。", "清聲不遠行人去，一世荒城伴夜砧。"]'),
('9bae5a01-c8c7-4a16-a3d3-89b5fcd0e305','和韓錄事送宮人入道','李商隱','唐','唐诗','tang','','[]','星使追還不自由，雙童捧上綠瓊輈。',64,'全唐诗/poet.tang.29000.json','["星使追還不自由，雙童捧上綠瓊輈。", "九枝燈下朝金殿，三素雲中侍玉樓。", "鳳女顛狂成久別，月娥孀獨好同遊。", "當時若愛韓公子，埋骨成灰恨未休。"]'),
('3896840c-3fe8-4548-95b5-7eea3bae363f','即目','李商隱','唐','唐诗','tang','','[]','小鼎煎茶面曲池，白鬚道士竹間棋。',32,'全唐诗/poet.tang.29000.json','["小鼎煎茶面曲池，白鬚道士竹間棋。", "何人書破蒲葵扇，記著南塘移樹時。"]'),
('3c621f65-39a2-456c-ab95-6ef8b45e974d','聖女祠','李商隱','唐','唐诗','tang','','[]','杳藹逢仙跡，蒼茫滯客途。',96,'全唐诗/poet.tang.29000.json','["杳藹逢仙跡，蒼茫滯客途。", "何年歸碧落，此路向皇都。", "消息期青雀，逢迎異紫姑。", "腸回楚國夢，心斷漢宮巫。", "從騎裁寒竹，行車蔭白榆。", "星娥一去後，月姊更來無。", "寡鵠迷蒼壑，羇凰怨翠梧。", "惟應碧桃下，方朔是狂夫。"]'),
('dd56a399-b6d6-41c5-8c89-53fea6235883','七月二十九日崇讓宅讌作','李商隱','唐','唐诗','tang','','["\u79cb\u5929", "\u58ee\u5fd7\u96be\u916c", "\u5199\u666f", "\u611f\u6168"]','露如微霰下前池，月過回塘萬竹悲。',64,'全唐诗/poet.tang.29000.json','["露如微霰下前池，月過回塘萬竹悲。", "浮世本來多聚散，紅蕖何事亦離披。", "悠揚歸夢惟燈見，濩落生涯獨酒知。", "豈到白頭長只爾，嵩陽松雪有心期。"]'),
('fcbdf93f-a1a6-4d39-8d39-2f35534cd3a4','贈從兄閬之','李商隱','唐','唐诗','tang','','[]','悵望人間萬事違，私書幽夢約忘機。',64,'全唐诗/poet.tang.29000.json','["悵望人間萬事違，私書幽夢約忘機。", "荻花村裏魚標在，石蘚庭中鹿跡微。", "幽徑定攜僧共入，寒塘好與月相依。", "城中猘犬憎蘭佩，莫損幽芳久不歸。"]'),
('1b46369b-d429-4216-9d01-8c59005107dc','吳宮','李商隱','唐','唐诗','tang','','[]','龍檻沈沈水殿清，禁門深揜斷人聲。',32,'全唐诗/poet.tang.29000.json','["龍檻沈沈水殿清，禁門深揜斷人聲。", "吳王宴罷滿宮醉，日暮水漂花出城。"]'),
('f7c9c409-9571-4eb8-abd9-91ec6c1ff564','常娥','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5b64\u72ec", "\u4e2d\u79cb", "\u5199\u4eba", "\u4e09\u5e74\u7ea7\u4e0b\u518c", "\u4e03\u8a00\u7edd\u53e5"]','雲母屏風燭影深，長河漸落曉星沈。',32,'全唐诗/poet.tang.29000.json','["雲母屏風燭影深，長河漸落曉星沈。", "常娥應悔偷靈藥，碧海青天夜夜心。"]'),
('6d8df2e0-709b-4e33-b5b2-4f577a9884f7','殘花','李商隱','唐','唐诗','tang','','[]','殘花啼露莫留春，尖髪誰非怨別人。',32,'全唐诗/poet.tang.29000.json','["殘花啼露莫留春，尖髪誰非怨別人。", "若但掩關勞燭夢，寶釵何日不生塵。"]'),
('da10a8c6-c0e0-47be-8f73-e4358888fd31','天津西望','李商隱','唐','唐诗','tang','','[]','虜馬崩騰忽一狂，翠華無日到東方。',32,'全唐诗/poet.tang.29000.json','["虜馬崩騰忽一狂，翠華無日到東方。", "天津西望腸真斷，滿眼秋波出苑牆。"]'),
('664c13c6-bfb4-4eb0-b477-f3bf50d78646','西亭','李商隱','唐','唐诗','tang','','[]','此夜西亭月正圓，疎簾相伴宿風煙。',32,'全唐诗/poet.tang.29000.json','["此夜西亭月正圓，疎簾相伴宿風煙。", "梧桐莫更翻清露，孤鶴從來不得眠。"]'),
('8449179c-8f81-4616-9183-02fc1a9fcac5','憶住一師','李商隱','唐','唐诗','tang','','["\u601d\u5ff5", "\u53cb\u4eba", "\u8ffd\u5fc6"]','無事經年別遠公，帝城鐘曉憶西峰。',32,'全唐诗/poet.tang.29000.json','["無事經年別遠公，帝城鐘曉憶西峰。", "爐煙消盡寒燈晦，童子開門雪滿松。"]'),
('95cd604d-e7f3-4837-9fd7-08773949bdff','昨夜','李商隱','唐','唐诗','tang','','[]','不辭鶗鴂妬年芳，但惜流塵暗燭房。',32,'全唐诗/poet.tang.29000.json','["不辭鶗鴂妬年芳，但惜流塵暗燭房。", "昨夜西池涼露滿，桂花吹斷月中香。"]'),
('318d7db7-d6c7-447f-b7af-b04eb5159332','海客','李商隱','唐','唐诗','tang','','[]','海客乘槎上紫氛，星娥罷織一相聞。',32,'全唐诗/poet.tang.29000.json','["海客乘槎上紫氛，星娥罷織一相聞。", "只應不憚牽牛妬，聊用支機石贈君。"]'),
('dd250eca-0b6e-42e2-a18d-1394c45cb365','初食笋呈座中','李商隱','唐','唐诗','tang','','[]','嫩籜香苞初出林，於陵論價重如金。',32,'全唐诗/poet.tang.29000.json','["嫩籜香苞初出林，於陵論價重如金。", "皇都陸海應無數，忍剪凌雲一寸心。"]'),
('2b51478e-5f70-4258-aff6-fd117b7222e9','早起','李商隱','唐','唐诗','tang','','[]','風露澹清晨，簾間獨起人。',24,'全唐诗/poet.tang.29000.json','["風露澹清晨，簾間獨起人。", "鸎花啼又笑，畢竟是誰春。"]'),
('5ad1e022-9f0f-4acd-b596-014978311869','寄蜀客','李商隱','唐','唐诗','tang','','[]','君到臨邛問酒壚，近來還有長卿無。',32,'全唐诗/poet.tang.29000.json','["君到臨邛問酒壚，近來還有長卿無。", "金徽却是無情物，不許文君憶故夫。"]'),
('53e2a812-b830-456f-a8f2-3d68fe0bcacb','行至金牛驛寄興元渤海尚書','李商隱','唐','唐诗','tang','','[]','樓上春雲水底天，五雲章色破巴牋。',64,'全唐诗/poet.tang.29000.json','["樓上春雲水底天，五雲章色破巴牋。", "諸生個個王恭柳，從事人人庾杲蓮。", "六曲屏風江雨急，九枝燈檠夜珠圓。", "深慙走馬金牛路，驟和陳王白玉篇。"]'),
('62c434cb-285c-4fd2-b355-aaec2d1e2f0f','深樹見一顆櫻桃尚在','李商隱','唐','唐诗','tang','','[]','高桃留晚實，尋得小庭南。',48,'全唐诗/poet.tang.29000.json','["高桃留晚實，尋得小庭南。", "矮墮綠雲髻，欹危紅玉簪。", "惜堪充鳳食，痛已被鸎含。", "越鳥誇香荔，齊名亦未甘。"]'),
('b8b6652a-5eed-414e-b49e-be67592f78b0','細雨','李商隱','唐','唐诗','tang','','[]','帷飄白玉堂，簟卷碧牙牀。',24,'全唐诗/poet.tang.29000.json','["帷飄白玉堂，簟卷碧牙牀。", "楚女當時意，蕭蕭髪彩涼。"]'),
('1dbf6f32-dc2e-4ed2-be7a-129231db405b','歌舞','李商隱','唐','唐诗','tang','','[]','遏雲歌響清，回雪舞腰輕。',24,'全唐诗/poet.tang.29000.json','["遏雲歌響清，回雪舞腰輕。", "只要君流眄，君傾國自傾。"]'),
('8e899f60-7985-4cd4-945d-c5fab85db25f','海上','李商隱','唐','唐诗','tang','','[]','石橋東望海連天，徐福空來不得仙。',32,'全唐诗/poet.tang.29000.json','["石橋東望海連天，徐福空來不得仙。", "直遣麻姑與搔背，可能留命待桑田。"]'),
('03acf765-3a7a-4a0e-89ce-b8ee06182b16','魏侯第東北樓堂郢叔言別聊用書所見成篇','李商隱','唐','唐诗','tang','','[]','暗樓連夜閣，不擬爲黃昏。',110,'全唐诗/poet.tang.29000.json','["暗樓連夜閣，不擬爲黃昏。", "未必斷別淚，何曾妨夢魂。", "疑穿花逶迤，漸近火溫黁。", "海底翻無水，仙家却有邨。", "鎖香金屈[戌]，殢酒玉崑崙。", "羽白風交扇，冰清月映盆。", "舊歡塵自積，新歲電猶奔。", "霞綺空留段，雲峰不帶根。", "念君千里舸，江草漏燈痕。"]'),
('7eff5e3c-acbf-4bf7-9971-ed0e3d095211','白雲夫舊居','李商隱','唐','唐诗','tang','','[]','平生誤識白雲夫，再到仙簷憶酒壚。',32,'全唐诗/poet.tang.29000.json','["平生誤識白雲夫，再到仙簷憶酒壚。", "牆外萬株人絕跡，夕陽惟照欲棲烏。"]'),
('428b63b2-9e22-4788-89c5-8bcb9d001fff','同學彭道士參寥','李商隱','唐','唐诗','tang','','[]','莫羨仙家有上真，仙家暫謫亦千春。',32,'全唐诗/poet.tang.29000.json','["莫羨仙家有上真，仙家暫謫亦千春。", "月中桂樹高多少，試問西河斫樹人。"]'),
('26145e3f-2165-4341-83a9-c6721d61d0f8','到秋','李商隱','唐','唐诗','tang','','[]','扇風淅瀝簟流離，萬里南風滯所思。',32,'全唐诗/poet.tang.29000.json','["扇風淅瀝簟流離，萬里南風滯所思。", "守到清秋還寂莫，葉丹苔碧閉門時。"]'),
('a353976b-e90f-48a4-a9a8-972304095488','華師','李商隱','唐','唐诗','tang','','[]','孤鶴不睡雲無心，衲衣筇杖來西林。',32,'全唐诗/poet.tang.29000.json','["孤鶴不睡雲無心，衲衣筇杖來西林。", "院門晝鎖回廊靜，秋日當堦柿葉陰。"]'),
('bd44f2a6-ef35-45d9-b487-c7c7821d2ed6','華嶽下題西王母廟','李商隱','唐','唐诗','tang','','["\u534e\u5c71"]','神仙有分豈關情，八馬虛隨落日行。',32,'全唐诗/poet.tang.29000.json','["神仙有分豈關情，八馬虛隨落日行。", "莫恨名姬中夜沒，君王猶自不長生。"]'),
('786f65e5-c374-411e-af4a-629176e4ce85','過華清內廐門','李商隱','唐','唐诗','tang','','[]','華清別館閉黃昏，碧草悠悠內廄門。',32,'全唐诗/poet.tang.29000.json','["華清別館閉黃昏，碧草悠悠內廄門。", "自是明時不巡幸，至今青海有龍孫。"]'),
('b18af06e-709e-4a98-9b49-6b2022daa42b','樂遊原','李商隱','唐','唐诗','tang','','["\u590f\u5929", "\u5199\u666f"]','萬樹鳴蟬隔岸虹，樂遊原上有西風。',32,'全唐诗/poet.tang.29000.json','["萬樹鳴蟬隔岸虹，樂遊原上有西風。", "羲和自趁虞泉宿，不放斜陽更向東。"]'),
('d83e75a1-db6e-4035-a4b6-cab288182996','贈荷花','李商隱','唐','唐诗','tang','','["\u8d5e\u7f8e", "\u8377\u82b1"]','世間花葉不相倫，花入金盆葉作塵。',50,'全唐诗/poet.tang.29000.json','["世間花葉不相倫，花入金盆葉作塵。", "惟有綠荷紅菡萏，卷舒開合任天真。", "此[花]此葉常相映，翠減紅衰愁殺人。"]'),
('50db36bc-3e3d-409d-97ab-3a665b7c4b04','丹丘','李商隱','唐','唐诗','tang','','[]','青女丁寧結夜霜，羲和辛苦送朝陽。',32,'全唐诗/poet.tang.29000.json','["青女丁寧結夜霜，羲和辛苦送朝陽。", "丹丘萬里無消息，幾對梧桐憶鳳皇。"]'),
('a857e97a-91d5-4ab2-9eed-da392c4a0de0','房君珊瑚散','李商隱','唐','唐诗','tang','','[]','不見姮娥影，清秋守月輪。',24,'全唐诗/poet.tang.29000.json','["不見姮娥影，清秋守月輪。", "月中閑杵臼，桂子擣成塵。"]'),
('8f1e710d-e244-44e0-9897-51886651078d','小桃園','李商隱','唐','唐诗','tang','','[]','竟日小桃園，休寒亦未暄。',48,'全唐诗/poet.tang.29000.json','["竟日小桃園，休寒亦未暄。", "坐鸎當酒重，送客出牆繁。", "啼久豔粉薄，舞多香雪翻。", "猶憐未圓月，先出照黃昏。"]'),
('8b6d1679-0aa5-4ab0-bbb6-3aeed5df53df','嘲櫻桃','李商隱','唐','唐诗','tang','','[]','朱實鳥含盡，青樓人未歸。',24,'全唐诗/poet.tang.29000.json','["朱實鳥含盡，青樓人未歸。", "南園無限樹，獨自葉如幃。"]'),
('43d6ba8c-0051-49f0-a139-db2d55d492ae','和張秀才落花有感','李商隱','唐','唐诗','tang','','[]','晴暖感餘芳，紅苞雜絳房。',48,'全唐诗/poet.tang.29000.json','["晴暖感餘芳，紅苞雜絳房。", "落時猶自舞，掃後更聞香。", "夢罷收羅薦，仙歸勅玉箱。", "回腸九回後，猶有剩回腸。"]'),
('298b8e0c-6c88-4042-a594-cca7a6a8ea4c','代越公房妓嘲徐公主','李商隱','唐','唐诗','tang','','[]','笑啼俱不敢，幾欲是吞聲。',36,'全唐诗/poet.tang.29000.json','["笑啼俱不敢，幾欲是吞聲。", "遽遣離琴怨，都由半鏡明。", "應防啼與笑，微露淺深情。"]'),
('7bb02dc6-51cb-42a4-be27-d5bc16c0618d','代貴公主','李商隱','唐','唐诗','tang','','[]','芳條得意紅，飄落忽西東。',36,'全唐诗/poet.tang.29000.json','["芳條得意紅，飄落忽西東。", "分逐春風去，風回得故叢。", "明朝金井露，始看憶春風。"]'),
('a9c3acb2-8f83-4491-b0fb-55f8554e19e0','鳳','李商隱','唐','唐诗','tang','','[]','萬里峰巒歸路迷，未判容彩借山雞。',32,'全唐诗/poet.tang.29000.json','["萬里峰巒歸路迷，未判容彩借山雞。", "新春定有將雛樂，阿閣華池兩處棲。"]'),
('7ef251d4-9925-4007-9e29-e85d06b1f4e1','昭肅皇帝挽歌辭三首 一','李商隱','唐','唐诗','tang','','[]','九縣懷雄武，三靈仰睿文。',48,'全唐诗/poet.tang.29000.json','["九縣懷雄武，三靈仰睿文。", "周王傳叔父，漢后重神君。", "玉律朝驚露，金莖夜切雲。", "笳簫淒欲斷，無復詠橫汾。"]'),
('e606d599-66b9-432a-a7a5-f630cad9da53','昭肅皇帝挽歌辭三首 二','李商隱','唐','唐诗','tang','','[]','玉塞驚宵柝，金橋罷舉烽。',48,'全唐诗/poet.tang.29000.json','["玉塞驚宵柝，金橋罷舉烽。", "始巢阿閣鳳，旋駕鼎湖龍。", "門咽通神鼓，樓凝警夜鐘。", "小臣觀吉從，猶誤欲東封。"]'),
('33ec0faf-e156-4829-aec6-cdf07eab727f','昭肅皇帝挽歌辭三首 三','李商隱','唐','唐诗','tang','','[]','莫驗昭華琯，虛傳甲帳神。',48,'全唐诗/poet.tang.29000.json','["莫驗昭華琯，虛傳甲帳神。", "海迷求藥使，雪隔獻桃人。", "桂寢青雲斷，松扉白露新。", "萬方同象鳥，舉慟滿秋塵。"]'),
('34e1cc78-213f-4ab0-85e5-6df3d35fddfc','梓州罷吟寄同舍','李商隱','唐','唐诗','tang','','[]','不揀花朝與雪朝，五年從事霍嫖姚。',64,'全唐诗/poet.tang.29000.json','["不揀花朝與雪朝，五年從事霍嫖姚。", "君緣接座交珠履，我爲分行近翠翹。", "楚雨含情皆有託，漳濱臥病竟無憀。", "長吟遠下燕臺去，惟有衣香染未銷。"]'),
('e006dfd3-40be-40ef-ba3b-552428931ae3','無題二首 一','李商隱','唐','唐诗','tang','','["\u601d\u5ff5", "\u4e03\u8a00\u5f8b\u8bd7", "\u5510\u8bd7\u4e09\u767e\u9996"]','鳳尾香羅薄幾重，碧文圓頂夜深縫。',48,'全唐诗/poet.tang.29000.json','["鳳尾香羅薄幾重，碧文圓頂夜深縫。", "扇裁月魄羞難掩，車走雷聲語未通。", "曾是寂寥金燼暗，斷無消息石榴紅。"]'),
('b6475dea-1d69-4f0d-b98a-39393f47741e','無題二首 二','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u4e03\u8a00\u5f8b\u8bd7", "\u6292\u60c5", "\u7231\u60c5"]','重帷深下莫愁堂，臥後清宵細細長。',64,'全唐诗/poet.tang.29000.json','["重帷深下莫愁堂，臥後清宵細細長。", "神女生涯原是夢，小姑居處本無郎。", "風波不信菱枝弱，月露誰教桂葉香。", "直道相思了無益，未妨惆悵是清狂。"]'),
('dd24ccbd-680c-470d-afda-63798396e338','病中早訪招國李十將軍遇挈家遊曲江','李商隱','唐','唐诗','tang','','[]','十頃平波溢岸清，病來惟夢此中行。',32,'全唐诗/poet.tang.29000.json','["十頃平波溢岸清，病來惟夢此中行。", "相如未是真消渴，猶放沱江過錦城。"]'),
('3256b035-3b67-4be9-9b73-3997f6ffc646','昨日','李商隱','唐','唐诗','tang','','[]','昨日紫姑神去也，今朝青鳥使來賒。',64,'全唐诗/poet.tang.29000.json','["昨日紫姑神去也，今朝青鳥使來賒。", "未容言語還分散，少得團圓足怨嗟。", "二八月輪蟾影破，十三絃柱雁行斜。", "平明鐘後更何事，笑倚牆邊梅樹花。"]'),
('fbfab70f-3306-41d6-bacb-3616986f084b','櫻桃花下','李商隱','唐','唐诗','tang','','[]','流鸎舞蝶兩相欺，不取花芳正結時。',32,'全唐诗/poet.tang.29000.json','["流鸎舞蝶兩相欺，不取花芳正結時。", "他日未開今日謝，嘉辰長短是參差。"]'),
('810878a7-9824-47f8-a5a6-8d3a28b1474d','故驛迎弔故桂府常侍有感','李商隱','唐','唐诗','tang','','[]','饑烏翻樹晚雞啼，泣過秋原沒馬泥。',32,'全唐诗/poet.tang.29000.json','["饑烏翻樹晚雞啼，泣過秋原沒馬泥。", "二紀征南恩與舊，此時丹旐玉山西。"]'),
('39482792-8182-4fb8-a324-bfd89fa460c1','槿花','李商隱','唐','唐诗','tang','','[]','風露淒淒秋景繁，可憐榮落在朝昏。',32,'全唐诗/poet.tang.29000.json','["風露淒淒秋景繁，可憐榮落在朝昏。", "未央宮裏三千女，但保紅顏莫保恩。"]'),
('e053b61f-d055-4484-8a65-7d977480aed5','暮秋獨遊曲江','李商隱','唐','唐诗','tang','','["\u601d\u5ff5", "\u7231\u60c5"]','荷葉生時春恨生，荷葉枯時秋恨成。',32,'全唐诗/poet.tang.29000.json','["荷葉生時春恨生，荷葉枯時秋恨成。", "深知身在情長在，悵望江頭江水聲。"]'),
('d5824360-df41-481d-bf99-b65bb35d8fbf','任弘農尉獻州刺史乞假還京','李商隱','唐','唐诗','tang','','[]','黃昏封印點刑徒，愧負荆山入座隅。',32,'全唐诗/poet.tang.29000.json','["黃昏封印點刑徒，愧負荆山入座隅。", "却羨卞和雙刖足，一生無復沒階趨。"]'),
('42b1b526-1d8e-4373-a990-af650dc8583e','贈句芒神','李商隱','唐','唐诗','tang','','[]','佳期不定春期賒，春物夭閼興咨嗟。',32,'全唐诗/poet.tang.29000.json','["佳期不定春期賒，春物夭閼興咨嗟。", "願得句芒索青女，不教容易損年華。"]'),
('8d395e7b-beda-45b7-9d58-ecb61186c80e','無愁果有愁曲北齊歌','李商隱','唐','唐诗','tang','','[]','東有青龍西白虎，中含福星包世度。',112,'全唐诗/poet.tang.29000.json','["東有青龍西白虎，中含福星包世度。", "玉壺渭水笑清潭，鑿天不到牽牛處。", "騏驎踏雲天馬獰，牛山撼碎珊瑚聲。", "秋娥點滴不成淚，十二玉樓無故釘。", "推煙唾月拋千里，十番紅桐一行死。", "白楊別屋鬼迷人，空留暗記如蠶紙。", "日暮向風牽短絲，血凝血散今誰是。"]'),
('ad19569a-b234-4db2-8c9f-4de50f36872c','房中曲','李商隱','唐','唐诗','tang','','[]','薔薇泣幽素，翠帶花錢小。',96,'全唐诗/poet.tang.29000.json','["薔薇泣幽素，翠帶花錢小。", "嬌郎癡若雲，抱日西簾曉。", "枕是龍宮石，割得秋波色。", "玉簟失柔膚，但見蒙羅碧。", "憶得前年春，未語含悲辛。", "歸來已不見，錦瑟長於人。", "今日澗底松，明日山頭檗。", "愁到天池翻，相看不相識。"]'),
('dffc9e3f-84ce-452d-bdd7-1b1d14860240','齊梁晴雲','李商隱','唐','唐诗','tang','','[]','緩逐煙波起，如妬柳緜飄。',48,'全唐诗/poet.tang.29000.json','["緩逐煙波起，如妬柳緜飄。", "故臨飛閣度，欲入回陂銷。", "縈歌憐畫扇，敞景弄柔條。", "更奈天南位，牛渚宿殘宵。"]'),
('610c6aa4-17ed-40ca-a064-2b0c3af7852e','效徐陵體贈更衣','李商隱','唐','唐诗','tang','','[]','密帳真珠絡，溫幃翡翠裝。',48,'全唐诗/poet.tang.29000.json','["密帳真珠絡，溫幃翡翠裝。", "楚腰知便寵，宮眉正鬬強。", "結帶懸梔子，繡領刺鴛鴦。", "輕寒衣省夜，金斗熨沉香。"]'),
('1604b1c0-e643-4bc5-8c4c-c32caee588f0','又效江南曲','李商隱','唐','唐诗','tang','','[]','郎船安兩槳，儂舸動雙橈。',48,'全唐诗/poet.tang.29000.json','["郎船安兩槳，儂舸動雙橈。", "掃黛開宮額，裁裙約楚腰。", "乖期方積思，臨酒欲拌嬌。", "莫以採菱唱，欲羨秦臺簫。"]'),
('8751c49d-ce6d-4c8a-8966-8a6d74f665ba','月夜重寄宋華陽姊妹','李商隱','唐','唐诗','tang','','[]','偷桃竊藥事難兼，十二城中鎖彩蟾。',32,'全唐诗/poet.tang.29000.json','["偷桃竊藥事難兼，十二城中鎖彩蟾。", "應共三英同夜賞，玉樓仍是水精簾。"]'),
('242af81a-f8c3-4ca3-ac1e-a91074d26149','訪人不遇留別館','李商隱','唐','唐诗','tang','','[]','卿卿不惜鎖窗春，去作長楸走馬身。',32,'全唐诗/poet.tang.29000.json','["卿卿不惜鎖窗春，去作長楸走馬身。", "閑倚繡簾吹柳絮，日高深院斷無人。"]'),
('7bc1e5de-bfda-464b-b942-81eaa8e33225','雨中長樂水館送趙十五滂不及','李商隱','唐','唐诗','tang','','[]','碧雲東去雨雲西，苑路高高驛路低。',32,'全唐诗/poet.tang.29000.json','["碧雲東去雨雲西，苑路高高驛路低。", "秋水綠蕪終盡分，夫君太騁錦障泥。"]'),
('958f0059-3cec-4585-8523-39220cf764d8','汴上送李郢之蘇州','李商隱','唐','唐诗','tang','','[]','人高詩苦滯夷門，萬里梁王有舊園。',64,'全唐诗/poet.tang.29000.json','["人高詩苦滯夷門，萬里梁王有舊園。", "煙幌自應憐白紵，月樓誰伴詠黃昏。", "露桃塗頰依苔井，風柳誇腰住水村。", "蘇小小墳今在否，紫蘭香徑與招魂。"]'),
('20f90857-83a9-4807-92e2-dd6f73dea0c9','贈鄭讜處士','李商隱','唐','唐诗','tang','','[]','浪跡江湖白髮新，浮雲一片是吾身。',64,'全唐诗/poet.tang.29000.json','["浪跡江湖白髮新，浮雲一片是吾身。", "寒歸山觀隨碁局，暖入汀洲逐釣輪。", "越桂留烹張翰鱠，蜀薑供煮陸機蓴。", "相逢一笑憐疎放，他日扁舟有故人。"]'),
('e9e8d65f-3b6b-4174-bde9-d262676b4051','復至裴明府所居','李商隱','唐','唐诗','tang','','[]','伊人卜築自幽深，桂巷杉籬不可尋。',64,'全唐诗/poet.tang.29000.json','["伊人卜築自幽深，桂巷杉籬不可尋。", "柱上雕蟲對書字，槽中瘦馬仰聽琴。", "求之流輩豈易得，行矣關山方獨吟。", "賒取松醪一斗酒，與君相伴灑煩襟。"]'),
('1edf0a20-87ff-4ca0-851f-abffeb1972d1','覽古','李商隱','唐','唐诗','tang','','[]','莫恃金湯忽太平，草間霜露古今情。',64,'全唐诗/poet.tang.29000.json','["莫恃金湯忽太平，草間霜露古今情。", "空糊頳壞真何益，欲舉黃旗竟未成。", "長樂瓦飛隨水逝，景陽鐘墮失天明。", "回頭一弔箕山客，始信逃堯不爲名。"]'),
('d1e0fde6-4599-47d4-865e-cb62e86a28d0','子初郊墅','李商隱','唐','唐诗','tang','','[]','看山對酒君思我，聽鼓離城我訪君。',64,'全唐诗/poet.tang.29000.json','["看山對酒君思我，聽鼓離城我訪君。", "臘雪已添牆下水，齋鐘不散檻前雲。", "陰移竹柏濃還淡，歌雜漁樵斷更聞。", "亦擬村南買煙舍，子孫相約事耕耘。"]'),
('57fd6525-b368-41f5-b625-c901e00202b3','漢南書事','李商隱','唐','唐诗','tang','','[]','西師萬衆幾時回，哀痛天書近已裁。',64,'全唐诗/poet.tang.29000.json','["西師萬衆幾時回，哀痛天書近已裁。", "文吏何曾重刀筆，將軍猶自舞輪臺。", "幾時拓土成王道，從古窮兵是禍胎。", "陛下好生千萬壽，玉樓長御白雲杯。"]'),
('6c93c1b3-316c-4b0f-acf6-5a1613104c32','當句有對','李商隱','唐','唐诗','tang','','[]','密邇平陽接上蘭，秦樓鴛瓦漢宮盤。',64,'全唐诗/poet.tang.29000.json','["密邇平陽接上蘭，秦樓鴛瓦漢宮盤。", "池光不定花光亂，日氣初涵露氣乾。", "但覺游蜂饒舞蝶，豈知孤鳳憶離鸞。", "三星自轉三山遠，紫府程遙碧落寬。"]'),
('6d7f3b9e-084e-4f78-af9c-68a34ecf54eb','井絡','李商隱','唐','唐诗','tang','','[]','井絡天彭一掌中，漫誇天設劒爲峰。',64,'全唐诗/poet.tang.29000.json','["井絡天彭一掌中，漫誇天設劒爲峰。", "陣圖東聚燕江石，邊柝西懸雪嶺松。", "堪歎故君成杜宇，可能先主是真龍。", "將來爲報姦雄輩，莫向金牛訪舊蹤。"]'),
('b1f915d3-7491-4306-b37a-f6812a654f5e','寫意','李商隱','唐','唐诗','tang','','[]','燕雁迢迢隔上林，高秋望斷正長吟。',64,'全唐诗/poet.tang.29000.json','["燕雁迢迢隔上林，高秋望斷正長吟。", "人間路有潼江險，天外山惟玉壘深。", "日向花間留返照，雲從城上結層陰。", "三年已制思鄉淚，更入新年恐不禁。"]'),
('87d23413-0dbe-4045-9c94-21817b6b4abe','隨師東','李商隱','唐','唐诗','tang','','[]','東征日調萬黃金，幾竭中原買鬬心。',64,'全唐诗/poet.tang.29000.json','["東征日調萬黃金，幾竭中原買鬬心。", "軍令未聞誅馬謖，捷書惟是報孫歆。", "但須鸑鷟巢阿閣，豈假鴟鴞在泮林。", "可惜前朝玄菟郡，積骸成莽陣雲深。"]'),
('f5a9da1b-1b08-4067-9030-b65756d160dc','宋玉','李商隱','唐','唐诗','tang','','[]','何事荆臺百萬家，惟教宋玉擅才華。',64,'全唐诗/poet.tang.29000.json','["何事荆臺百萬家，惟教宋玉擅才華。", "楚辭已不饒唐勒，風賦何曾讓景差。", "落日渚宮供觀閣，開年雲夢送煙花。", "可憐庾信尋荒徑，猶得三朝託後車。"]'),
('93f08235-2abe-4392-b905-ccc95276fa30','韓同年新居餞韓西迎家室戲贈','李商隱','唐','唐诗','tang','','[]','籍籍征西萬戶侯，新緣貴婿起朱樓。',64,'全唐诗/poet.tang.29000.json','["籍籍征西萬戶侯，新緣貴婿起朱樓。", "一名我漫居先甲，千騎君翻在上頭。", "雲路招邀迴綵鳳，天河迢遰笑牽牛。", "南朝禁臠無人近，瘦盡瓊枝詠四愁。"]'),
('1b25b3c0-1450-42e9-84b0-eb2fbac2bfd8','奉和太原公送前楊秀才戴兼招楊正字戎','李商隱','唐','唐诗','tang','','[]','潼關地接古弘農，萬里高飛雁與鴻。',64,'全唐诗/poet.tang.29000.json','["潼關地接古弘農，萬里高飛雁與鴻。", "桂樹一枝當白日，芸香三代繼清風。", "仙舟尚惜乖雙美，綵服何由得盡同。", "誰憚士龍多笑疾，美髭終類晉司空。"]'),
('62a65e3b-dc73-4c9f-86c1-6a34050f0039','池邊','李商隱','唐','唐诗','tang','','[]','玉管葭灰細細吹，流鸎上下燕參差。',32,'全唐诗/poet.tang.29000.json','["玉管葭灰細細吹，流鸎上下燕參差。", "日西千遶池邊樹，憶把枯條撼雪時。"]'),
('02456f60-6ab5-4de8-b9ed-f7519818f0ca','賈生','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u6258\u53e4\u8bbd\u4eca", "\u4e03\u8a00\u7edd\u53e5", "\u6000\u624d\u4e0d\u9047"]','宣室求賢訪逐臣，賈生才調更無倫。',32,'全唐诗/poet.tang.29000.json','["宣室求賢訪逐臣，賈生才調更無倫。", "可憐夜半虛前席，不問蒼生問鬼神。"]'),
('72ac253a-605a-455a-8ef1-4db76f263e69','送王十三校書分司','李商隱','唐','唐诗','tang','','[]','多少分曹掌秘文，洛陽花雪夢隨君。',32,'全唐诗/poet.tang.29000.json','["多少分曹掌秘文，洛陽花雪夢隨君。", "定知何遜緣聯句，每到城東憶范雲。"]'),
('75c05119-28d2-4647-a58f-e2dda460d5de','寄惱韓同年二首 一','李商隱','唐','唐诗','tang','','[]','簾外辛夷定已開，開時莫放豔陽回。',32,'全唐诗/poet.tang.29000.json','["簾外辛夷定已開，開時莫放豔陽回。", "年華若到經風雨，便是胡僧話劫灰。"]'),
('61659953-ea54-4c63-8b9d-4a19d05a8b30','寄惱韓同年二首 二','李商隱','唐','唐诗','tang','','[]','龍山晴雪鳳樓霞，洞裏迷人有幾家。',32,'全唐诗/poet.tang.29000.json','["龍山晴雪鳳樓霞，洞裏迷人有幾家。", "我爲傷春心自醉，不勞君勸石榴花。"]'),
('f602b4b7-b7cf-4b67-a1a9-12282c8072ad','謁山','李商隱','唐','唐诗','tang','','["\u6292\u60c5", "\u767b\u9ad8", "\u5199\u666f"]','從來繫日乏長繩，水去雲回恨不勝。',32,'全唐诗/poet.tang.29000.json','["從來繫日乏長繩，水去雲回恨不勝。", "欲就麻姑買滄海，一杯春露冷如冰。"]'),
('4a49bc13-8939-4d2d-ac7e-f3fb0d24918a','鈞天','李商隱','唐','唐诗','tang','','[]','上帝鈞天會衆靈，昔人因夢到青冥。',32,'全唐诗/poet.tang.29000.json','["上帝鈞天會衆靈，昔人因夢到青冥。", "伶倫吹裂孤生竹，却爲知音不得聽。"]'),
('d0c9f158-8e05-4056-96f5-ca699b182651','失猿','李商隱','唐','唐诗','tang','','[]','祝融南去萬重雲，清嘯無因更一聞。',32,'全唐诗/poet.tang.29000.json','["祝融南去萬重雲，清嘯無因更一聞。", "莫遣碧江通箭道，不教腸斷憶同羣。"]'),
('b4e4b854-a0a3-4b95-a45b-eb2c3b9c7742','戲題友人壁','李商隱','唐','唐诗','tang','','[]','花逕逶迤柳巷深，小闌亭舞囀春禽。',32,'全唐诗/poet.tang.29000.json','["花逕逶迤柳巷深，小闌亭舞囀春禽。", "相如解作長門賦，却用文君取酒金。"]'),
('4981ac5a-eb1d-4f53-92f2-b917c96e1cb1','假日','李商隱','唐','唐诗','tang','','[]','素琴絃斷酒缾空，倚坐欹眠日已中。',32,'全唐诗/poet.tang.29000.json','["素琴絃斷酒缾空，倚坐欹眠日已中。", "誰向劉靈天幕內，更當陶令北窻風。"]'),
('4fc78fe8-b466-4452-9010-0ee4a336c0a7','寄遠','李商隱','唐','唐诗','tang','','[]','姮娥擣藥無時已，玉女投壺未肯休。',32,'全唐诗/poet.tang.29000.json','["姮娥擣藥無時已，玉女投壺未肯休。", "何日桑田俱變了，不教伊水向東流。"]'),
('4ab77712-fd4f-49bb-9448-d3757930dba6','王昭君','李商隱','唐','唐诗','tang','','[]','毛延壽畫欲通神，忍爲黃金不顧人。',32,'全唐诗/poet.tang.29000.json','["毛延壽畫欲通神，忍爲黃金不顧人。", "馬上琵琶行萬里，漢宮長有隔生春。"]'),
('bc57ab42-df51-48ce-ae62-ed2d59fe0a23','舊將軍','李商隱','唐','唐诗','tang','','[]','雲臺高議正紛紛，誰定當時蕩寇勳。',32,'全唐诗/poet.tang.29000.json','["雲臺高議正紛紛，誰定當時蕩寇勳。", "日暮灞陵原上獵，李將軍是故將軍。"]'),
('ff3c01f2-a898-43e6-9753-c1aef10c9934','曼倩辭','李商隱','唐','唐诗','tang','','[]','十八年來墮世間，瑤池歸夢碧桃閑。',32,'全唐诗/poet.tang.29000.json','["十八年來墮世間，瑤池歸夢碧桃閑。", "如何漢殿穿鍼夜，又向窻中覷阿環。"]'),
('cbc1659f-763b-4030-a6ab-a24103e457a7','所居','李商隱','唐','唐诗','tang','','[]','窻下尋書細，溪邊坐石平。',48,'全唐诗/poet.tang.29000.json','["窻下尋書細，溪邊坐石平。", "水風醒酒病，霜日曝衣輕。", "雞黍隨人設，蒲漁得地生。", "前賢無不謂，容易即遺名。"]'),
('b22dca88-d21b-42ee-966a-d0cad2f1ce16','高松','李商隱','唐','唐诗','tang','','[]','高松出衆木，伴我向天涯。',48,'全唐诗/poet.tang.29000.json','["高松出衆木，伴我向天涯。", "客散初晴候，僧來不語時。", "有風傳雅韻，無雪試幽姿。", "上藥終相待，他年訪伏龜。"]'),
('6effad7a-4035-4848-b239-229c70901a62','訪秋','李商隱','唐','唐诗','tang','','["\u6292\u60c5", "\u79cb\u5929"]','酒薄吹還醒，樓危望已窮。',48,'全唐诗/poet.tang.29000.json','["酒薄吹還醒，樓危望已窮。", "江臯當落日，帆席見歸風。", "煙帶龍潭白，霞分鳥道紅。", "殷勤報秋意，只是有丹楓。"]'),
('c97083d3-0fd7-4cb1-b5bb-cb6260ce07fe','昭州','李商隱','唐','唐诗','tang','','[]','桂水春猶早，昭川日正西。',48,'全唐诗/poet.tang.29000.json','["桂水春猶早，昭川日正西。", "虎當官道鬬，猿上驛樓啼。", "繩爛金沙井，松乾乳洞梯。", "鄉音殊可駭，仍有醉如泥。"]'),
('e77a57ba-1bb8-48d5-b68c-34b51c175f6e','哭劉司戶蕡','李商隱','唐','唐诗','tang','','[]','路有論冤謫，言皆在中興。',48,'全唐诗/poet.tang.29000.json','["路有論冤謫，言皆在中興。", "空聞遷賈誼，不待相孫弘。", "江闊惟回首，天高但撫膺。", "去年相送地，春雪滿黃陵。"]'),
('b03916cf-f4b4-4144-9ba8-450f028795ae','裴明府居止','李商隱','唐','唐诗','tang','','[]','愛君茅屋下，向晚水溶溶。',48,'全唐诗/poet.tang.29000.json','["愛君茅屋下，向晚水溶溶。", "試墨書新竹，張琴和古松。", "坐來聞好鳥，歸去度疎鐘。", "明日還相見，橋南貰酒醲。"]'),
('756653f2-048c-4463-805f-739b73681958','陸發荆南始至商洛','李商隱','唐','唐诗','tang','','[]','昔去真無奈，今還豈自知。',48,'全唐诗/poet.tang.29000.json','["昔去真無奈，今還豈自知。", "青辭木奴橘，紫見地仙芝。", "四海秋風闊，千嵓暮景遲。", "向來憂際會，猶有五湖期。"]'),
('ac3757d4-033b-4c69-baf8-8558055d42d4','陳後宮','李商隱','唐','唐诗','tang','','[]','玄武開新苑，龍舟讌幸頻。',48,'全唐诗/poet.tang.29000.json','["玄武開新苑，龍舟讌幸頻。", "渚蓮參法駕，沙鳥犯句陳。", "壽獻金莖露，歌翻玉樹塵。", "夜來江令醉，別詔宿臨春。"]'),
('83007a15-cc6d-4eb4-8758-0d1a2739ce77','樂遊原','李商隱','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f", "\u6292\u60c5"]','春夢亂不記，春原登已重。',48,'全唐诗/poet.tang.29000.json','["春夢亂不記，春原登已重。", "青門弄煙柳，紫閣舞雲松。", "拂硯輕冰散，開尊綠酎濃。", "無悰託詩遣，吟罷更無悰。"]'),
('3fef80d2-5d8a-4a3d-b39d-98e162b7a665','贈子直花下','李商隱','唐','唐诗','tang','','[]','池光忽隱牆，花氣亂侵房。',48,'全唐诗/poet.tang.29000.json','["池光忽隱牆，花氣亂侵房。", "屏緣蝶留粉，窗油蜂印黃。", "官書推小吏，侍史從清郎。", "竝馬更吟去，尋思有底忙。"]'),
('8e443c36-3168-4728-bc0d-f80377f08b9e','小園獨酌','李商隱','唐','唐诗','tang','','[]','柳帶誰能結，花房未肯開。',48,'全唐诗/poet.tang.29000.json','["柳帶誰能結，花房未肯開。", "空餘雙蝶舞，竟絕一人來。", "半展龍鬚席，輕斟瑪瑙杯。", "年年春不定，虛信歲前梅。"]'),
('c2c7a332-9a19-4939-a38a-d1f1ffdd9aac','思歸','李商隱','唐','唐诗','tang','','[]','固有樓堪依，能無酒可傾。',48,'全唐诗/poet.tang.29000.json','["固有樓堪依，能無酒可傾。", "嶺雲春沮洳，江月夜晴明。", "魚亂書何託，猿哀夢易驚。", "舊居連上苑，時節正遷鸎。"]'),
('1eec5cf1-4b4d-4419-944e-5b33f272d56d','獻寄舊府開封公','李商隱','唐','唐诗','tang','','[]','幕府三年遠，春秋一字襃。',48,'全唐诗/poet.tang.29000.json','["幕府三年遠，春秋一字襃。", "書論秦逐客，賦續楚離騷。", "地理南溟闊，天文北極高。", "酬恩撫身世，未覺勝鴻毛。"]'),
('02ffd0e1-e85d-4100-b89f-7b077bfeb497','向晚','李商隱','唐','唐诗','tang','','[]','當風橫去幰，臨水卷空帷。',48,'全唐诗/poet.tang.29000.json','["當風橫去幰，臨水卷空帷。", "北土鞦韆罷，南朝祓禊歸。", "花情羞脈脈，柳意悵微微。", "莫歎佳期晚，佳期自古稀。"]'),
('ae4aa20e-0532-4940-beee-163f08a0a8ad','春游','李商隱','唐','唐诗','tang','','[]','橋峻斑騅疾，川長白鳥高。',48,'全唐诗/poet.tang.29000.json','["橋峻斑騅疾，川長白鳥高。", "煙輕惟潤柳，風濫欲吹桃。", "徙倚三層閣，摩挲七寶刀。", "庾郎年最少，青草妬春袍。"]'),
('5e8cbbf6-3284-48fd-a120-27024e74a442','離席','李商隱','唐','唐诗','tang','','[]','出宿金尊掩，從公玉帳新。',48,'全唐诗/poet.tang.29000.json','["出宿金尊掩，從公玉帳新。", "依依向餘照，遠遠隔芳塵。", "細草翻驚雁，殘花伴醉人。", "楊朱不用勸，只是更霑巾。"]'),
('0a7f9be0-8e61-47a2-9078-e3f33966f797','俳諧','李商隱','唐','唐诗','tang','','[]','短顧何由遂，遲光且莫驚。',48,'全唐诗/poet.tang.29000.json','["短顧何由遂，遲光且莫驚。", "鸎能歌子夜，蝶解舞宮城。", "柳訝眉雙淺，桃猜粉太輕。", "年華有情狀，吾豈怯平生。"]'),
('5262b973-36ff-4bae-979c-8e674b705893','細雨','李商隱','唐','唐诗','tang','','[]','蕭灑傍回汀，依微過短亭。',48,'全唐诗/poet.tang.29000.json','["蕭灑傍回汀，依微過短亭。", "氣涼先動竹，點細未開萍。", "稍促高高燕，微疎的的螢。", "故園煙草色，仍近五門青。"]'),
('3ed4190b-f684-45d2-a1dd-6111536f27b6','商於新開路','李商隱','唐','唐诗','tang','','[]','六百商於路，崎嶇古共聞。',48,'全唐诗/poet.tang.29000.json','["六百商於路，崎嶇古共聞。", "蜂房春欲暮，虎穽日初曛。", "路向泉間辨，人從樹杪分。", "更誰開捷徑，速擬上青雲。"]'),
('ffc746f8-fc07-4cc8-a60f-a70d2d13cb3f','題鄭大有隱居','李商隱','唐','唐诗','tang','','[]','結構何峰是，喧閑此地分。',48,'全唐诗/poet.tang.29000.json','["結構何峰是，喧閑此地分。", "石梁高瀉月，樵路細侵雲。", "堰臥蛟螭室，希夷鳥獸羣。", "近知西嶺上，玉管有時聞。"]'),
('fc6082d1-7aff-4ace-a1bb-602972a4eb03','夜飲','李商隱','唐','唐诗','tang','','[]','卜夜容衰鬢，開筵屬異方。',48,'全唐诗/poet.tang.29000.json','["卜夜容衰鬢，開筵屬異方。", "燭分歌扇淚，雨送酒船香。", "江海三年客，乾坤百戰場。", "誰能辭酩酊，淹臥劇清漳。"]'),
('39cee781-3835-415e-a59d-87eadbc8e5ca','江上','李商隱','唐','唐诗','tang','','[]','萬里風來地，清江北望樓。',48,'全唐诗/poet.tang.29000.json','["萬里風來地，清江北望樓。", "雲通梁苑路，月帶楚城秋。", "刺字從漫滅，歸途尚阻脩。", "前程更煙水，吾道豈淹留。"]'),
('15c6cbc9-753a-4f09-86bf-4fe2d8bb1fee','涼思','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6101\u601d", "\u4e94\u8a00\u5f8b\u8bd7"]','客去波平檻，蟬休露滿枝。',48,'全唐诗/poet.tang.29000.json','["客去波平檻，蟬休露滿枝。", "永懷當此節，倚立自移時。", "北斗兼春遠，南陵寓使遲。", "天涯占夢數，疑誤有新知。"]'),
('96183765-aba5-4f09-b0e8-ffc9233246f4','鷥鳳','李商隱','唐','唐诗','tang','','[]','舊鏡鸞何處，衰桐鳳不棲。',48,'全唐诗/poet.tang.29000.json','["舊鏡鸞何處，衰桐鳳不棲。", "金錢饒孔雀，錦段落山雞。", "王子調清管，天人降紫泥。", "豈無雲路分，相望不應迷。"]'),
('68582fdd-45c9-42d9-b969-87b3c5ede889','李衛公','李商隱','唐','唐诗','tang','','[]','絳紗弟子音塵絕，鸞鏡佳人舊會稀。',32,'全唐诗/poet.tang.29000.json','["絳紗弟子音塵絕，鸞鏡佳人舊會稀。", "今日致身歌舞地，木棉花暖鷓鴣飛。"]'),
('5e2a64e8-e5e6-4a54-873f-6b5bfe8f5a1d','韋蟾','李商隱','唐','唐诗','tang','','[]','謝家離別正淒涼，少傅臨岐賭佩囊。',32,'全唐诗/poet.tang.29000.json','["謝家離別正淒涼，少傅臨岐賭佩囊。", "却憶短亭回首處，夜來煙雨滿池塘。"]'),
('18f90e38-6104-487f-bcc8-8356a1acd3d4','自貺','李商隱','唐','唐诗','tang','','[]','陶令棄官後，仰眠書屋中。',24,'全唐诗/poet.tang.29000.json','["陶令棄官後，仰眠書屋中。", "誰將五斗米，擬換北窗風。"]'),
('c038d184-4ba3-4b7c-a849-31d2c1b9030e','蝶','李商隱','唐','唐诗','tang','','[]','孤蝶小徘徊，翩翾粉翅開。',24,'全唐诗/poet.tang.29000.json','["孤蝶小徘徊，翩翾粉翅開。", "併應傷皎潔，頻近雪中來。"]'),
('00ec5d09-642e-419e-82d3-5a4b16c75cbf','夜意','李商隱','唐','唐诗','tang','','[]','簾垂幕半卷，枕冷被仍香。',24,'全唐诗/poet.tang.29000.json','["簾垂幕半卷，枕冷被仍香。", "如何爲相憶，魂夢過瀟湘。"]'),
('b0f81bac-a6f7-4c5f-9c15-7277ce8e2cd7','因書','李商隱','唐','唐诗','tang','','[]','絕徼南通棧，孤城北枕江。',48,'全唐诗/poet.tang.29000.json','["絕徼南通棧，孤城北枕江。", "猿聲連月檻，鳥影落天窗。", "海石分碁子，郫筒當酒缸。", "生歸話辛苦，別夜對凝釭。"]'),
('e71f2dc7-76b6-49e0-999c-d76dac5ba0aa','奉寄安國大師兼簡子蒙','李商隱','唐','唐诗','tang','','[]','憶奉蓮花座，兼聞貝葉經。',48,'全唐诗/poet.tang.29000.json','["憶奉蓮花座，兼聞貝葉經。", "巖光分蠟屐，澗響入銅缾。", "日下徒推鶴，天涯正對螢。", "魚山羨曹植，眷屬有文星。"]'),
('4e6afeba-b99d-42d0-b2a7-c1b8fe87adba','閑遊','李商隱','唐','唐诗','tang','','[]','危亭題竹粉，曲沼嗅荷花。',48,'全唐诗/poet.tang.29000.json','["危亭題竹粉，曲沼嗅荷花。", "數日同攜酒，平明不在家。", "尋幽殊未極，得句總堪誇。", "強下西樓去，西樓倚暮霞。"]'),
('2188f3d7-5dfb-45fd-8e71-1e97b1263cbd','縣中惱飲席','李商隱','唐','唐诗','tang','','[]','晚醉題詩贈物華，罷吟還醉忘歸家。',32,'全唐诗/poet.tang.29000.json','["晚醉題詩贈物華，罷吟還醉忘歸家。", "若無江氏五色筆，爭奈河陽一縣花。"]'),
('ed639115-f3ed-40fd-8a15-fdb08cd77934','題李上謩壁','李商隱','唐','唐诗','tang','','[]','舊著思玄賦，新編雜擬詩。',48,'全唐诗/poet.tang.29000.json','["舊著思玄賦，新編雜擬詩。", "江庭猶近別，山舍得幽期。", "嫩割周顒韭，肥烹鮑照葵。", "飽聞南燭酒，仍及撥醅時。"]'),
('f32f662b-4ce2-4481-a1b7-53cfbd41b2cf','江村題壁','李商隱','唐','唐诗','tang','','[]','沙岸竹森森，維艄聽越禽。',48,'全唐诗/poet.tang.29000.json','["沙岸竹森森，維艄聽越禽。", "數家同老壽，一徑自陰深。", "喜客嘗留橘，應官說採金。", "傾壺真得地，愛日靜霜砧。"]'),
('1aa19603-f858-4fa7-832a-75f76c24e192','即日','李商隱','唐','唐诗','tang','','[]','桂林聞舊說，曾不異炎方。',48,'全唐诗/poet.tang.29000.json','["桂林聞舊說，曾不異炎方。", "山響匡牀語，花飄度臘香。", "幾時逢雁足，著處斷猿腸。", "獨撫青青桂，臨城憶雪霜。"]'),
('e6ae6da2-783a-4da3-9012-3cb96ff93fca','漫成五章 一','李商隱','唐','唐诗','tang','','[]','沈宋裁辭矜變律，王楊落筆得良朋。',32,'全唐诗/poet.tang.29000.json','["沈宋裁辭矜變律，王楊落筆得良朋。", "當時自謂宗師妙，今日惟觀對屬能。"]'),
('ac7c473c-01d3-46fc-829c-fd79b864b0bc','漫成五章 二','李商隱','唐','唐诗','tang','','[]','李杜操持事略齊，三才萬象共端倪。',32,'全唐诗/poet.tang.29000.json','["李杜操持事略齊，三才萬象共端倪。", "集仙殿與金鑾殿，可是蒼蠅惑曙雞。"]'),
('735c36c7-50b7-4d55-b77f-54cf2bffd19a','漫成五章 三','李商隱','唐','唐诗','tang','','[]','生兒古有孫征虜，嫁女今無王右軍。',32,'全唐诗/poet.tang.29000.json','["生兒古有孫征虜，嫁女今無王右軍。", "借問琴書終一世，何如旗蓋仰三分。"]'),
('02ab34de-208b-42bd-8432-116a9fcc28a6','漫成五章 四','李商隱','唐','唐诗','tang','','[]','代北偏師銜使節，關中裨將建行臺。',32,'全唐诗/poet.tang.29000.json','["代北偏師銜使節，關中裨將建行臺。", "不妨常日饒輕薄，且喜臨戎用草萊。"]'),
('ea82e0c2-3af3-48a9-a08a-2012a4772101','漫成五章 五','李商隱','唐','唐诗','tang','','[]','郭令素心非黷武，韓公本意在和戎。',32,'全唐诗/poet.tang.29000.json','["郭令素心非黷武，韓公本意在和戎。", "兩都耆舊偏垂淚，臨老中原見朔風。"]'),
('de91c17f-6db9-48c8-a6e3-db4e499803af','射魚曲','李商隱','唐','唐诗','tang','','[]','思牢弩箭磨青石，繡額蠻渠三虎力。',64,'全唐诗/poet.tang.29000.json','["思牢弩箭磨青石，繡額蠻渠三虎力。", "尋潮背日伺泅鱗，貝闕夜移鯨失色。", "纖纖粉簳馨香餌，綠鴨回塘養龍水。", "含冰漢語遠於天，何由回作金盤死。"]'),
('f3a696d8-ae23-42b2-ad56-0af657c1176e','日高','李商隱','唐','唐诗','tang','','[]','鍍鐶故錦縻輕拖，玉𥫽不動便門鎖。',64,'全唐诗/poet.tang.29000.json','["鍍鐶故錦縻輕拖，玉𥫽不動便門鎖。", "水精眠夢是何人，欄藥日高紅髲𩭝。", "飛香上雲春訴天，雲梯十二門九關。", "輕身滅影何可望，粉蛾帖死屏風上。"]'),
('0839ea23-580d-43fd-bc24-ca9e752d0e8e','宮中曲','李商隱','唐','唐诗','tang','','[]','雲母濾宮月，夜夜白於水。',72,'全唐诗/poet.tang.29000.json','["雲母濾宮月，夜夜白於水。", "賺得羊車來，低扇遮黃子。", "水精不覺冷，自刻鴛鴦翅。", "蠶縷茜香濃，正朝纏左臂。", "巴牋兩三幅，滿寫承恩字。", "欲得識青天，昨夜蒼龍是。"]'),
('5139878e-bd5a-4aa3-9333-00b1ce9f4cc4','海上謠','李商隱','唐','唐诗','tang','','[]','桂水寒於江，玉兔秋冷咽。',76,'全唐诗/poet.tang.29000.json','["桂水寒於江，玉兔秋冷咽。", "海底覓仙人，香桃如瘦骨。", "紫鸞不肯舞，滿翅蓬山雪。", "借得龍堂寬，曉出揲雲髪。", "劉郎舊香炷，立見茂陵樹。", "雲孫帖帖臥秋煙，上元細字如蠶眠。"]'),
('ce8dd56f-f879-4962-8bc2-e8a8b5660174','李夫人三首 一','李商隱','唐','唐诗','tang','','[]','一帶不結心，兩股方安髻。',24,'全唐诗/poet.tang.29000.json','["一帶不結心，兩股方安髻。", "慙愧白茅人，月沒教星替。"]'),
('74f9bb0d-5622-482c-b165-11fd6e89d3a0','李夫人三首 二','李商隱','唐','唐诗','tang','','[]','剩結茱萸枝，多擘秋蓮的。',24,'全唐诗/poet.tang.29000.json','["剩結茱萸枝，多擘秋蓮的。", "獨自有波光，綵囊盛不得。"]'),
('65344e34-9b98-44cb-9ad9-bb92010a52e2','李夫人三首 三','李商隱','唐','唐诗','tang','','["\u9ec4\u6cb3"]','蠻絲繫條脫，妍眼和香屑。',76,'全唐诗/poet.tang.29000.json','["蠻絲繫條脫，妍眼和香屑。", "壽宮不惜鑄南人，柔腸早被秋眸割。", "清澄有餘幽素香，鰥魚渴鳳真珠房。", "不知瘦骨類冰井，更許夜簾通曉霜。", "土花漠漠雲茫茫，黃河欲盡天蒼蒼。"]'),
('d91d4049-4d11-4b38-891c-888b3aa592ce','景陽宮井雙桐','李商隱','唐','唐诗','tang','','[]','秋港菱花乾，玉盤明月蝕。',124,'全唐诗/poet.tang.29000.json','["秋港菱花乾，玉盤明月蝕。", "血滲兩枯心，情多去未得。", "徒經白門伴，不見丹山客。", "未待刻作人，愁多有魂魄。", "誰將玉盤與，不死翻相誤。", "天更闊於江，孫枝覓郎主。", "昔妬隣宮槐，道類雙眉歛。", "今日繁紅櫻，拋人占長簟。", "翠襦不禁綻，留淚啼天眼。", "寒灰劫盡問方知，石羊不去誰相絆。"]'),
('be8991ff-00c0-47b6-b1d1-1bd0e61ad1a0','秋日晚思','李商隱','唐','唐诗','tang','','[]','桐槿日零落，雨餘方寂寥。',48,'全唐诗/poet.tang.29000.json','["桐槿日零落，雨餘方寂寥。", "枕寒莊蝶去，窻冷胤螢銷。", "取適琴將酒，忘名牧與樵。", "平生有遊舊，一一在煙霄。"]'),
('40fe3139-61c4-4a96-8206-f879f613a694','春宵自遣','李商隱','唐','唐诗','tang','','[]','地勝遺塵事，身閑念歲華。',48,'全唐诗/poet.tang.29000.json','["地勝遺塵事，身閑念歲華。", "晚晴風過竹，深夜月當花。", "石亂知泉咽，苔荒任逕斜。", "陶然恃琴酒，忘却在山家。"]'),
('7b71e7a7-5444-4112-87d1-26510d74961d','七夕偶題','李商隱','唐','唐诗','tang','','[]','寶婺搖珠珮，常娥照玉輪。',48,'全唐诗/poet.tang.29000.json','["寶婺搖珠珮，常娥照玉輪。", "靈歸天上匹，巧遺世間人。", "花果香千戶，笙竽濫四隣。", "明朝曬犢鼻，方信阮家貧。"]'),
('e24c0447-4f15-4fff-9025-caca400fa139','靈仙閣晚眺寄鄆州韋評事','李商隱','唐','唐诗','tang','','[]','愚公方住谷，仁者本依山。',96,'全唐诗/poet.tang.29000.json','["愚公方住谷，仁者本依山。", "共誓林泉志，胡爲尊俎間。", "華蓮開菡萏，荆玉刻孱顏。", "爽氣臨周道，嵐光入漢關。", "滿壺徒蟻泛，高閣已苔斑。", "想就安車召，寧期負矢還。", "潘遊全璧散，郭去半舟閑。", "定笑幽人跡，鴻軒不可攀。"]'),
('4350eb92-339b-49e8-b8a3-8a13b6cb4813','幽居冬暮','李商隱','唐','唐诗','tang','','["\u7231\u56fd", "\u51ac\u5929", "\u5199\u666f"]','羽翼摧殘日，郊園寂寞時。',48,'全唐诗/poet.tang.29000.json','["羽翼摧殘日，郊園寂寞時。", "曉雞驚樹雪，寒騖守冰池。", "急景忽云暮，頹年浸已衰。", "如何匡國分，不與夙心期。"]'),
('1fcaa691-8161-4893-9958-ce4d224e6be3','過姚孝子廬偶書','李商隱','唐','唐诗','tang','','[]','拱木臨周道，荒廬積古苔。',48,'全唐诗/poet.tang.29000.json','["拱木臨周道，荒廬積古苔。", "魚因感姜出，鶴爲弔陶來。", "兩鬢蓬常亂，雙眸血不開。", "聖朝敦爾類，非獨路人哀。"]'),
('702e1b2f-5792-4007-9be4-4d121e740061','賦得月照冰池','李商隱','唐','唐诗','tang','','[]','皓月方離海，堅冰正滿池。',96,'全唐诗/poet.tang.29000.json','["皓月方離海，堅冰正滿池。", "金波雙激射，璧彩兩參差。", "影占徘徊處，光含的皪時。", "高低連素色，上下接清規。", "顧兔飛難定，潛魚躍未期。", "鵲驚俱欲遶，狐聽始無疑。", "似鏡將盈手，如霜恐透肌。", "獨憐遊翫意，達曉不知疲。"]'),
('43f35b78-9101-4e37-9c51-0ab68d3fcf52','永樂縣所居一草一木無非自栽今春悉已芳茂因書即事一章','李商隱','唐','唐诗','tang','','[]','手種悲陳事，心期玩物華。',72,'全唐诗/poet.tang.29000.json','["手種悲陳事，心期玩物華。", "柳飛彭澤雪，桃散武陵霞。", "枳嫩棲鸞葉，桐香待鳳花。", "綬藤縈弱蔓，袍草展新芽。", "學植功雖倍，成蹊跡尚賒。", "芳年誰共玩，終老邵平瓜。"]'),
('5ee868dd-0971-493e-8cbb-97d8e8e2b68d','南潭上亭讌集以疾後至因而抒情','李商隱','唐','唐诗','tang','','[]','馬卿聊應召，謝傅已登山。',72,'全唐诗/poet.tang.29000.json','["馬卿聊應召，謝傅已登山。", "歌發百花外，樂調深竹間。", "鷁舟縈遠岸，魚鑰啓重關。", "鸎蝶如相引，煙蘿不暇攀。", "佳人啓玉齒，上客頷朱顏。", "肯念沈痾士，俱期倒載還。"]'),
('ed0a5d7c-e6f1-4ef7-847d-42367dd4ffe1','寒食行次冷泉驛','李商隱','唐','唐诗','tang','','[]','驛途仍近節，旅宿倍思家。',48,'全唐诗/poet.tang.29000.json','["驛途仍近節，旅宿倍思家。", "獨夜三更月，空庭一樹花。", "介山當驛秀，汾水遶關斜。", "自怯春寒苦，那堪禁火賒。"]'),
('4b17e56c-b0f1-4293-a390-aa8ccdce82c3','寄華嶽孫逸人','李商隱','唐','唐诗','tang','','["\u534e\u5c71"]','靈嶽幾千仞，老松逾百尋。',48,'全唐诗/poet.tang.29000.json','["靈嶽幾千仞，老松逾百尋。", "攀崖仍躡壁，噉葉復眠陰。", "海上呼三島，齋中戲五禽。", "唯應逢阮籍，長嘯作鸞音。"]'),
('8520c586-9556-4c55-8a11-56d416380376','戲題贈稷山驛吏王全','李商隱','唐','唐诗','tang','','[]','絳臺驛吏老風塵，耽酒成仙幾十春。',32,'全唐诗/poet.tang.29000.json','["絳臺驛吏老風塵，耽酒成仙幾十春。", "過客不勞詢甲子，惟書亥字與時人。"]'),
('8de6a9e6-0185-4bc4-8bc5-3c38a3b9def4','和韋潘前輩七月十二日夜泊池州城下先寄上李使君','李商隱','唐','唐诗','tang','','[]','桂含爽氣三秋首，蓂吐中旬二葉新。',32,'全唐诗/poet.tang.29000.json','["桂含爽氣三秋首，蓂吐中旬二葉新。", "正是澄江如練處，玄暉應喜見詩人。"]'),
('50295b5c-22d9-4c04-975c-7edddb177542','花下醉','李商隱','唐','唐诗','tang','','[]','尋芳不覺醉流霞，倚樹沈眠日已斜。',32,'全唐诗/poet.tang.29000.json','["尋芳不覺醉流霞，倚樹沈眠日已斜。", "客散酒醒深夜後，更持紅燭賞殘花。"]'),
('fbc7d768-3364-466a-9db3-ccec07df57a1','所居永樂縣久旱縣宰祈禱得雨因賦詩','李商隱','唐','唐诗','tang','','[]','甘膏滴滴是精誠，晝夜如絲一尺盈。',32,'全唐诗/poet.tang.29000.json','["甘膏滴滴是精誠，晝夜如絲一尺盈。", "祗怪閭閻喧鼓吹，邑人同報束長生。"]'),
('7af6841a-3381-426d-a811-4e1d133ba180','正月十五夜聞京有燈恨不得觀','李商隱','唐','唐诗','tang','','["\u8282\u65e5", "\u5143\u5bb5\u8282", "\u5143\u5bb5"]','月色燈光滿帝都，香車寶輦隘通衢。',32,'全唐诗/poet.tang.29000.json','["月色燈光滿帝都，香車寶輦隘通衢。", "身閑不睹中興盛，羞逐鄉人賽紫姑。"]'),
('cbce96ac-c994-4521-b108-5e25b931320a','贈趙協律晳','李商隱','唐','唐诗','tang','','[]','俱識孫公與謝公，二年歌哭處還同。',63,'全唐诗/poet.tang.29000.json','["俱識孫公與謝公，二年歌哭處還同。", "已叨鄒馬聲華末，更共劉盧族望通南省恩深賓館在，東山事往妓樓空。", "不堪歲暮相逢地，我欲西征君又東。"]'),
('3f9c820c-a58e-49f3-b2be-e614fc15850a','搖落','李商隱','唐','唐诗','tang','','[]','搖落傷年日，羈留念遠心。',96,'全唐诗/poet.tang.29000.json','["搖落傷年日，羈留念遠心。", "水亭吟斷續，月幌夢飛沈。", "古木含風久，疎螢怯露深。", "人閑始遙夜，地迥更清砧。", "結愛曾傷晚，端憂復至今。", "未諳滄海路，何處玉山岑？", "灘激黃牛暮，雲屯白帝陰。", "遙知霑灑意，不減欲分襟。"]'),
('9386eae5-ef3b-4c42-8602-bee9a75a8018','滯雨','李商隱','唐','唐诗','tang','','["\u6292\u60c5", "\u601d\u4e61"]','滯雨長安夜，殘燈獨客愁。',24,'全唐诗/poet.tang.29000.json','["滯雨長安夜，殘燈獨客愁。", "故鄉雲水地，歸夢不宜秋。"]'),
('264265bc-10cc-4084-b6e7-e6d93ddfecbd','偶題二首 一','李商隱','唐','唐诗','tang','','[]','小亭閒眠微醉消，山榴海栢枝相交。',32,'全唐诗/poet.tang.29000.json','["小亭閒眠微醉消，山榴海栢枝相交。", "水文簟上琥珀枕，傍有墮釵雙翠翹。"]'),
('26560253-1755-422e-861b-0a1d456bf79a','偶題二首 二','李商隱','唐','唐诗','tang','','[]','清月依微香露輕，曲房小院多逢迎。',32,'全唐诗/poet.tang.29000.json','["清月依微香露輕，曲房小院多逢迎。", "春叢定見饒棲鳥，飲罷莫持紅燭行。"]'),
('00135042-ba1a-4926-9c73-f227f3a7793e','月','李商隱','唐','唐诗','tang','','[]','過水穿樓觸處明，藏人帶樹遠含清。',32,'全唐诗/poet.tang.29000.json','["過水穿樓觸處明，藏人帶樹遠含清。", "初生欲缺虛惆悵，未必圓時即有情。"]'),
('76b3540f-48bf-4116-a9aa-73b368ac9521','夜冷','李商隱','唐','唐诗','tang','','[]','樹遶池寬月影多，村砧塢笛隔風蘿。',32,'全唐诗/poet.tang.29000.json','["樹遶池寬月影多，村砧塢笛隔風蘿。", "西亭翠被餘香薄，一夜將愁向敗荷。"]'),
('f8d3fa77-35a3-407f-9205-1d372b8c98ca','正月崇讓宅','李商隱','唐','唐诗','tang','','[]','密鎖重關掩綠苔，廊深閣迥此徘徊。',64,'全唐诗/poet.tang.29000.json','["密鎖重關掩綠苔，廊深閣迥此徘徊。", "先知風起月含暈，尚自露寒花未開。", "蝙拂簾旌終展轉，鼠翻牕網小驚猜。", "背燈獨共餘香語，不覺猶歌起夜來。"]'),
('7d0944b7-f3a5-415f-b728-4c275497cc98','城外','李商隱','唐','唐诗','tang','','[]','露寒風定不無情，臨水當山又隔城。',32,'全唐诗/poet.tang.29000.json','["露寒風定不無情，臨水當山又隔城。", "未必明時勝蜯蛤，一生長共月虧盈。"]'),
('c4914cff-9362-498b-9602-c802daf5c870','撰彭陽公誌文畢有感','李商隱','唐','唐诗','tang','','[]','延陵留表墓，峴首送沈碑。',48,'全唐诗/poet.tang.29000.json','["延陵留表墓，峴首送沈碑。", "敢伐不加點，猶當無愧辭。", "百生終莫報，九死諒難追。", "待得生金後，川原亦幾移。"]'),
('9380d4f6-e19d-4ff1-8309-07f4ede69f7c','北青蘿','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5bfb\u8bbf", "\u4e94\u8a00\u5f8b\u8bd7"]','殘陽西入崦，茅屋訪孤僧。',48,'全唐诗/poet.tang.29000.json','["殘陽西入崦，茅屋訪孤僧。", "落葉人何在，寒雲路幾層。", "獨敲初夜磬，閑倚一枝藤。", "世界微塵裏，吾寧愛與憎。"]'),
('8c43285a-df09-4b32-b5d7-9af713978aa6','戲贈張書記','李商隱','唐','唐诗','tang','','[]','別館君孤枕，空庭我閉關。',72,'全唐诗/poet.tang.29000.json','["別館君孤枕，空庭我閉關。", "池光不受月，野氣欲沈山。", "星漢秋方會，關河夢幾還。", "危絃傷遠道，明鏡惜紅顏。", "古木含風久，平蕪盡日閑。", "心知兩愁絕，不段若尋環。"]'),
('f88687ce-4a49-4ee7-a7e7-201caaa98247','幽人','李商隱','唐','唐诗','tang','','[]','丹竈三年火，蒼崖萬歲藤。',48,'全唐诗/poet.tang.29000.json','["丹竈三年火，蒼崖萬歲藤。", "樵歸說逢虎，碁罷正留僧。", "星斗同秦分，人煙接漢陵。", "東流清渭苦，不盡照衰興。"]'),
('c5f746e9-c478-46ee-9338-3b7cdb5ae376','念遠','李商隱','唐','唐诗','tang','','[]','日月淹秦甸，江湖動越吟。',72,'全唐诗/poet.tang.29000.json','["日月淹秦甸，江湖動越吟。", "蒼桐應露下，白閣自雲深。", "皎皎非鸞扇，翹翹失鳳簪。", "牀空鄂君被，杵冷女媭砧。", "北思驚沙雁，南情屬海禽。", "關山已搖落，天地共登臨。"]'),
('3b8fc044-5100-49fd-86fb-9431f821777e','過故崔兖海宅與崔明秀才話舊因寄僚杜趙李三掾','李商隱','唐','唐诗','tang','','[]','絳帳恩如昨，烏衣事莫尋。',48,'全唐诗/poet.tang.29000.json','["絳帳恩如昨，烏衣事莫尋。", "諸生空會葬，舊掾已華簪。", "共入留賓驛，俱分市駿金。", "莫憑無鬼論，終負託孤心。"]'),
('23fd89cf-a133-42f4-80eb-d4997dc36bec','微雨','李商隱','唐','唐诗','tang','','["\u5199\u96e8", "\u96e8", "\u548f\u7269", "\u548f\u7269\u8bd7"]','初隨林靄動，稍共夜涼分。',24,'全唐诗/poet.tang.29000.json','["初隨林靄動，稍共夜涼分。", "窗迥侵燈冷，庭虛近水聞。"]'),
('91b7a173-d330-4add-afc4-013c9d480ed9','南山趙行軍新詩盛稱游讌之洽因寄一絶','李商隱','唐','唐诗','tang','','[]','蓮幕遙臨黑水津，橐鞬無事但尋春。',32,'全唐诗/poet.tang.29000.json','["蓮幕遙臨黑水津，橐鞬無事但尋春。", "梁王司馬非孫武，且免宮中斬美人。"]'),
('c60a62f9-bae4-45fe-b7f1-899b0acf8515','曲江','李商隱','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u60b2\u4f24", "\u53d9\u4e8b", "\u653f\u6cbb"]','望斷平時翠輦過，空聞子夜鬼悲歌。',64,'全唐诗/poet.tang.29000.json','["望斷平時翠輦過，空聞子夜鬼悲歌。", "金輿不返傾城色，玉殿猶分下苑波。", "死憶華亭聞唳鶴，老憂王室泣銅駝。", "天荒地變心難折，若比陽春意未多。"]'),
('b9e00bc2-52d6-49bd-91c2-6ef990f4e0b7','景陽井','李商隱','唐','唐诗','tang','','[]','景陽宮井剩堪悲，不盡龍鸞誓死期。',32,'全唐诗/poet.tang.29000.json','["景陽宮井剩堪悲，不盡龍鸞誓死期。", "腸斷吳王宮外水，濁泥猶得葬西施。"]'),
('bc9a793a-a116-4a9c-b0b9-8a4f38b7ae89','故番禺侯以贓罪致不辜事覺母者他日過其門','李商隱','唐','唐诗','tang','','[]','飲鴆非君命，茲身亦厚亡。',48,'全唐诗/poet.tang.29000.json','["飲鴆非君命，茲身亦厚亡。", "江陵從種橘，交廣合投香。", "不見千金子，空馀數仞墻。", "殺人須顯戮，誰舉漢三章。"]'),
('63431f77-0404-4f65-8bf0-a193ece18c35','詠雲','李商隱','唐','唐诗','tang','','[]','捧月三更斷，藏星七夕明。',48,'全唐诗/poet.tang.29000.json','["捧月三更斷，藏星七夕明。", "纔聞飄迥路，旋見隔重城。", "潭暮隨龍起，河秋壓雁聲。", "只應惟宋玉，知是楚神名。"]'),
('dea9f624-70b1-4bc6-b2d6-00c20bed2e79','夜出西溪','李商隱','唐','唐诗','tang','','[]','東府憂春盡，西溪許日曛。',48,'全唐诗/poet.tang.29000.json','["東府憂春盡，西溪許日曛。", "月澄新漲水，星見欲銷雲。", "柳好休傷別，松高莫出羣。", "軍書雖倚馬，猶未當能文。"]'),
('a0c8050c-4122-4c2a-a6a6-e66d096331a2','效長吉','李商隱','唐','唐诗','tang','','[]','長長漢殿眉，窄窄楚宮衣。',36,'全唐诗/poet.tang.29000.json','["長長漢殿眉，窄窄楚宮衣。", "鏡好鸞空舞，簾疎燕誤飛。", "君王不可問，昨夜約黃歸。"]'),
('97baa2c2-02e7-4320-8ccc-9509c669d752','柳','李商隱','唐','唐诗','tang','','[]','江南江北雪初消，漠漠輕黃惹嫩條。',64,'全唐诗/poet.tang.29000.json','["江南江北雪初消，漠漠輕黃惹嫩條。", "灞岸已攀行客手，楚宮先騁舞姬腰。", "清明帶雨臨官道，晚日含風拂野橋。", "如線如絲正牽恨，王孫歸路一何遙。"]'),
('98dadbcc-7409-42f1-b504-2b2775282f4c','九月於東逢雪','李商隱','唐','唐诗','tang','','[]','舉家忻共報，秋雪墮前峰。',48,'全唐诗/poet.tang.29000.json','["舉家忻共報，秋雪墮前峰。", "嶺外他年憶，於東此日逢。", "粒輕還自亂，花薄未成重。", "豈是驚離鬢，應來洗病容。"]'),
('99969894-e7ad-4687-a9ee-c02c7c232a48','四皓廟','李商隱','唐','唐诗','tang','','[]','本爲留侯慕赤松，漢庭方識紫芝翁。',32,'全唐诗/poet.tang.29000.json','["本爲留侯慕赤松，漢庭方識紫芝翁。", "蕭何只解追韓信，豈得虛當第一功。"]'),
('5acb0fbd-d02d-4370-97d3-17edc3d0258a','送阿龜歸華','李商隱','唐','唐诗','tang','','[]','草堂歸意背煙蘿，黃綬垂腰不奈何。',32,'全唐诗/poet.tang.29000.json','["草堂歸意背煙蘿，黃綬垂腰不奈何。", "因汝華陽求藥物，碧松根下茯苓多。"]'),
('f45be7b3-9455-4769-a066-3bb421d02a19','九日','李商隱','唐','唐诗','tang','','[]','曾共山翁把酒時，霜天白菊繞堦墀。',64,'全唐诗/poet.tang.29000.json','["曾共山翁把酒時，霜天白菊繞堦墀。", "十年泉下無人問，九日樽前有所思。", "不學漢臣栽苜蓿，空教楚客詠江籬。", "郎君官貴施行馬，東閣無因再得窺。"]'),
('39ecc68c-d75d-4256-bc26-6ebb2e184bc5','僧院牡丹','李商隱','唐','唐诗','tang','','[]','薄葉風才倚，枝輕霧不勝。',48,'全唐诗/poet.tang.29000.json','["薄葉風才倚，枝輕霧不勝。", "開先如避客，色淺爲依僧。", "粉壁正蕩水，緗幃初卷燈。", "傾城惟待笑，要裂幾多繒。"]'),
('af2b6768-c929-4910-97f5-7472cc1217e1','贈司勳杜十三員外','李商隱','唐','唐诗','tang','','["\u957f\u6c5f"]','杜牧司勳字牧之，清秋一首杜秋詩。',66,'全唐诗/poet.tang.29000.json','["杜牧司勳字牧之，清秋一首杜秋詩。", "前身應是梁江總，名總還曾字總持。", "心鐵已從干鏌利，鬢絲休嘆雪霜垂。", "漢江遠弔西江水，羊[祜]韋丹盡有碑。"]'),
('751c67f2-a4a5-462e-877f-87d9e9e47578','高花','李商隱','唐','唐诗','tang','','[]','花將人共笑，籬外露繁枝。',24,'全唐诗/poet.tang.29000.json','["花將人共笑，籬外露繁枝。", "宋玉臨江宅，墻低不礙窺。"]'),
('5831e658-329d-4fd8-b624-c4af883a121f','嘲桃','李商隱','唐','唐诗','tang','','[]','無賴夭桃面，平明露井東。',24,'全唐诗/poet.tang.29000.json','["無賴夭桃面，平明露井東。", "春風爲開了，却擬笑春風。"]'),
('18d87f3b-c668-427b-9e56-0e1022911d52','送豐都李尉','李商隱','唐','唐诗','tang','','[]','萬古商於地，憑君泣路岐。',48,'全唐诗/poet.tang.29000.json','["萬古商於地，憑君泣路岐。", "固難尋綺季，可得信張儀。", "雨氣燕先覺，葉陰蟬遽知。", "望鄉尤忌晚，山晚更參差。"]'),
('7df747d5-e7b2-4651-ab44-f0f7db3534c1','天平公座中呈令狐令公時蔡京在坐京曾爲僧徒故有第五句','李商隱','唐','唐诗','tang','','[]','罷執霓旌上醮壇，慢粧嬌樹水晶盤。',64,'全唐诗/poet.tang.29000.json','["罷執霓旌上醮壇，慢粧嬌樹水晶盤。", "更深欲訴蛾眉歛，衣薄臨醒玉豔寒。", "白足禪僧思敗道，青袍御史擬休官。", "雖然同是將軍客，不敢公然子細看。"]'),
('475063b5-bd8e-48a9-9ea2-d0226e53d7de','江上憶嚴五廣休','李商隱','唐','唐诗','tang','','[]','征南幕下帶長刀，夢筆深藏五色毫。',32,'全唐诗/poet.tang.29000.json','["征南幕下帶長刀，夢筆深藏五色毫。", "逢著澄江不敢詠，鎮西留與謝功曹。"]'),
('40d6818a-3178-4ec6-ba53-74234ea48421','餞席重送從叔余之梓州','李商隱','唐','唐诗','tang','','[]','莫歎萬重山，君還我未還。',24,'全唐诗/poet.tang.29000.json','["莫歎萬重山，君還我未還。", "武關猶悵望，何況百牢關。"]'),
('4c35c7ff-bf5d-4dca-9e32-da58c5713909','訪隱','李商隱','唐','唐诗','tang','','[]','路到層峰斷，門依老樹開。',48,'全唐诗/poet.tang.29000.json','["路到層峰斷，門依老樹開。", "月從平楚轉，泉自上方來。", "薤白羅朝饌，松黃暖夜盃。", "相留笑孫綽，空解賦天台。"]'),
('cd8f26bd-589f-462d-b1a4-e9f30f19dbcb','寓興','李商隱','唐','唐诗','tang','','[]','薄宦仍多病，從知竟遠遊。',48,'全唐诗/poet.tang.29000.json','["薄宦仍多病，從知竟遠遊。", "談諧叨客禮，休澣接冥搜。", "樹好頻移榻，雲奇不下樓。", "豈關無景物，自是有鄉愁。"]'),
('1f484765-e036-4f66-b3e8-0e36f0fec4cb','東南','李商隱','唐','唐诗','tang','','[]','東南一望日中烏，欲遂羲和去得無。',32,'全唐诗/poet.tang.29000.json','["東南一望日中烏，欲遂羲和去得無。", "且向秦樓棠樹下，每朝先覓照羅敷。"]'),
('15c66868-b96c-4213-a1ae-a3311faa0982','歸來','李商隱','唐','唐诗','tang','','[]','舊隱無何別，歸來始更悲。',48,'全唐诗/poet.tang.29000.json','["舊隱無何別，歸來始更悲。", "難尋白道士，不見惠禪師。", "草徑蟲鳴急，沙渠水下遲。", "却將波浪眼，清曉對紅梨。"]'),
('a18a5269-8281-44f4-9fc6-b0f097b580aa','子直晉昌李花','李商隱','唐','唐诗','tang','','[]','吳館何時熨，秦臺幾夜熏。',48,'全唐诗/poet.tang.29000.json','["吳館何時熨，秦臺幾夜熏。", "綃輕誰解卷，香異自先聞。", "月裏誰無姊，雲中亦有君。", "罇前見飄蕩，愁極客襟分。"]'),
('2e1338b8-d89b-4f96-8346-0ce769e21d60','河清與趙氏昆季讌集得擬杜工部','李商隱','唐','唐诗','tang','','[]','勝概殊江右，佳名逼渭川。',48,'全唐诗/poet.tang.29000.json','["勝概殊江右，佳名逼渭川。", "虹收青嶂雨，鳥沒夕陽天。", "客鬢行如此，滄波坐渺然。", "此中真得地，漂蕩釣魚船。"]'),
('29fe9b6a-61b4-4cff-8e65-0ea9e1649922','寓目','李商隱','唐','唐诗','tang','','[]','園桂懸心碧，池蓮飫眼紅。',48,'全唐诗/poet.tang.29000.json','["園桂懸心碧，池蓮飫眼紅。", "此生真遠客，幾別即衰翁。", "小幌風煙入，高窻霧雨通。", "新知他日好，錦瑟傍朱櫳。"]'),
('55e36123-9411-4b9b-b9e3-4bc20f6c5b38','題道靜院院在中條山故王顏中丞所置虢州刺史捨官居此今寫真存焉','李商隱','唐','唐诗','tang','','[]','紫府丹成化鶴羣，青松手植變龍文。',64,'全唐诗/poet.tang.29000.json','["紫府丹成化鶴羣，青松手植變龍文。", "壺中別有仙家日，嶺上猶多隱士雲。", "獨坐遺芳成故事，褰帷舊貌似元君。", "自憐築室靈山下，徒望朝嵐與夕曛。"]'),
('9521af5a-4b92-4e5f-af33-ba71807dbce2','賦得桃李無言','李商隱','唐','唐诗','tang','','[]','夭桃花正發，穠李蘂方繁。',72,'全唐诗/poet.tang.29000.json','["夭桃花正發，穠李蘂方繁。", "應候非爭豔，成蹊不在言。", "靜中霞暗吐，香處雪潛翻。", "得意搖風態，含情泣露痕。", "芬芳光上苑，寂默委中園。", "赤白徒自許，幽芳誰與論。"]'),
('404b5d91-26be-4868-b366-3c9562917770','登霍山驛樓','李商隱','唐','唐诗','tang','','[]','廟列前峰迥，樓開四望窮。',48,'全唐诗/poet.tang.29000.json','["廟列前峰迥，樓開四望窮。", "嶺鼷嵐色外，陂雁夕陽中。", "弱柳千條露，衰荷一面風。", "壺關有狂孽，速繼老生功。"]'),
('0bcc8af5-e5cd-4dbd-9db4-bdfdb585826b','寄和水部馬郎中題興德驛時昭義已平','李商隱','唐','唐诗','tang','','[]','仙郎倦去心，鄭驛暫登臨。',48,'全唐诗/poet.tang.29000.json','["仙郎倦去心，鄭驛暫登臨。", "水色瀟湘闊，沙程朔漠深。", "鷁舟時往復，鷗鳥恣浮沈。", "更想逢歸馬，悠悠嶽樹陰。"]'),
('30c37368-602f-4ccf-9de5-36e827acaac0','題小松','李商隱','唐','唐诗','tang','','["\u6292\u60c5", "\u548f\u7269", "\u548f\u7269\u8bd7"]','憐君孤秀植庭中，細葉輕陰滿座風。',64,'全唐诗/poet.tang.29000.json','["憐君孤秀植庭中，細葉輕陰滿座風。", "桃李盛時雖寂寞，雪霜多後始青蔥。", "一年幾變枯榮事，百尺方資柱石功。", "爲謝西園車馬客，定悲搖落盡成空。"]'),
('bc1fb1be-6613-49e7-b3ff-45b6c5cb6590','行次昭應縣道上送戶部李郎中充昭義攻討','李商隱','唐','唐诗','tang','','[]','將軍大斾埽狂童，詔選名賢贊武功。',64,'全唐诗/poet.tang.29000.json','["將軍大斾埽狂童，詔選名賢贊武功。", "暫逐虎牙臨故絳，遠含雞舌過新豐。", "魚遊沸鼎知無日，鳥覆危巢豈待風。", "早勒勳庸燕石上，佇光綸綍漢廷中。"]'),
('abf6916b-e466-4acb-a755-e2bfc3a3f6d7','水齋','李商隱','唐','唐诗','tang','','[]','多病欣依有道邦，南塘宴起想秋江。',64,'全唐诗/poet.tang.29000.json','["多病欣依有道邦，南塘宴起想秋江。", "卷簾飛燕還拂水，開戶暗蟲猶打窗。", "更閱前題已披卷，仍斟昨夜未開缸。", "誰人爲報故交道，莫惜鯉雨時一雙。"]'),
('bee77a97-c70a-4d90-bd7b-01f0f8cf9998','奉同諸公題河中任中丞新創河亭四韻之作','李商隱','唐','唐诗','tang','','[]','萬里誰能訪十洲，新亭雲搆壓中流。',64,'全唐诗/poet.tang.29000.json','["萬里誰能訪十洲，新亭雲搆壓中流。", "河鮫縱翫難爲室，海蜃遙驚恥化樓。", "左右名山窮遠目，東西大道鎖輕舟。", "獨留巧思傳千古，長與蒲津作勝遊。"]'),
('62cc5ffe-6f2f-43a8-9cf3-562c4607039d','過故府中武威公交城舊莊感事','李商隱','唐','唐诗','tang','','[]','信陵亭館接郊畿，幽象遙通晉水祠。',64,'全唐诗/poet.tang.29000.json','["信陵亭館接郊畿，幽象遙通晉水祠。", "日落高門喧燕雀，風飄大樹撼熊羆。", "新蒲似筆思投日，芳草如茵憶吐時。", "山下祗今黃絹字，淚痕猶墮六州兒。"]'),
('27e9b15b-75ed-46c3-ada7-d4d10190785f','贈田叟','李商隱','唐','唐诗','tang','','[]','荷蓧衰翁似有情，相逢攜手遶村行。',64,'全唐诗/poet.tang.29000.json','["荷蓧衰翁似有情，相逢攜手遶村行。", "燒畬曉映遠山色，伐樹暝傳深谷聲。", "鷗鳥忘機翻浹洽，交親得路昧平生。", "撫躬道直誠感激，在野無賢心自驚。"]'),
('dc6f6aa7-b244-45a3-9cb5-c4b9737c9bce','贈別前蔚州契苾使君','李商隱','唐','唐诗','tang','','["\u6218\u4e89"]','何年部落到陰陵，奕世勤王國史稱。',64,'全唐诗/poet.tang.29000.json','["何年部落到陰陵，奕世勤王國史稱。", "夜捲牙旗千帳雪，朝飛羽騎一河冰。", "蕃兒襁負來青塚，狄女壺漿出白登。", "日晚鸊鵜泉畔獵，路人遙識郅都鷹。"]'),
('416a1b26-baf9-499f-8838-34ce8d26691a','和人題真娘墓','李商隱','唐','唐诗','tang','','[]','虎丘山下劒池邊，長遣遊人嘆逝川。',64,'全唐诗/poet.tang.29000.json','["虎丘山下劒池邊，長遣遊人嘆逝川。", "罥樹斷絲悲舞席，出雲清梵想歌筵。", "柳眉空吐效顰葉，榆莢還飛買笑錢。", "一自香魂招不得，祗應江上獨嬋娟。"]'),
('dc83756d-d6a8-4da7-9daf-4f1e91470ed7','人日即事','李商隱','唐','唐诗','tang','','[]','文王喻復今朝是，子晉吹笙此日同。',64,'全唐诗/poet.tang.29000.json','["文王喻復今朝是，子晉吹笙此日同。", "舜格有苗旬太遠，周稱流火月難窮。", "鏤金作勝傳荆俗，翦綵爲人起晉風。", "獨想道衡詩思苦，離家恨得二年中。"]'),
('9e08df46-f0ea-4e85-b136-c0945ab28482','春日寄懷','李商隱','唐','唐诗','tang','','["\u6625\u5929", "\u6292\u6000", "\u6101\u82e6", "\u58ee\u5fd7\u672a\u916c"]','世間榮落重逡巡，我獨丘園坐四春。',64,'全唐诗/poet.tang.29000.json','["世間榮落重逡巡，我獨丘園坐四春。", "縱使有花兼有月，可堪無酒又無人。", "青袍似草年年定，白髮如絲日日新。", "欲逐風波千萬里，未知何路到龍津。"]'),
('2540c7c4-de81-4032-8360-262fa6d72053','和劉評事永樂閑居見寄','李商隱','唐','唐诗','tang','','[]','白社幽閑君暫居，青雲器業我全疎。',64,'全唐诗/poet.tang.29000.json','["白社幽閑君暫居，青雲器業我全疎。", "看封諫草歸鸞掖，尚賁衡門待鶴書。", "蓮聳碧峰關路近，荷翻翠扇水堂虛。", "自探典籍忘名利，欹枕時驚落蠹魚。"]'),
('1c1ac9e3-ae77-47b4-a501-ab9ca2eb84bc','和馬郎中移白菊見示','李商隱','唐','唐诗','tang','','[]','陶詩只採黃金寶，郢曲新傳白雪英。',64,'全唐诗/poet.tang.29000.json','["陶詩只採黃金寶，郢曲新傳白雪英。", "素色不同籬下發，繁花疑自月中生。", "浮杯小摘開雲母，帶露全移綴水精。", "偏稱含香五字客，從茲得地始芳榮。"]'),
('b04fcdbd-a33c-4a85-bb27-f14970010de5','喜聞太原同院崔侍御臺拜兼寄在臺三二同年之什','李商隱','唐','唐诗','tang','','[]','鵬魚何事遇屯同，雲水升沈一會中。',64,'全唐诗/poet.tang.29000.json','["鵬魚何事遇屯同，雲水升沈一會中。", "劉放未歸雞樹老，鄒陽新去兔園空。", "寂寥我對先生柳，赫奕君乘御史驄。", "若向南臺見鶯友，爲傳垂翅度春風。"]'),
('9ac26cbb-e57d-4df7-bd60-cf668ef47d4a','喜雪','李商隱','唐','唐诗','tang','','[]','朔雪自龍沙，呈祥勢可嘉。',120,'全唐诗/poet.tang.29000.json','["朔雪自龍沙，呈祥勢可嘉。", "有田皆種玉，無樹不開花。", "班扇慵裁素，曹衣詎比麻。", "鵝歸逸少宅，鶴滿令威家。", "寂寞門扉掩，依稀履跡斜。", "人疑遊麵市，馬似困鹽車。", "洛水妃虛妬，姑山客漫誇。", "聯辭雖許謝，和曲本慙巴。", "粉署闈全隔，霜臺路正賒。", "此時傾賀酒，相望在京華。"]'),
('17d156e0-7c71-4f1d-beb9-e6accf2ce7c0','柳枝五首 一','李商隱','唐','唐诗','tang','','[]','花房與蜜脾，蜂雄蛺蝶雌。',24,'全唐诗/poet.tang.29000.json','["花房與蜜脾，蜂雄蛺蝶雌。", "同時不同類，那復更相思。"]'),
('07022b01-e5ce-4d70-8cc3-d8e92cd40baf','柳枝五首 二','李商隱','唐','唐诗','tang','','[]','本是丁香樹，春條結始生。',24,'全唐诗/poet.tang.29000.json','["本是丁香樹，春條結始生。", "玉作彈碁局，中心亦不平。"]'),
('a48fb9c2-4bd6-4150-981d-245b904b758e','柳枝五首 三','李商隱','唐','唐诗','tang','','[]','嘉瓜引蔓長，碧玉冰寒漿。',24,'全唐诗/poet.tang.29000.json','["嘉瓜引蔓長，碧玉冰寒漿。", "東陵雖五色，不忍值牙香。"]'),
('b6e06bcb-8091-46f4-8a36-548bb55b54e7','柳枝五首 四','李商隱','唐','唐诗','tang','','[]','柳枝井上蟠，蓮葉浦中乾。',24,'全唐诗/poet.tang.29000.json','["柳枝井上蟠，蓮葉浦中乾。", "錦鱗與繡羽，水陸有傷殘。"]'),
('79caf113-8524-4f43-b128-5aa3a8a165dd','柳枝五首 五','李商隱','唐','唐诗','tang','','[]','畫屏繡步障，物物自成雙。',24,'全唐诗/poet.tang.29000.json','["畫屏繡步障，物物自成雙。", "如何湖上望，只是見鴛鴦。"]'),
('4a0df6ca-b050-4985-bfee-4bda09da6bc6','燕臺四首 春','李商隱','唐','唐诗','tang','','[]','風光冉冉東西陌，幾日嬌魂尋不得。',160,'全唐诗/poet.tang.29000.json','["風光冉冉東西陌，幾日嬌魂尋不得。", "蜜房羽客類芳心，冶葉倡條徧相識。", "暖藹輝遲桃樹西，高鬟立共桃鬟齊。", "雄龍雌鳳杳何許，絮亂絲繁天亦迷。", "醉起微陽若初曙，映簾夢斷聞殘語。", "愁將鐵網罥珊瑚，海闊天翻迷處所。", "衣帶無情有寬窄，春煙自碧秋霜白。", "研丹擘石天不知，願得天牢鎖冤魄。", "夾羅委篋單綃起，香肌冷襯琤琤珮。", "今日東風自不勝，化作幽光入西海。"]'),
('b5c254cc-0149-4bb9-89cb-d9146893714d','燕臺四首 夏','李商隱','唐','唐诗','tang','','["\u9ec4\u6cb3"]','前閣雨簾愁不卷，後堂芳樹陰陰見。',128,'全唐诗/poet.tang.29000.json','["前閣雨簾愁不卷，後堂芳樹陰陰見。", "石城景物類黃泉，夜半行郎空柘彈。", "綾扇喚風閶闔天，輕帷翠幕波淵旋。", "蜀魂寂寞有伴未，幾夜瘴花開木棉。", "桂宮留影光難取，嫣薰蘭破輕輕語。", "直教銀漢墮懷中，未遣星妃鎮來去。", "濁水清波何異源，濟河水清黃河渾。", "安得簿霧起緗裙，手接雲軿呼太君。"]'),
('31328cbe-0011-48e1-9f8f-892d2993df6b','燕臺四首 秋','李商隱','唐','唐诗','tang','','[]','月浪衝天天宇濕，涼蟾落盡疎星入。',160,'全唐诗/poet.tang.29000.json','["月浪衝天天宇濕，涼蟾落盡疎星入。", "雲屏不動掩孤嚬，西樓一夜風箏急。", "欲織相思花寄遠，終日相思却相怨。", "但聞北斗聲迴環，不見長河水清淺。", "金魚鎖斷紅桂春，古時塵滿鴛鴦茵。", "堪悲小苑作長道，玉樹未憐亡國人。", "瑤琴愔愔藏楚弄，越羅冷薄金泥重。", "簾鉤鸚鵡夜驚霜，喚起南雲繞雲夢。", "雙璫丁丁聯尺素，內記湘川相識處。", "歌唇一世銜雨看，可惜馨香手中故。"]'),
('491fe247-c00b-4f11-9e67-7db1c7d55b3c','燕臺四首 冬','李商隱','唐','唐诗','tang','','[]','天東日出天西下，雌鳳孤飛女龍寡。',128,'全唐诗/poet.tang.29000.json','["天東日出天西下，雌鳳孤飛女龍寡。", "青溪白石不相望，堂中遠甚蒼梧野。", "凍壁霜華交隱起，芳根中斷香心死。", "浪乘畫舸憶蟾蜍，月娥未必嬋娟子。", "楚管蠻絃愁一概，空城舞罷腰支在。", "當時歡向掌中銷，桃葉桃根雙姊妹。", "破鬟矮墮凌朝寒，白玉燕釵黃金蟬。", "風車雨馬不持去，蠟燭啼紅怨天曙。"]'),
('8979051e-dbab-4191-b4eb-da134a09f691','河內詩二首 一','李商隱','唐','唐诗','tang','','[]','鼉鼓沈沈虬水咽，秦絲不上蠻絃絕。',112,'全唐诗/poet.tang.29000.json','["鼉鼓沈沈虬水咽，秦絲不上蠻絃絕。", "常娥衣薄不禁寒，蟾蜍夜豔秋河月。", "碧城冷落空蒙煙，簾輕幕重金鉤欄。", "靈香不下兩皇子，孤星直上相風竿。", "八桂林邊九芝草，短襟小鬢相逢道。", "入門暗數一千春，願去閏年留月小。", "梔子交加香蓼繁，停辛佇苦留待君。"]'),
('d828e0d8-f37b-4835-9bf3-daf2294e4b45','河內詩二首 二','李商隱','唐','唐诗','tang','','[]','閶門日下吳歌遠，陂路綠菱香滿滿。',80,'全唐诗/poet.tang.29000.json','["閶門日下吳歌遠，陂路綠菱香滿滿。", "後溪暗起鯉魚風，船旗閃斷芙蓉幹。", "輕身奉君畏身輕，雙橈兩槳樽酒清。", "莫因風雨罷團扇，此曲斷腸惟北聲。", "低樓小徑城南道，猶自金鞍對芳草。"]'),
('74ad36fa-903a-4312-8a17-3d090b5a29e0','贈送前劉五經映三十四韻','李商隱','唐','唐诗','tang','','[]','建國宜師古，興邦屬上庠。',288,'全唐诗/poet.tang.29000.json','["建國宜師古，興邦屬上庠。", "從來以儒戲，安得振朝綱。", "叔世何多難，茲基遂已亡。", "泣麟猶委吏，歌鳳更佯狂。", "屋壁餘無幾，焚坑逮可傷。", "挾書秦二世，壤宅漢諸王。", "草草臨盟誓，區區務富強。", "微茫金馬署，狼籍鬬雞場。", "盡欲心無竅，皆如面正墻。", "驚疑豹文鼠，貪竊虎皮羊。", "南渡宜終否，西遷冀小康。", "策非方正士，貢絕孝廉郎。", "海鳥悲鐘鼓，狙公畏服裳。", "多岐空擾擾，幽室竟倀倀。", "凝邈爲時範，虛空作士常。", "何由羞五霸，直自呰三皇。", "別派驅楊墨，他鑣並老莊。", "詩書資破冢，法制困探囊。", "周禮仍存魯，隋師果禪唐。", "鼎新麾一舉，革故法三章。", "星宿森文雅，風雷起退藏。", "縲囚爲學切，掌故受經忙。", "夫子時之彥，先生跡未荒。", "褐衣終不召，白首興難忘。"]'),
('6767b044-44d9-46ee-b87b-33bfcb381ba0','哭遂州蕭侍郎二十四韻','李商隱','唐','唐诗','tang','','["\u957f\u6c5f"]','遙作時多難，先令禍有源。',288,'全唐诗/poet.tang.29000.json','["遙作時多難，先令禍有源。", "初驚逐客議，旋駭黨人冤。", "密侍榮方入，司刑望愈尊。", "皆因優詔用，實有諫書存。", "苦霧三辰沒，窮陰四塞昏。", "虎威狐更假，隼擊鳥踰喧。", "徒欲心存闕，終遭耳屬垣。", "遺音和蜀魄，易簀對巴猿。", "有女悲初寡，無男泣過門。", "朝爭屈原草，廟餒莫敖魂。", "迥閣傷神峻，長江極望翻。", "青雲寧寄意，白骨始霑恩。", "早歲思東閤，爲邦屬故園。", "登舟慚郭泰，解榻愧陳蕃。", "分以忘年契，情猶錫類敦。", "公先真帝子，我系本王孫。", "嘯傲張高蓋，從容接短轅。", "秋吟小山桂，春醉後堂萱。", "自歎離通籍，何嘗忘呌閽。", "不成穿壙入，終擬上書論。", "多士還魚貫，云誰正駿奔。", "暫能誅儵忽，長與問乾坤。", "蟻漏三泉路，螿啼百草根。", "始知同泰講，徼福是虛言。"]'),
('c89d8196-a13b-4f0c-9f5f-71652c0061e1','送千牛李將軍赴闕五十韻','李商隱','唐','唐诗','tang','','["\u9ec4\u5c71"]','照席瓊枝秀，當年紫綬榮。',288,'全唐诗/poet.tang.29000.json','["照席瓊枝秀，當年紫綬榮。", "班資古直閣，勳伐舊西京。", "在昔王綱紊，因誰國步清。", "如無一戰霸，安有大橫庚。", "內豎依憑切，凶門責望輕。", "中台終惡直，上將更要盟。", "丹陛祥煙滅，皇闈殺氣橫。", "喧闐衆狙怒，容易八蠻驚。", "梼杌寬之久，防風戮不行。", "素來矜異類，此去豈親征。", "捨魯真非策，居邠未有名。", "曾無力牧御，寧待雨師迎。", "火箭侵乘石，雲橋逼禁營。", "何時絕刁斗，不夜見欃槍。", "屢亦聞投鼠，誰其敢射鯨。", "世情休念亂，物議笑輕生。", "大鹵思龍躍，蒼梧失象耕。", "靈衣沾愧汗，儀馬困陰兵。", "別館蘭薰酷，深宮蠟燄明。", "黃山遮舞態，黑水斷歌聲。", "縱未移周鼎，何辭免趙坑。", "空拳轉鬬地，數板不沈城。", "且欲憑神算，無因計力爭。", "幽囚蘇武節，棄市仲由纓。"]'),
('727fc701-c7b8-48b8-89be-7759dc365062','詠懷寄秘閣舊僚二十六韻','李商隱','唐','唐诗','tang','','[]','年鬢日堪悲，衡茅益自嗤。',288,'全唐诗/poet.tang.29000.json','["年鬢日堪悲，衡茅益自嗤。", "攻文枯若木，處世鈍如鎚。", "敢忘垂堂戒，寧將暗室欺。", "懸頭曾苦學，折臂反成醫。", "僕御嫌夫懦，孩童笑叔癡。", "小男方嗜栗，幼女漫憂葵。", "遇炙誰先噉，逢韲即便吹。", "官銜同畫餅，面貎乏凝脂。", "典籍將蠡測，文章若管窺。", "圖形翻類狗，入夢肯非羆。", "自哂成書簏，終當呪酒巵。", "懶霑襟上血，羞鑷鏡中絲。", "槖籥言方喻，樗蒱齒詎知。", "事神徒惕慮，佞佛媿虛辭。", "曲藝垂麟角，浮名狀虎皮。", "乘軒寧見寵，巢幕更逢危。", "禮俗拘嵇喜，侯王忻戴逵。", "途窮方結舌，靜勝但搘頤。", "糲食空彈劒，亨衢詎置錐。", "栢臺成口號，芸閣暫肩隨。", "悔逐遷鸎伴，誰觀擇虱時。", "甕間眠太率，牀下隱何卑。", "奮跡登弘閣，摧心對董帷。", "校讎如有暇，松竹一相思。"]'),
('d1dbe123-eb3a-4d48-ba55-0a14d193f33e','戊辰會靜中出貽同志二十韻','李商隱','唐','唐诗','tang','','[]','大道諒無外，會越自登真。',240,'全唐诗/poet.tang.29000.json','["大道諒無外，會越自登真。", "丹元子何索，在己莫問隣。", "蒨璨玉琳華，翶翔九真君。", "戲擲萬里火，聊召六甲旬。", "瑤簡被靈誥，持符開七門。", "金鈴攝羣魔，絳節何兟兟。", "吟弄東海若，笑倚扶桑春。", "三山誠迥視，九州揚一塵。", "我本玄元胄，稟華由上津。", "中迷鬼道樂，沈爲下土民。", "託質屬太陰，鍊形復爲人。", "誓將覆宮澤，安此真與神。", "龜山有慰薦，南真爲彌綸。", "玉管會玄圃，火棗承天姻。", "科車遏故氣，侍香傳靈氛。", "飄颻被青霓，婀娜佩紫紋。", "林洞何其微，下仙不與羣。", "丹泥因未控，萬劫猶逡巡。", "荆蕪既以薙，舟壑永無湮。", "相期保妙命，騰景侍帝宸。"]'),
('af70c9da-8e36-44b4-aee0-4e73e87192e1','和鄭愚贈汝陽王孫家箏妓二十韻','李商隱','唐','唐诗','tang','','[]','冰霧怨何窮，秦絲嬌未已。',240,'全唐诗/poet.tang.29000.json','["冰霧怨何窮，秦絲嬌未已。", "寒空煙霞高，白日一萬里。", "碧嶂愁不行，濃翠遙相倚。", "茜袖捧瓊姿，皎日丹霞起。", "孤猿耿幽寂，西風吹白芷。", "回首蒼梧深，女蘿閉山鬼。", "荒郊白鱗斷，別浦晴霞委。", "長彴壓河心，白道連地尾。", "秦人昔富家，綠窗聞妙旨。", "鴻驚雁背飛，象牀殊故里。", "因令五十絲，中道分宮徵。", "斗粟配新聲，娣姪徒纖指。", "風流大堤上，悵望白門裏。", "蠹粉實雌絃，燈光冷如水。", "羌管促蠻柱，從醉吳宮耳。", "滿內不埽眉，君王對西子。", "初花慘朝露，冷臂淒愁髓。", "一曲送連錢，遠別長於死。", "玉砌銜紅蘭，粧窗結碧綺。", "九門十二關，清晨禁桃李。"]'),
('7fb0a5a6-b0c4-45eb-8d92-e8ea38463dd3','四年冬以退居蒲之永樂渴然有農夫望歲之志遂作憶雪又作殘雪詩各一百言以寄情於游舊 憶雪','李商隱','唐','唐诗','tang','','[]','愛景人方樂，同雲候稍愆。',120,'全唐诗/poet.tang.29000.json','["愛景人方樂，同雲候稍愆。", "徒聞周雅什，願賦朔風篇。", "欲俟千箱慶，須資六出妍。", "詠留飛絮後，歌唱落梅前。", "庭樹思瓊蕊，粧樓認粉綿。", "瑞邀盈尺日，豐待兩岐年。", "預約延枚酒，虛乘訪戴船。", "映書孤志業，披氅阻神仙。", "幾向霜階步，頻將月幌褰。", "玉京應已足，白屋但顒然。"]'),
('879b7153-c37a-420f-82e7-9f863d1ce365','四年冬以退居蒲之永樂渴然有農夫望歲之志遂作憶雪又作殘雪詩各一百言以寄情於游舊 殘雪','李商隱','唐','唐诗','tang','','[]','旭日開晴色，寒空失素塵。',120,'全唐诗/poet.tang.29000.json','["旭日開晴色，寒空失素塵。", "遶墻全剝粉，傍井漸消銀。", "刻獸摧鹽虎，爲山倒玉人。", "珠還猶照魏，璧碎尚留秦。", "落日驚侵畫，餘光悞惜春。", "簷冰滴鵝管，屋瓦鏤魚鱗。", "嶺霽嵐光坼，松暄翠粒新。", "擁林愁拂盡，著砌恐行頻。", "焦寢忻無患，梁園去有因。", "莫能知帝力，空此荷平均。"]'),
('eb89bf00-4f43-4dfa-96a3-899b19931b80','大鹵平後移家到永樂縣居書懷十韻寄劉韋二前輩二公嘗於此縣寄居','李商隱','唐','唐诗','tang','','[]','驅馬遶河干，家山照露寒。',120,'全唐诗/poet.tang.29000.json','["驅馬遶河干，家山照露寒。", "依然五柳在，況值百花殘。", "昔去驚投筆，今來分挂冠。", "不憂懸磬乏，乍喜覆盂安。", "甑破寧迴顧，舟沈豈暇看。", "脫身離虎口，移疾就猪肝。", "鬢入新年白，顏無舊日丹。", "自悲秋穫少，谁懼夏畦難。", "逸志忘鴻鵠，清香披蕙蘭。", "還持一杯酒，坐想二公懽。"]'),
('dda04956-3b08-44a5-af05-d4b170ce445f','河陽詩','李商隱','唐','唐诗','tang','','["\u9ec4\u6cb3"]','黃河搖溶天上來，玉樓影近中天臺。',288,'全唐诗/poet.tang.29000.json','["黃河搖溶天上來，玉樓影近中天臺。", "龍頭瀉酒客壽杯，主人淺笶紅玫瑰。", "梓澤東來七十里，長溝複塹埋雲子。", "可惜秋眸一臠光，漢陵走馬黃塵起。", "南浦老魚腥古涎，真珠密字芙蓉篇。", "湘中寄到夢不到，衰容自去拋涼天。", "憶得蛟絲裁小卓，蛺蝶飛迴木綿薄。", "綠繍笙囊不見人，一口紅霞夜深嚼。", "幽蘭泣露新香死，畫圖淺縹松溪水。", "楚絲微覺竹枝高，半曲新辭寫緜紙。", "巴西夜市紅守宮，後房點臂斑斑紅。", "堤南渴雁自飛久，蘆花一夜吹西風。", "曉簾串斷蜻蜓翼，羅屏但有空青色。", "玉灣不釣三千年，蓮房暗被蛟龍惜。", "濕銀注鏡井口平，鸞釵映月寒錚錚。", "不知桂樹在何處，仙人不下雙金莖。", "百尺相風插重屋，側近嫣紅伴柔綠。", "百勞不識對月郎，湘竹千條爲一束。"]'),
('8511f2ce-c150-4948-ad49-ad6e8ac118ff','自桂林奉使江陵途中感懷寄獻尚書','李商隱','唐','唐诗','tang','','[]','下客依蓮幕，明公念竹林。',288,'全唐诗/poet.tang.29000.json','["下客依蓮幕，明公念竹林。", "縱然膺使命，何以奉徽音。", "投刺雖傷晚，酬恩豈在今。", "迎來新瑣闥，從到碧瑤岑。", "水勢初知海，天文始識參。", "固慚非賈誼，惟恐後陳琳。", "前席驚虛辱，華樽許細斟。", "尚憐秦痔苦，不遣楚醪沈。", "既載從戎筆，仍披選勝襟。", "瀧通伏波柱，簾對有虞琴。", "宅與嚴城接，門藏別岫深。", "閣涼松冉冉，堂靜桂森森。", "社內容周續，鄉中保展禽。", "白衣居士訪，烏帽逸人尋。", "佞佛將成傳，耽書或類淫。", "長懷五羖贖，終著九州箴。", "良訊封鴛綺，餘光借玳簪。", "張衡愁浩浩，沈約瘦愔愔。", "蘆白疑粘鬢，楓丹欲照心。", "歸期無雁報，旅抱有猿侵。", "短日安能駐，低雲只有陰。", "亂鴉衝曬網，寒女簇遙砧。", "東道違寧久，西園望不禁。", "江生魂黯黯，泉客淚涔涔。"]'),
('3d0605f6-b831-4ddf-a00e-18a0f7380ddd','送從翁從東川弘農尚書幕','李商隱','唐','唐诗','tang','','[]','大鎮初更帥，嘉賓素見邀。',288,'全唐诗/poet.tang.29000.json','["大鎮初更帥，嘉賓素見邀。", "使車無遠近，歸路更煙霄。", "穩放驊騮步，高安翡翠巢。", "御風知有在，去國肯無聊。", "早忝諸孫末，俱從小隱招。", "心懸紫雲閣，夢斷赤城標。", "素女悲清瑟，秦娥弄玉簫。", "山連玄圃近，水接絳河遙。", "豈意聞周鐸，翻然慕舜韶。", "皆辭喬木去，遠逐斷蓬飄。", "薄俗誰其激，斯民已甚恌。", "鸞皇期一舉，燕雀不相饒。", "敢共頽波遠，因之內火燒。", "是非過別夢，時節慘驚飙。", "未至誰能賦，中乾欲病痟。", "屢曾紆錦繍，勉欲報瓊瑤。", "我恐霜侵鬢，君先綬挂腰。", "甘心與陳阮，揮手謝松喬。", "錦里差隣接，雲臺閉寂寥。", "一川虛月魄，萬崦自芝苗。", "瘴雨瀧間急，離魂峽外銷。", "非關無燭夜，其奈落花朝。", "幾處逢鳴佩，何筵不翠翹。", "蠻童騎象舞，江市賣鮫綃。"]'),
('733f6c2e-04a1-4935-9054-01ae4e03220c','李肱所遺畫松詩書兩紙得四十韻','李商隱','唐','唐诗','tang','','[]','萬草已涼露，開圖披古松。',288,'全唐诗/poet.tang.29000.json','["萬草已涼露，開圖披古松。", "青山徧滄海，此樹生何峰。", "孤根邈無倚，直立撐鴻濛。", "端如君子身，挺若壯士胸。", "樛枝勢夭矯，忽欲蟠拏空。", "又如驚螭走，默與奔雲逢。", "孫枝擢細葉，旖旎狐裘茸。", "鄒颠蓐髪軟，麗姬眉黛濃。", "視久眩目睛，倏忽變輝容。", "竦削正稠直，婀娜旋敷峰。", "又如洞房冷，翠被張穹籠。", "亦若暨羅女，平旦妝顏容。", "細疑襲氣母，猛若爭神功。", "燕雀固寂寂，霧露常衝衝。", "香蘭媿傷暮，碧竹慚空中。", "可集呈瑞鳳，堪藏行雨龍。", "淮山桂偃蹇，蜀郡桑重童。", "枝條亮眇脆，靈氣何由同。", "昔聞咸陽帝，近說稽山儂。", "或著仙人號，或以大夫封。", "終南與清都，煙雨遙相通。", "安知夜夜意，不起西南風。", "美人昔清興，重之猶月鐘。", "寶笥十八九，香緹千萬重。"]'),
('b52c24db-89d8-423c-aa49-b665a8b41141','戲題樞言草閣三十二韻','李商隱','唐','唐诗','tang','','[]','君家在河北，我家在山西。',288,'全唐诗/poet.tang.29000.json','["君家在河北，我家在山西。", "百歲本無業，陰陰仙李枝。", "尚書文與武，戰罷幕府開。", "君從渭南至，我自仙遊來。", "平昔苦南北，動成雲雨乖。", "逮今兩攜手，對若牀下鞵。", "夜歸碣石館，朝上黃金臺。", "我有苦寒調，君抱陽春才。", "年顏各少壯，髪綠齒尚齊。", "我雖不能飲，君時醉如泥。", "政靜籌畫簡，退食多相攜。", "埽掠走馬路，整頓射雉翳。", "春風二三月，柳密鶯正啼。", "清河在門外，上與浮雲齊。", "欹冠調玉琴，彈作松風哀。", "又彈明君怨，一去怨不回。", "感激坐者泣，起視雁行低。", "翻憂龍山雪，却雜胡沙飛。", "仲容銅琵琶，項直聲淒淒。", "上貼金捍撥，畫爲承露雞。", "君時臥掁觸，勸客白玉盃。", "苦云年光疾，不飲將安歸。", "我賞此言是，因循未能諧。", "君言中聖人，坐臥莫我違。"]'),
('a153607f-10f7-41ab-ba80-88ed17e9d728','偶成轉韻七十二句贈四同舍','李商隱','唐','唐诗','tang','','[]','沛國東風吹大澤，蒲青柳碧春一色。',384,'全唐诗/poet.tang.29000.json','["沛國東風吹大澤，蒲青柳碧春一色。", "我來不見隆準人，瀝酒空餘廟中客。", "征東同舍鴛與鸞，酒酣勸我懸征鞍。", "藍山寶肆不可入，玉中仍是青琅玕。", "武威將軍使中俠，少年箭道驚楊葉。", "戰功高後數文章，憐我秋齋夢蝴蝶。", "詰旦九門傳奏章，高車大馬來煌煌。", "路逢鄒枚不暇揖，臘月大雪過大梁。", "憶昔公爲會昌宰，我時入謁虛懷待。", "衆中賞我賦高唐，迴看屈宋由年輩。", "公事武皇爲鐵冠，歷廳請我相所難。", "我時顦顇在書閣，臥枕芸香春夜闌。", "明年赴辟下昭桂，東郊慟哭辭兄弟。", "韓公堆上跋馬時，廻望秦川樹如薺。", "依稀南指陽臺雲，鯉魚食鈎猿失羣。", "湘妃廟下已春盡，虞帝城前初日曛。", "謝遊橋上澄江館，下望山城如一彈。", "鷓鴣聲苦曉驚眠，朱槿花嬌晚相伴。", "頃之失職辭南風，破帆壞槳荆江中。", "斬蛟斷璧不無意，平生自許非忩忩。", "歸來寂寞靈臺下，著破藍衫出無馬。", "天官補吏府中趨，玉骨瘦來無一把。", "手封狴牢屯制囚，直廳印鎖黃昏愁。", "平明赤帖使修表，上賀嫖姚收賊州。"]'),
('ceb373e9-4d4e-48f0-8dac-43a20d12466e','五言述德抒情詩一首四十韻獻上杜七兄僕射相公','李商隱','唐','唐诗','tang','','[]','帝作黃金闕，仙開白玉京。',288,'全唐诗/poet.tang.29000.json','["帝作黃金闕，仙開白玉京。", "有人扶太極，惟嶽降元精。", "耿賈官勳大，荀陳地望清。", "旂常懸祖德，甲令著嘉聲。", "經出宣尼壁，書留晏子楹。", "武鄉傳陳法，踐土主文盟。", "自昔流王澤，由來仗國楨。", "九河分合沓，一柱忽崢嶸。", "得主勞三顧，驚人肯再鳴。", "碧虛天共轉，黃道日同行。", "後飲曹參酒，先和傅說羹。", "即時賢路闢，此夜泰階平。", "願保無疆福，將圖不朽名。", "率身期濟世，叩額慮興兵。", "感念殽屍露，咨嗟趙卒坑。", "儻令安隱忍，何以贊貞明。", "惡草雖當路，寒松實挺生。", "人言真可畏，公意本無爭。", "故事留臺閣，前驅且斾旌。", "芙蓉王儉府，楊柳亞夫營。", "清嘯頻疎俗，高談屢析酲。", "過庭多令子，乞墅有名甥。", "南詔應聞命，西山莫敢驚。", "寄辭收的博，端坐掃欃槍。"]'),
('90bb2eb8-0a59-43e9-9d1c-b29f382d3aaf','今月二日不自量度輒以詩一首四十韻干凟尊嚴伏蒙仁恩俯賜披覽獎踰其實情溢於辭顧惟疎蕪曷用酬戴輒復五言四十韻詩獻上亦詩人詠嘆不足之義也','李商隱','唐','唐诗','tang','','[]','家擅無雙譽，朝居第一功。',288,'全唐诗/poet.tang.29000.json','["家擅無雙譽，朝居第一功。", "四時當首夏，八節應條風。", "滌濯臨清濟，巉巖倚碧嵩。", "鮑壺冰皎潔，王佩玉丁東。", "處劇張京兆，通經戴侍中。", "將星臨迥夜，卿月麗層穹。", "下令銷秦盜，高談破宋聾。", "含霜太山竹，拂霧嶧陽桐。", "樂道乾知退，當官蹇匪躬。", "服箱青海馬，入兆渭川熊。", "固是符真宰，徒勞讓化工。", "鳳池春瀲豔，雞樹曉曈曨。", "願守三章約，還期九譯通。", "薰琴調大舜，寶瑟和神農。", "慷慨資元老，周旋值狡童。", "仲尼羞問陣，魏絳喜和戎。", "欵欵將除蠧，孜孜欲達聰。", "所求因渭濁，安肯與雷同。", "物議將調鼎，君恩忽賜弓。", "開吳相上下，全蜀占西東。", "銳卒魚懸餌，豪胥鳥在籠。", "疲民呼杜母，隣國仰羊公。", "置驛推東道，安禪合北宗。", "嘉賓增重價，上士悟真空。"]'),
('1e21d335-a523-4b60-b2d4-6d198f86c88d','驕兒詩','李商隱','唐','唐诗','tang','','[]','衮師我驕兒，美秀乃無匹。',290,'全唐诗/poet.tang.29000.json','["衮師我驕兒，美秀乃無匹。", "文葆未周晬，固已知六七。", "四歲知名姓，眼不視棃栗。", "交朋頗窺觀，謂是丹穴物。", "前朝尚器貌，流品方第一。", "不然神仙姿，不爾燕鶴骨。", "安得此相謂，欲慰衰朽質。", "青春妍和月，朋戲渾甥姪。", "繞堂復穿林，沸若金鼎溢。", "門有長者來，造次請先出。", "客前問所須，含意下吐實。", "歸來學客面，䦱敗秉爺笏。", "或謔張飛胡，或笑鄧艾吃。", "豪鷹毛崱屴，猛馬氣佶傈。", "截得青篔簹，騎走恣唐突。", "忽復學參軍，按聲喚蒼鶻。", "又復紗燈旁，稽首禮夜佛。", "仰鞭罥蛛網，俯首飲花蜜。", "欲爭蛺蝶輕，未謝柳絮疾。", "階前逢阿姊，六甲頗輸失。", "凝走弄香奩，拔脫金屈[戌]。", "抱持多反側，威怒不可律。", "曲躬牽牕網，衉唾拭琴漆。", "有時看臨書，挺立不動膝。"]'),
('21ba27c8-91e7-4d58-b85a-99cd049552a8','行次西郊作一百韻','李商隱','唐','唐诗','tang','','[]','蛇年建午月，我自梁還秦。',288,'全唐诗/poet.tang.29000.json','["蛇年建午月，我自梁還秦。", "南下大散關，北濟渭之濱。", "草木半舒坼，不類冰雪晨。", "又若夏苦熱，燋卷無芳津。", "高田長檞櫪，下田長荆榛。", "農具棄道旁，饑牛死空墩。", "依依過村落，十室無一存。", "存者皆面啼，無衣可迎賓。", "始若畏人問，及門還具陳。", "右輔田疇薄，斯民常苦貧。", "伊昔稱樂土，所賴牧伯仁。", "官清若冰玉，吏善如六親。", "生兒不遠征，生女事四隣。", "濁酒盈瓦缶，爛穀堆荆囷。", "健兒庇旁婦，衰翁舐童孫。", "況自貞觀後，命官多儒臣。", "例以賢牧伯，徵人司陶鈞。", "降及開元中，姦邪撓經綸。", "晉公忌此事，多録邊將勳。", "因令猛毅輩，雜牧升平民。", "中原遂多故，除授非至尊。", "或出倖臣輩，或由帝戚恩。", "中原困屠解，奴隸厭肥豚。", "皇子棄不乳，椒房抱羌渾。"]'),
('dac05039-922b-4847-85d5-2fc051753b30','井泥四十韻','李商隱','唐','唐诗','tang','','[]','皇都依仁里，西北有高齋。',288,'全唐诗/poet.tang.29000.json','["皇都依仁里，西北有高齋。", "昨日主人氏，治井堂西陲。", "工人三五輩，輦出土與泥。", "到水不數尺，積共庭樹齊。", "他日井甃畢，用土益作堤。", "曲隨林掩映，繚以池周迴。", "下去冥寞穴，上承雨露滋。", "寄辭別地脉，因言謝泉扉。", "升騰不自意，疇昔忽已乖。", "伊余掉行鞅，行行來自西。", "一日下馬到，此時芳草萋。", "四面多好樹，旦暮雲霞姿。", "晚落花滿地，幽鳥鳴何枝。", "蘿幄既已薦，山樽亦可開。", "待得孤月上，如與佳人來。", "因茲感物理，惻愴平生懷。", "茫茫此羣品，不定輪與蹄。", "喜得舜可禪，不以瞽瞍疑。", "禹竟代舜立，其父吁咈哉。", "嬴氏幷六合，所來因不韋。", "漢祖把左契，自言一布衣。", "當塗佩國璽，本乃黃門攜。", "長戟亂中原，何妨起戎氐。", "不獨帝王耳，臣下亦如斯。"]'),
('cd263b00-f520-4266-8d16-5e0e19d8160d','夜思','李商隱','唐','唐诗','tang','','[]','銀箭耿寒漏，金釭凝夜光。',120,'全唐诗/poet.tang.29000.json','["銀箭耿寒漏，金釭凝夜光。", "綵鸞空自舞，別燕不相將。", "寄恨一尺素，含情雙玉璫。", "會前猶月在，去後始宵長。", "往事經春物，前期託報章。", "永令虛粲枕，長不掩蘭房。", "覺動迎猜影，疑來浪認香。", "鶴應聞露警，蜂亦爲花忙。", "古有陽臺夢，今多下蔡倡。", "何爲薄冰雪，消瘦滯非鄉。"]'),
('b33f8ef9-fbf0-492f-8437-88ed7d4b5e44','思賢頓','李商隱','唐','唐诗','tang','','[]','內殿張弦管，中原絕鼓鼙。',48,'全唐诗/poet.tang.29000.json','["內殿張弦管，中原絕鼓鼙。", "舞成青海馬，鬬殺汝南雞。", "不見華胥夢，空聞下蔡迷。", "宸襟他日淚，薄暮望賢西。"]'),
('5dffd98b-0cfe-4376-9ece-658a111877a7','無題','李商隱','唐','唐诗','tang','','[]','萬里風波一葉舟，憶歸初罷更夷猶。',64,'全唐诗/poet.tang.29000.json','["萬里風波一葉舟，憶歸初罷更夷猶。", "碧江地沒元相引，黃鶴沙邊亦少留。", "益德冤魂終報主，阿童高義鎮橫秋。", "人生豈得長無謂，懷古思鄉共白頭。"]'),
('9b2e28da-a8d4-4f75-9d5d-b3a3beddb628','有懷在蒙飛卿','李商隱','唐','唐诗','tang','','[]','薄宦頻移疾，當年久索居。',48,'全唐诗/poet.tang.29000.json','["薄宦頻移疾，當年久索居。", "哀同庚開府，瘦極沈尚書。", "城綠新陰遠，江清返照虛。", "所思惟翰墨，從古待雙魚。"]'),
('be4f0808-2ef3-4917-a41c-e78808ed69f6','春深脫衣','李商隱','唐','唐诗','tang','','[]','睥睨江鴉集，堂皇海燕過。',48,'全唐诗/poet.tang.29000.json','["睥睨江鴉集，堂皇海燕過。", "減衣憐蕙若，展帳動煙波。", "日烈憂花甚，風長奈柳何。", "陳遵容易學，身世醉時多。"]'),
('f32f5a08-5e49-4772-a0fa-3a674e74d406','懷求古翁','李商隱','唐','唐诗','tang','','[]','何時粉署仙，傲兀逐戎旃。',48,'全唐诗/poet.tang.29000.json','["何時粉署仙，傲兀逐戎旃。", "關塞猶傳箭，江湖莫繫船。", "欲收棊子醉，竟把釣車眠。", "謝朓真堪憶，多才不忌前。"]'),
('431a83cf-ac5f-4faf-8e21-ef3e486e69e2','五月六日夜憶往歲秋與徹師同宿','李商隱','唐','唐诗','tang','','[]','紫閣相逢處，丹巖議宿時。',48,'全唐诗/poet.tang.29000.json','["紫閣相逢處，丹巖議宿時。", "墮蟬翻敗葉，棲鳥定寒枝。", "萬里飄流遠，三年問訊遲。", "炎方憶初地，頻夢碧琉璃。"]'),
('dcd807c4-684b-47c2-b53e-e5e3f394ec0f','城上','李商隱','唐','唐诗','tang','','[]','有客虛投筆，無憀獨上城。',48,'全唐诗/poet.tang.29000.json','["有客虛投筆，無憀獨上城。", "沙禽失侶遠，江樹著陰輕。", "邊遽稽天討，軍須竭地征。", "賈生游刃極，作賦又論兵。"]'),
('05ee948c-da09-4249-8e0d-669cad8206c0','如有','李商隱','唐','唐诗','tang','','[]','如有瑤臺客，相難復索歸。',48,'全唐诗/poet.tang.29000.json','["如有瑤臺客，相難復索歸。", "芭蕉開綠扇，菡萏薦紅衣。", "浦外傳光遠，煙中結響微。", "良宵一寸焰，回首是重幃。"]'),
('5a7b2dae-0164-4177-8bcc-c648dc17f470','朱槿花二首 一','李商隱','唐','唐诗','tang','','[]','蓮後紅何患，梅先白莫誇。',48,'全唐诗/poet.tang.29000.json','["蓮後紅何患，梅先白莫誇。", "纔飛建章火，又落赤城霞。", "不卷錦步障，未登油壁車。", "日西相對罷，休澣向天涯。"]'),
('d792bdc2-3729-4337-9adb-c0a6cabaf833','朱槿花二首 二','李商隱','唐','唐诗','tang','','[]','勇多侵路去，恨有礙燈還。',48,'全唐诗/poet.tang.29000.json','["勇多侵路去，恨有礙燈還。", "嗅自微微白，看成沓沓殷。", "坐疑忘物外，歸去有簾間。", "君問傷春句，千辭不可刪。"]'),
('caa83495-341c-4eb8-82b1-a4b52710d331','寓懷','李商隱','唐','唐诗','tang','','[]','綵鸞餐顥氣，威鳳入卿雲。',144,'全唐诗/poet.tang.29000.json','["綵鸞餐顥氣，威鳳入卿雲。", "長養三清境，追隨五帝君。", "煙波遺汲汲，矰繳任云云。", "下界圍黃道，前程合紫氛。", "金書惟是見，玉管不勝聞。", "草爲迴生種，香緣却死熏。", "海明三島見，天迥九江分。", "搴樹無勞援，神禾豈用耘。", "鬬龍風結陣，惱鶴露成文。", "漢嶺霜何早，秦宮日易曛。", "星機拋密緒，月杵散靈氛。", "陽鳥西南下，相思不及羣。"]'),
('86b5e021-5de9-4133-8e51-f36db9874431','木蘭','李商隱','唐','唐诗','tang','','[]','二月二十二，木蘭開坼初。',96,'全唐诗/poet.tang.29000.json','["二月二十二，木蘭開坼初。", "初當新病酒，復自久離居。", "愁絕更傾國，驚新聞遠書。", "紫絲何日障，油壁幾時車。", "弄粉知傷重，調紅或有餘。", "波痕空映襪，煙態不勝裾。", "桂嶺含芳遠，蓮塘屬意疎。", "瑤姬與神女，長短定何如。"]'),
('59643cd3-cf82-453a-a932-cf793f8dc196','細雨成詠獻尚書河東公','李商隱','唐','唐诗','tang','','[]','灑砌聽來響，卷簾看已迷。',96,'全唐诗/poet.tang.29000.json','["灑砌聽來響，卷簾看已迷。", "江間風暫定，雲外日應西。", "稍稍落蝶粉，班班融燕泥。", "颭萍初過沼，重柳更緣堤。", "必擬和殘漏，寧無晦暝鼙。", "半將花漠漠，全共草萋萋。", "猿別方長嘯，鳥驚始獨棲。", "府公能八詠，聊且續新題。"]'),
('622626e1-e3ff-4450-b14a-cb5ead3f5954','病中聞河東公樂營置酒口占寄上','李商隱','唐','唐诗','tang','','[]','聞駐行春斾，中途賞物華。',144,'全唐诗/poet.tang.29000.json','["聞駐行春斾，中途賞物華。", "緣憂武昌柳，遂憶洛陽花。", "嵇鶴元無對，荀龍不在誇。", "只將滄海月，長壓赤城霞。", "興欲傾燕館，歡終到習家。", "風長應側帽，路隘豈容車。", "樓迥波窺錦，窗虛日弄紗。", "鎖門金了鳥，展障玉鴉叉。", "舞妙從兼楚，歌能莫雜巴。", "必投潘岳果，誰摻禰衡撾。", "刻燭當時忝，傳杯此夕賒。", "可憐漳浦臥，愁緒獨如麻。"]'),
('24bec9f3-8073-4343-a5d1-37781d4c3aad','回中牡丹爲雨所敗二首 一','李商隱','唐','唐诗','tang','','[]','下苑他年未可追，西州今日忽相期。',64,'全唐诗/poet.tang.29000.json','["下苑他年未可追，西州今日忽相期。", "水亭暮雨寒猶在，羅薦春香暖不知。", "舞蝶殷勤收落蘂，佳人惆悵臥遙帷。", "章臺街裏芳菲伴，且問宮腰損幾枝。"]'),
('8e04b3e9-ca54-4939-abb4-acf10c3e8ea6','回中牡丹爲雨所敗二首 二','李商隱','唐','唐诗','tang','','[]','浪笑榴花不及春，先期零落更愁人。',64,'全唐诗/poet.tang.29000.json','["浪笑榴花不及春，先期零落更愁人。", "玉盤迸淚傷心數，錦瑟驚絃破夢頻。", "萬里重陰非舊圃，一年生意屬流塵。", "前溪舞罷君迴顧，併覺今朝粉態新。"]'),
('38a7e5bf-e4f3-49b5-a134-9d59c4451f50','擬意','李商隱','唐','唐诗','tang','','[]','悵望逢張女，遲迴送阿侯。',288,'全唐诗/poet.tang.29000.json','["悵望逢張女，遲迴送阿侯。", "空看小垂手，忍問大刀頭。", "妙選茱萸帳，平居翡翠樓。", "雲屏不取暖，月扇未遮羞。", "上掌真何有，傾城豈自由。", "楚妃交薦枕，漢后共藏𩰘。", "夫向羊車覓，男從鳳穴求。", "書成祓禊帖，唱殺畔牢愁。", "夜杵鳴江練，春刀解若榴。", "象牀穿幰網，犀帖釘窗油。", "仁壽遺明鏡，陳倉拂綵毬。", "真防舞如意，佯蓋臥箜篌。", "濯錦桃花水，濺裙杜若洲。", "魚兒懸寶劒，燕子合金甌。", "銀箭催搖落，華筵慘去留。", "幾時銷薄怒，從此抱離憂。", "帆落啼猿峽，樽開畫鷁舟。", "急絃腸對斷，翦蠟淚爭流。", "璧馬誰能帶，金蟲不復收。", "銀河撲醉眼，珠串咽歌喉。", "去夢隨川后，來風貯石郵。", "蘭叢銜露重，榆莢點星稠。", "解佩無遺迹，凌波有舊游。", "曾來十九首，私讖詠牽牛。"]'),
('ea04b546-f35e-4b21-a63d-052a966af2fd','謝往桂林至彤庭竊詠','李商隱','唐','唐诗','tang','','[]','辰象森羅正，句陳翊衛寬。',120,'全唐诗/poet.tang.29000.json','["辰象森羅正，句陳翊衛寬。", "魚龍排百戲，劍佩儼千官。", "城禁將開晚，宮深欲曙難。", "月輸移枍詣，仙路下欄干。", "共賀高禖應，將陳壽酒歡。", "金星壓芒角，銀漢轉波瀾。", "王母來空闊，羲和上屈盤。", "鳳皇傳詔旨，獬廌冠朝端。", "造化中台座，威風上將壇。", "甘泉猶望幸，早晚冠呼韓。"]'),
('f7fcd168-6de6-45a1-a1a4-e11d7ff5a345','燒香曲','李商隱','唐','唐诗','tang','','[]','鈿雲蟠蟠牙比魚，孔雀翅尾蛟龍鬚。',144,'全唐诗/poet.tang.29000.json','["鈿雲蟠蟠牙比魚，孔雀翅尾蛟龍鬚。", "漳宮舊樣博山鑪，楚嬌捧笑開芙蕖。", "八蠶繭緜小分炷，獸燄微紅隔雲母。", "白天月澤寒未冰，金虎含秋向東吐。", "玉佩呵光銅照昏，簾波日暮衝斜門。", "西來欲上茂陵樹，柏梁已失栽桃魂。", "露庭月井大紅氣，輕衫薄細當君意。", "蜀殿瓊人伴夜深，金鑾不問殘燈事。", "何當巧吹君懷度，襟灰爲土填清露。"]'),
('f3ae2b00-1de4-4748-a751-7db2bd520450','送從翁東川弘農尚書幕','李商隱','唐','唐诗','tang','','["\u9ec4\u5c71"]','昔帝迴沖眷，維皇惻上仁。',288,'全唐诗/poet.tang.29000.json','["昔帝迴沖眷，維皇惻上仁。", "三靈迷赤氣，萬彙呌蒼旻。", "刊木方隆禹，陞陑始創殷。", "夏臺曾圮閉，汜水敢逡巡。", "拯溺休規步，防虞要徙薪。", "蒸黎今得請，宇宙昨還淳。", "纘祖功宜急，貽孫計甚勤。", "降災雖代有，稔惡不無因。", "宮掖方爲蠱，邊隅忽遘迍。", "獻書秦逐客，間諜漢名臣。", "北伐將誰使，南征決此辰。", "中原重板蕩，玄象失鉤陳。", "詰旦違清道，銜枚別紫宸。", "茲行殊厭勝，故老遂分新。", "去異封於鞏，來寧避處豳。", "永嘉幾失墜，宣政遽酸辛。", "元子當傳啓，皇孫合授詢。", "時非三揖讓，表請再陶鈞。", "舊好盟還在，中樞策屢遵。", "蒼黃傳國璽，違遠屬車塵。", "雛虎如憑怒，漦龍性漫馴。", "封崇自何等，流落乃斯民。", "逗撓官軍亂，優容敗將頻。", "早朝披草莽，夜縋達絲綸。"]'),
('b731f233-722f-407b-8754-6a8d84575a04','晉昌晚歸馬上贈','李商隱','唐','唐诗','tang','','[]','西北朝天路，登臨思上才。',48,'全唐诗/poet.tang.29000.json','["西北朝天路，登臨思上才。", "城閑煙草遍，村暗雨雲回。", "人豈無端別，猨應有意哀。", "征南予更遠，吟斷望鄉臺。"]'),
('5f9dce4c-57b9-4431-92a2-47166fc5a016','哭虔州楊侍郎','李商隱','唐','唐诗','tang','','[]','漢網疎仍漏，齊民困未蘇。',168,'全唐诗/poet.tang.29000.json','["漢網疎仍漏，齊民困未蘇。", "如何大丞相，翻作弛刑徒。", "中憲方外易，尹京終就拘。", "本矜能弭謗，先議取非辜。", "巧有凝脂密，功無一柱扶。", "深知獄吏貴，幾迫季冬誅。", "呌帝青天闊，辭家白日晡。", "流亡誠不弔，神理若爲誣。", "在昔恩知忝，諸生禮秩殊。", "入韓非劒客，過趙受鉗奴。", "楚水招魂遠，邙山卜宅孤。", "甘心親垤蟻，旋踵戮城狐。", "陰騭今如此，天災未可無。", "莫憑牲玉請，便望救焦枯。"]'),
('0eb698f4-f471-40fb-91b9-de88d62e4b26','寄太原盧司空三十韻','李商隱','唐','唐诗','tang','','[]','隋艦臨淮甸，唐旗出井陘。',288,'全唐诗/poet.tang.29000.json','["隋艦臨淮甸，唐旗出井陘。", "斷鰲搘四柱，卓馬濟三靈。", "祖業隆盤古，孫謀復大庭。", "從來師俊傑，可以煥丹青。", "舊族開東岳，雄圖奮北溟。", "邪同獬廌觸，樂伴鳳凰聽。", "酣戰仍揮日，降妖亦鬬霆。", "將軍功不伐，叔舅德惟馨。", "雞塞誰生事，狼煙不暫停。", "擬填滄海鳥，敢競太陽螢。", "內草纔傳詔，前茅已勒銘。", "那勞出師表，盡入大荒經。", "德水縈長帶，陰山繞畫屏。", "秖憂非綮肯，未覺有膻腥。", "保佐資沖漠，扶持在杳冥。", "乃心防暗室，華髪稱明廷。", "按甲神初靜，揮戈思欲醒。", "羲之當妙選，孝若近歸寧。", "月色來侵幌，詩成有轉櫺。", "羅含黃菊宅，柳惲白蘋汀。", "神物龜酬孔，僊才鶴姓丁。", "西山童子藥，南極老人星。", "自頃徒窺管，於今媿挈瓶。", "何由叨末席，還得叩玄扃。"]'),
('410b6c68-3226-47ea-a83c-c93f648d5213','安平公詩','李商隱','唐','唐诗','tang','','["\u6cf0\u5c71", "\u9ec4\u6cb3"]','丈人博陵王名家，憐我總角稱才華。',384,'全唐诗/poet.tang.29000.json','["丈人博陵王名家，憐我總角稱才華。", "華州留語曉至暮，高聲喝吏放兩衙。", "明朝騎馬出城外，送我習業南山阿。", "仲子延岳年十六，面如白玉欹烏紗。", "其弟炳章猶兩丱，瑤林瓊樹含奇花。", "陳留阮家諸侄秀，邐迤出拜何駢羅。", "府中從事杜與李，麟角虎翅相過摩。", "清詞孤韻有歌響，擊觸鐘磬鳴環珂。", "三月石堤凍銷釋，東風開花滿陽坡。", "時禽得伴戲新木，其聲尖咽如鳴梭。", "公時載酒領從事，踴躍鞍馬來相過。", "仰看樓殿撮清漢，坐視世界如恒沙。", "面熱脚掉互登陟，青雲表柱白雲崖。", "一百八句在貝葉，三十三天長雨花。", "長者子來輒獻蓋，辟支佛去空留鞾。", "公時受詔鎮東魯，遣我草詔隨車牙。", "顧我下筆即千字，疑我讀書傾五車。", "嗚嘑大賢苦不壽，時世方士無靈砂。", "五月至止六月病，遽頹泰山驚逝波。", "明年徒步弔京國，宅破子毀哀如何。", "西風衝戶捲素帳，隟光斜照舊燕窠。", "古人常歎知己少，況我淪賤艱虞多。", "如公之德世一二，豈得無淚如黃河。", "瀝膽咒願天有眼，君子之澤方滂沱。"]'),
('ae660471-84bc-4a58-a438-005b8a99c3c1','赤壁','李商隱','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u6218\u4e89", "\u516b\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5185)", "\u521d\u4e2d\u53e4\u8bd7", "\u4e03\u8a00\u7edd\u53e5"]','折戟沈沙鐵未銷，自將磨洗認前朝。',32,'全唐诗/poet.tang.29000.json','["折戟沈沙鐵未銷，自將磨洗認前朝。", "東風不與周郎便，銅雀春深鎖二喬。"]'),
('10256150-7be8-4da3-8292-82e61ac918a2','垂柳','李商隱','唐','唐诗','tang','','[]','垂柳碧鬅茸，樓昏雨帶容。',96,'全唐诗/poet.tang.29000.json','["垂柳碧鬅茸，樓昏雨帶容。", "思量成夜夢，束久廢春慵。", "梳洗憑張敞，乘騎笑稚恭。", "碧虛隨轉笠，紅燭近高舂。", "怨目明秋水，愁眉淡遠峰。", "小闌花盡蝶，靜院醉醒蛩。", "舊作琴臺鳳，今爲藥店龍。", "寶匳拋擲久，一任景陽鐘。"]'),
('a56b89f1-347a-417f-853e-7721520942ee','清夜怨','李商隱','唐','唐诗','tang','','[]','含淚坐春宵，聞君欲度遼。',48,'全唐诗/poet.tang.29000.json','["含淚坐春宵，聞君欲度遼。", "綠池荷葉嫩，紅砌杏花嬌。", "曙月當窗滿，征雲出塞遙。", "畫樓終日閉，清管爲誰調。"]'),
('cc85917d-d8b9-4e69-a8bf-891edf86f3fe','定子','李商隱','唐','唐诗','tang','','[]','檀槽一抹廣陵春，定子初開睡臉新。',32,'全唐诗/poet.tang.29000.json','["檀槽一抹廣陵春，定子初開睡臉新。", "卻笑喫虛隋煬帝，破家亡國爲何人。"]'),
('43c95929-ff50-40f7-8447-2b2603f8b551','木蘭花','李商隱','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭波冷曉侵雲，日日征帆送遠人。',32,'全唐诗/poet.tang.29000.json','["洞庭波冷曉侵雲，日日征帆送遠人。", "幾度木蘭舟上望，不知元是此花身。"]'),
('64a7f056-71e6-4ccf-abe1-711ccedef0be','遊靈伽寺','李商隱','唐','唐诗','tang','','[]','碧煙秋寺汎湖來，水打城根古堞摧。',32,'全唐诗/poet.tang.29000.json','["碧煙秋寺汎湖來，水打城根古堞摧。", "盡日傷心人不見，石榴花滿舊琴臺。"]'),
('0abe360d-128c-446d-a27b-62371e6bbc04','龍丘途中 一','李商隱','唐','唐诗','tang','','[]','漢苑殘花別，吳江盛夏來。',24,'全唐诗/poet.tang.29000.json','["漢苑殘花別，吳江盛夏來。", "惟看萬樹谷，不見一枝開。"]'),
('131b9bdc-8df2-4dd9-aa38-db6c73284606','龍丘途中 二','李商隱','唐','唐诗','tang','','[]','水色饒湘浦，灘聲怯建溪。',24,'全唐诗/poet.tang.29000.json','["水色饒湘浦，灘聲怯建溪。", "淚流迴月上，可得更猨蹄。"]'),
('5aeef785-6d02-4199-b259-175b136a977c','句','李商隱','唐','唐诗','tang','','[]','蘭膏爇處心猶淺，銀燭燒殘焰不馨。',64,'全唐诗/poet.tang.29000.json','["蘭膏爇處心猶淺，銀燭燒殘焰不馨。", "好向書生窗畔種，免教辛苦更囊螢。", "遙想故園陌，桃李正酣酣。", "頭上金雀釵，腰珮翠琅玕。", "蘆洲客雁報春來。"]'),
('c568d2b8-c691-490c-acab-58ebc366db47','送友人歸宜春','紀唐夫','唐','唐诗','tang','','[]','落花兼柳絮，無處不紛紛。',48,'全唐诗/poet.tang.29000.json','["落花兼柳絮，無處不紛紛。", "遠道空歸去，流鶯獨自聞。", "墅橋喧碓水，山郭入樓雲。", "故里南陔曲，秋期欲送君。"]'),
('cea96e47-9117-4909-bf90-9394890b87d7','驄馬曲','紀唐夫','唐','唐诗','tang','','[]','連錢出塞蹋沙蓬，豈比當時御史驄。',64,'全唐诗/poet.tang.29000.json','["連錢出塞蹋沙蓬，豈比當時御史驄。", "逐北自諳深磧路，連嘶誰念靜邊功。", "登山每與青雲合，弄影應知碧草同。", "今日虜平將換妾，不如羅袖舞春風。"]'),
('2c4fc4ed-9623-4cef-a0de-1a270effc21c','送溫庭筠尉方城','紀唐夫','唐','唐诗','tang','','[]','何事明時泣玉頻，長安不見杏園春。',64,'全唐诗/poet.tang.29000.json','["何事明時泣玉頻，長安不見杏園春。", "鳳皇詔下雖霑命，鸚鵡才高却累身。", "且盡綠醽銷積恨，莫辭黃綬拂行塵。", "方城若比長沙路，猶隔千山與萬津。"]'),
('2997f5a6-5f48-411b-a445-e21d865db136','及第後宿平康里','裴思謙','唐','唐诗','tang','','[]','銀缸斜背解鳴璫，小語偷聲賀玉郎。',32,'全唐诗/poet.tang.29000.json','["銀缸斜背解鳴璫，小語偷聲賀玉郎。", "從此不知蘭麝貴，夜來新染桂枝香。"]'),
('55cbce85-fcf0-4d3a-8141-a0357f2e70d7','都堂試貢士日慶春雪','李衢','唐','唐诗','tang','','[]','錫瑞來豐歲，旌賢入貢辰。',72,'全唐诗/poet.tang.29000.json','["錫瑞來豐歲，旌賢入貢辰。", "輕搖梅共笑，飛褭柳知春。", "遶砌封瓊屑，依階噴玉塵。", "蜉蝣吟更古，科斗映還新。", "鶴毳迷難辨，冰壺鑒易真。", "因歌大君德，率舞詠陶鈞。"]'),
('3d45b8ef-2cc2-49da-8ae7-3246fdb817f6','都堂試貢士日慶春雪','李損之','唐','唐诗','tang','','[]','春雪晝悠颺，飄飛試士場。',72,'全唐诗/poet.tang.29000.json','["春雪晝悠颺，飄飛試士場。", "綴毫疑起草，霑字共成章。", "匝地如鋪練，凝階似截肪。", "鵝毛縈樹合，柳絮帶風狂。", "息疫方殊慶，豐年已報祥。", "應知郢上曲，高唱出東堂。"]'),
('04881b67-c09f-4fcb-b935-a2591cde6430','除夜長安作','李景','唐','唐诗','tang','','[]','長安朔風起，窮巷掩雙扉。',48,'全唐诗/poet.tang.29000.json','["長安朔風起，窮巷掩雙扉。", "新歲明朝是，故鄉何路歸。", "鬢絲饒鏡色，隟雪奪燈輝。", "却羨秦州鴈，逢春盡北飛。"]'),
('54c567ce-5fb0-40d9-a00a-bca0d94b3643','都堂試貢士日慶春雪','李景','唐','唐诗','tang','','[]','密雪分天路，羣才坐粉廊。',72,'全唐诗/poet.tang.29000.json','["密雪分天路，羣才坐粉廊。", "靄空迷晝景，臨宇借寒光。", "似暖花消地，無聲玉滿堂。", "灑池偏誤曲，留硯忽因方。", "幾處曹風比，何人謝賦長。", "春暉早相照，莫滯九衢芳。"]'),
('bed1a4a7-2786-4d40-adab-6d8e9ca7bae7','登景雲寺閣','張元宗','唐','唐诗','tang','','[]','胡馬飲河洛，我家從此遷。',24,'全唐诗/poet.tang.29000.json','["胡馬飲河洛，我家從此遷。", "今來獨垂淚，三十六峰前。"]'),
('d38f9d8f-3a9f-4c1b-8c53-ece13e3b47b5','望終南山','張元宗','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','紅塵白日長安路，馬足車輪不暫閑。',32,'全唐诗/poet.tang.29000.json','["紅塵白日長安路，馬足車輪不暫閑。", "唯有茂陵多病客，每來高處望南山。"]'),
('342fab30-f025-454a-a63d-4c3e1ef4e633','省試霓裳羽衣曲','李肱','唐','唐诗','tang','','[]','開元太平時，萬國賀豐歲。',72,'全唐诗/poet.tang.29000.json','["開元太平時，萬國賀豐歲。", "梨園獻舊曲，玉座流新製。", "鳳管遞參差，霞衣競搖曳。", "醼罷水殿空，輦餘春草細。", "蓬壺事已久，仙樂功無替。", "詎肯聽遺音，聖明知善繼。"]'),
('20980d9a-874a-48f8-af29-0ea529c7eb3d','句','李肱','唐','唐诗','tang','','[]','水光先見月，露氣早知秋。',12,'全唐诗/poet.tang.29000.json','["水光先見月，露氣早知秋。"]'),
('132d0b6a-2bc0-4385-84fa-9b415f305243','永州送姪歸宜春','鄭史','唐','唐诗','tang','','[]','宋玉正秋悲，那堪更別離。',48,'全唐诗/poet.tang.29000.json','["宋玉正秋悲，那堪更別離。", "從來襟上淚，盡作鬢邊絲。", "永水清如此，袁江色可知。", "到家黃菊坼，亦莫怪歸遲。"]'),
('ceba570e-3e0b-4a9c-b521-9c25b1e1e102','秋日零陵與幕下諸賓遊河夜飲','鄭史','唐','唐诗','tang','','[]','湘月蘋風乍暢襟，燭前江水練千尋。',64,'全唐诗/poet.tang.29000.json','["湘月蘋風乍暢襟，燭前江水練千尋。", "新秋宋玉能爲賦，永夕袁安好共吟。", "輦下翠蛾須強展，尊中綠蟻且徐斟。", "汀沙漸有珠凝露，緩棹蘭橈任夜深。"]'),
('07bc7049-60da-49f1-8f5d-794947993563','贈妓行雲詩','鄭史','唐','唐诗','tang','','[]','最愛鉛華薄薄妝，更兼衣著又鵝黃。',32,'全唐诗/poet.tang.29000.json','["最愛鉛華薄薄妝，更兼衣著又鵝黃。", "從來南國名佳麗，何事今朝在北行。"]'),
('f845e50b-8b2b-466b-bdc4-73ae4502f2ff','紀夢','許瀍','唐','唐诗','tang','','[]','曉入瑤臺露氣清，天風飛下步虛聲。',32,'全唐诗/poet.tang.29000.json','["曉入瑤臺露氣清，天風飛下步虛聲。", "塵心未盡俗緣在，十里下山空月明。"]'),
('a443d900-8747-454f-bafc-1c59dc0615d1','題朝陽巖','牛叢','唐','唐诗','tang','','[]','躡石攀蘿路不迷，曉天風好浪花低。',32,'全唐诗/poet.tang.29000.json','["躡石攀蘿路不迷，曉天風好浪花低。", "洞名獨占朝陽號，應有梧桐待鳳棲。"]'),
('9c074d22-f8fb-48e7-8790-39751e272622','咸陽有懷','陳上美','唐','唐诗','tang','','[]','山連河水碧氛氳，瑞氣東移擁聖君。',64,'全唐诗/poet.tang.29000.json','["山連河水碧氛氳，瑞氣東移擁聖君。", "秦苑有花空笑日，漢陵無主自侵雲。", "古槐堤上鶯千囀，遠渚沙中鷺一羣。", "賴與淵明同把菊，煙郊西望夕陽曛。"]'),
('38fa500d-186d-44b1-adea-0fa43230fa4d','晴望九華山','楊鴻','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','九華閑望簇清虛，氣象羣峰盡不如。',32,'全唐诗/poet.tang.29000.json','["九華閑望簇清虛，氣象羣峰盡不如。", "惆悵都南挂冠吏，無人解向此山居。"]'),
('5524ba0b-6cfa-499e-9032-6d8460523264','正月','趙璜','唐','唐诗','tang','','[]','正月今朝半，陽臺信未迴。',50,'全唐诗/poet.tang.29000.json','["正月今朝半，陽臺信未迴。", "水芹寒不食，山杏雨應開。", "世網留三宿，真源寄一杯。", "因聲謝猨鳥，歲[晏]會歸來。"]'),
('483c8965-6078-49ba-b9e7-e31cde55e2b8','七夕詩','趙璜','唐','唐诗','tang','','[]','烏鵲橋頭雙扇開，年年一度過河來。',64,'全唐诗/poet.tang.29000.json','["烏鵲橋頭雙扇開，年年一度過河來。", "莫嫌天上稀相見，猶勝人間去不迴。", "欲減煙花饒俗世，暫煩雲月掩樓臺。", "別時舊路長清淺，豈肯離情似死灰。"]'),
('cea6636e-71e3-4270-b496-32ddcd871c93','曲江上巳','趙璜','唐','唐诗','tang','','[]','長隄十里轉香車，兩岸煙花錦不如。',32,'全唐诗/poet.tang.29000.json','["長隄十里轉香車，兩岸煙花錦不如。", "欲問神仙在何處，紫雲樓閣向空虛。"]'),
('df2cc9a0-fb5a-4d7e-adef-c5659ba33d8e','題七夕圖','趙璜','唐','唐诗','tang','','[]','帝子吹簫上翠微，秋風一曲鳳皇歸。',32,'全唐诗/poet.tang.29000.json','["帝子吹簫上翠微，秋風一曲鳳皇歸。", "明年七月重相見，依舊高懸織女機。"]'),
('27e5216a-6ba3-4f7c-a037-1be2a09e958d','登明戍堡','潘咸','唐','唐诗','tang','','[]','來經古城上，極目思無窮。',48,'全唐诗/poet.tang.29000.json','["來經古城上，極目思無窮。", "寇盡煙蘿外，人歸蔓草中。", "峰巒當闕古，堞壘對雲空。", "不見昔名將，徒稱有戰功。"]'),
('50fa4a0e-6c9c-4636-8b98-01509255d3de','送陳明府之任','潘咸','唐','唐诗','tang','','[]','客見天台縣，閭閻樹色間。',48,'全唐诗/poet.tang.29000.json','["客見天台縣，閭閻樹色間。", "驂回幾臨水，帶緩獨開山。", "吏散落花盡，人居遠島閑。", "過於老萊子，端簡獨承顏。"]'),
('c4870297-447a-47e1-b3c4-adbb19519bd9','長安春暮','潘咸','唐','唐诗','tang','','[]','客在關西春暮夜，還同江外已清明。',32,'全唐诗/poet.tang.29000.json','["客在關西春暮夜，還同江外已清明。", "三更獨立看花月，惟欠子規啼一聲。"]'),
('e8557154-1783-4d3c-b8e2-cb793c40e509','舟行','潘咸','唐','唐诗','tang','','[]','平沙極浦無人度，獨繫孤舟寒草西。',32,'全唐诗/poet.tang.29000.json','["平沙極浦無人度，獨繫孤舟寒草西。", "半夜起看潮上月，萬山中有一猨啼。"]'),
('118df0b5-8bf6-41c2-a95f-67531ac766f0','送僧','潘咸','唐','唐诗','tang','','[]','闕下僧歸山頂寺，却看朝日下方明。',32,'全唐诗/poet.tang.29000.json','["闕下僧歸山頂寺，却看朝日下方明。", "莫道野人尋不見，半天雲裏有鐘聲。"]'),
('e25da8d3-1c5a-453f-b82b-214db39e0fe5','句','潘咸','唐','唐诗','tang','','[]','棧踏猨聲暮，江看劍影秋。',64,'全唐诗/poet.tang.29000.json','["棧踏猨聲暮，江看劍影秋。", "僧老白雲上，磬寒高鳥邊。", "心已同猨狖，不聞人是非。", "行人渡流水，白馬入前山。", "秋深雪滿黃金塞，夜夜鴻聲入漢陽。"]'),
('33916556-2066-498e-a2ae-0e35f03f3589','秋晚同友人閑步','薛瑩','唐','唐诗','tang','','[]','藉草與行莎，相看日未斜。',48,'全唐诗/poet.tang.29000.json','["藉草與行莎，相看日未斜。", "斷崖分鳥道，疎樹見人家。", "望遠臨孤石，吟餘落片霞。", "野情看不足，歸路思猶賒。"]'),
('b9b28029-af0b-410b-adca-7e93a044b043','宿仙都觀陰王二君修道處','薛瑩','唐','唐诗','tang','','[]','十載別仙峰，峰前千古蹤。',48,'全唐诗/poet.tang.29000.json','["十載別仙峰，峰前千古蹤。", "陰王修道處，雲雪滿高松。", "洞口風雷異，池心星漢重。", "明朝下山去，片月落殘鐘。"]'),
('7d2b8cec-3afd-4eb5-8d05-b7e692753748','宿東巖寺曉起','薛瑩','唐','唐诗','tang','','[]','野寺寒塘曉，遊人一夢分。',48,'全唐诗/poet.tang.29000.json','["野寺寒塘曉，遊人一夢分。", "鐘殘數樹月，僧起半巖雲。", "宿鳥驚初見，幽泉落不聞。", "吟餘憑前檻，紅葉下紛紛。"]'),
('60a7d82c-47ae-41e3-862c-e61ea8f65494','秋日湖上','薛瑩','唐','唐诗','tang','','[]','落日五湖遊，煙波處處愁。',24,'全唐诗/poet.tang.29000.json','["落日五湖遊，煙波處處愁。", "沈浮千古事，誰與問東流。"]'),
('ff24370c-4941-4ce7-b424-b484367a0aba','江山閑望','薛瑩','唐','唐诗','tang','','[]','渺渺無窮盡，風濤幾日平。',24,'全唐诗/poet.tang.29000.json','["渺渺無窮盡，風濤幾日平。", "年光與人事，東去一聲聲。"]'),
('e020e986-d544-401d-95ee-f9d8ae0adb74','訪武陵道者不遇','薛瑩','唐','唐诗','tang','','[]','花發鳥仍啼，行行路欲迷。',24,'全唐诗/poet.tang.29000.json','["花發鳥仍啼，行行路欲迷。", "二真無問處，虛度武陵溪。"]'),
('bdcdfd98-1a2f-4cc4-94f2-9179fd13ca70','寄舊山隱侶','薛瑩','唐','唐诗','tang','','[]','舊山諸隱淪，身在苦無身。',24,'全唐诗/poet.tang.29000.json','["舊山諸隱淪，身在苦無身。", "莫鎖白雲路，白雲多悞人。"]'),
('da552079-89c8-48ec-a913-710125e257e7','羨僧','薛瑩','唐','唐诗','tang','','[]','處世曾無著，生前事盡非。',24,'全唐诗/poet.tang.29000.json','["處世曾無著，生前事盡非。", "一缾兼一衲，南北去如歸。"]'),
('b7ca7ff8-c8b5-4b33-a191-4ada8ce9e86f','錦','薛瑩','唐','唐诗','tang','','[]','軋軋弄寒機，功多力漸微。',24,'全唐诗/poet.tang.29000.json','["軋軋弄寒機，功多力漸微。", "惟憂機上錦，不稱舞人衣。"]'),
('634aa7c8-8cf7-4519-88fa-57ff5d91ba03','中秋月','薛瑩','唐','唐诗','tang','','[]','三十六旬盈復缺，百年堪喜又堪傷。',32,'全唐诗/poet.tang.29000.json','["三十六旬盈復缺，百年堪喜又堪傷。", "勸君莫惜登樓望，雲放嬋娟不久長。"]'),
('51a95b90-85f2-43d9-adbd-ac98573860d3','句','薛瑩','唐','唐诗','tang','','[]','單棹橫疎雨，江灘秋泊時。',24,'全唐诗/poet.tang.29000.json','["單棹橫疎雨，江灘秋泊時。", "花留身住越，月遞夢還秦。"]'),
('c6071988-def8-4a18-a925-66ef3ef61b70','贈毛仙翁','崔元略','唐','唐诗','tang','','[]','莫將凡聖比雲泥，椿菌之年本不齊。',64,'全唐诗/poet.tang.29000.json','["莫將凡聖比雲泥，椿菌之年本不齊。", "度世無勞大稻米，昇天只用半刀圭。", "人間嗟對黃昏槿，海上閑聽碧落雞。", "旌節行中令引道，便從塵外踏丹梯。"]'),
('42f41270-eebd-4809-b0f5-0f687bbf629c','太學創置石經','馮涯','唐','唐诗','tang','','[]','聖唐復古制，德義功無替。',72,'全唐诗/poet.tang.29000.json','["聖唐復古制，德義功無替。", "奧旨悅詩書，遺文分篆隸。", "銀鉤互交映，石壁靡塵翳。", "永與乾坤期，不逐日月逝。", "儒林道益廣，學者心彌銳。", "從此理化成，恩光遍遐裔。"]'),
('d235b6d6-20e0-44fd-a924-5b4841822972','贈李商隱','喻鳧','唐','唐诗','tang','','[]','羽翼恣摶扶，山河使筆驅。',48,'全唐诗/poet.tang.29000.json','["羽翼恣摶扶，山河使筆驅。", "月疎吟夜桂，龍失詠春珠。", "草細盤金勒，花繁倒玉壺。", "徒嗟好章句，無力致前途。"]'),
('98690cc8-65fe-492c-96c7-eda3c902d84d','元日即事','喻鳧','唐','唐诗','tang','','[]','斂板賀交親，稱觴詎有巡。',48,'全唐诗/poet.tang.29000.json','["斂板賀交親，稱觴詎有巡。", "年光悲擲舊，景色喜呈新。", "水柳煙中重，山梅雪後真。", "不知將白髮，何以度青春。"]'),
('511d4d29-fcfb-40af-86d1-a5a66dd82825','送賈島往金州謁姚員外','喻鳧','唐','唐诗','tang','','[]','山光與水色，獨往此中深。',48,'全唐诗/poet.tang.29000.json','["山光與水色，獨往此中深。", "溪瀝椒花氣，巖盤漆葉陰。", "瀟湘終共去，巫峽羨先尋。", "幾夕江樓月，玄暉伴靜吟。"]'),
('41d49db0-d027-4a09-82a3-4e73d65b1ddb','送友人罷舉歸蜀','喻鳧','唐','唐诗','tang','','[]','憔悴滿衣塵，風光豈屬身。',48,'全唐诗/poet.tang.29000.json','["憔悴滿衣塵，風光豈屬身。", "賣琴紅粟貴，看鏡白髭新。", "棧畔誰高步，巴邊自問津。", "悽然莫滴血，杜宇正哀春。"]'),
('3b392b79-2a3a-49f3-bd7d-a3c5528cba5f','送衛尉之延陵','喻鳧','唐','唐诗','tang','','[]','草木正花時，交親觸雨辭。',48,'全唐诗/poet.tang.29000.json','["草木正花時，交親觸雨辭。", "一官之任遠，盡室出城遲。", "乳滴茅君洞，鴉鳴季子祠。", "想知佐理暇，日有詠懷詩。"]'),
('915fdfc5-575f-4cfe-a4b9-07eb5b6a2258','送越州高錄事','喻鳧','唐','唐诗','tang','','[]','官曹權紀綱，行李半舟航。',48,'全唐诗/poet.tang.29000.json','["官曹權紀綱，行李半舟航。", "浦溆潮來廣，川源鳥去長。", "筍成稽嶺岸，蓮發鏡湖香。", "澤國還之任，鱸魚浪得嘗。"]'),
('14e3b4e7-8e36-498f-b304-01b2d0ac88b0','送潘咸','喻鳧','唐','唐诗','tang','','[]','時時齎破囊，訪我息閑坊。',48,'全唐诗/poet.tang.29000.json','["時時齎破囊，訪我息閑坊。", "煮雪問茶味，當風看鴈行。", "心齊山鹿逸，句敵柳花狂。", "堅苦今如此，前程豈渺茫。"]'),
('850eb99d-8e71-4d28-a138-f2d828a1a792','送友人下第歸寧','喻鳧','唐','唐诗','tang','','[]','紫閣雪未盡，杏園花亦寒。',48,'全唐诗/poet.tang.29000.json','["紫閣雪未盡，杏園花亦寒。", "灞西辭舊友，楚外憶新安。", "細雨猨啼枿，微陽鷺起灘。", "旋應赴秋貢，詎得久承歡。"]'),
('0987c6db-16dc-418e-81a9-00263a8c3fd0','游北山寺','喻鳧','唐','唐诗','tang','','[]','煙岡影畔寺，游步此時孤。',48,'全唐诗/poet.tang.29000.json','["煙岡影畔寺，游步此時孤。", "庭靜衆藥在，鶴閑雙檜枯。", "藍峰露秋院，灞水入春廚。", "便可棲心跡，如何返舊途。"]'),
('82aa7717-7a23-471c-a650-c263244f4044','冬日題無可上人院','喻鳧','唐','唐诗','tang','','[]','入戶道心生，茶間踏葉行。',48,'全唐诗/poet.tang.29000.json','["入戶道心生，茶間踏葉行。", "瀉風瓶水澀，承露鶴巢輕。", "閣北長河氣，窗東一檜聲。", "詩言與禪味，語默此皆清。"]'),
('a19ba3e6-c35f-41bf-a5fc-cf0cdbffe7ae','游雲際寺','喻鳧','唐','唐诗','tang','','[]','澗壑吼風雷，香門絕頂開。',48,'全唐诗/poet.tang.29000.json','["澗壑吼風雷，香門絕頂開。", "閣寒僧不下，鐘定虎常來。", "鳥啄林稍菓，鼯跳竹裏苔。", "心源無一事，塵界擬休回。"]'),
('c6480be6-096b-4c28-a2ef-231691fc73b2','題翠微寺','喻鳧','唐','唐诗','tang','','[]','沿溪又涉巔，始喜入前軒。',48,'全唐诗/poet.tang.29000.json','["沿溪又涉巔，始喜入前軒。", "鐘度鳥沈壑，殿扃雲濕幡。", "涼泉墮衆石，古木徹疎猨。", "月上僧階近，斯遊豈易言。"]'),
('e30a1d04-8a64-4d91-9749-a94785424ed1','廣德官舍二松','喻鳧','唐','唐诗','tang','','[]','楊公休簿領，二木日堅牢。',48,'全唐诗/poet.tang.29000.json','["楊公休簿領，二木日堅牢。", "直甚彰吾節，清終庇爾曹。", "幽陰月裏細，冷樹雪中高。", "誰見干霄後，枝飄白鶴毛。"]'),
('689ccdb3-04b3-4669-84d9-8c4fc9f9c03f','浴馬','喻鳧','唐','唐诗','tang','','[]','解控復收鞭，長津動細漣。',48,'全唐诗/poet.tang.29000.json','["解控復收鞭，長津動細漣。", "空蹄沈綠玉，闊臆沒連錢。", "沫漩橋聲下，嘶盤柳影邊。", "常聞畯龍性，固與白波便。"]'),
('2eb1a9b4-e2a1-4cdb-b4a4-4b31d767b9a9','和段學士南亭春日對雨','喻鳧','唐','唐诗','tang','','[]','晨飛晚未休，蘭閣客吟愁。',48,'全唐诗/poet.tang.29000.json','["晨飛晚未休，蘭閣客吟愁。", "蕭颯柳邊挂，縈紆花底流。", "聲繁乍離籟，灑急不成漚。", "經夕江湖思，煙波一釣舟。"]'),
('11019324-2d71-40a7-8b63-ae45da9c35a2','書懷','喻鳧','唐','唐诗','tang','','["\u592a\u6e56"]','秖是守琴書，僧中獨寓居。',48,'全唐诗/poet.tang.29000.json','["秖是守琴書，僧中獨寓居。", "心唯務鶴靜，分合與名疎。", "暮雨啼螿次，涼風落木初。", "家山太湖淥，歸去復何如。"]'),
('c88c9816-8f77-4d64-9ed2-49ded4293ddf','一公房','喻鳧','唐','唐诗','tang','','[]','幽深誰掩關，清淨自多閑。',48,'全唐诗/poet.tang.29000.json','["幽深誰掩關，清淨自多閑。", "一雨收衆木，孤雲生遠山。", "花萎綠苔上，鴿乳翠樓間。", "嵐靄燃香夕，容聽半偈還。"]'),
('19e60559-18ed-4ef8-b25a-810f2870905b','晚次臨涇','喻鳧','唐','唐诗','tang','','[]','路入犬羊群，城寒雉堞曛。',48,'全唐诗/poet.tang.29000.json','["路入犬羊群，城寒雉堞曛。", "居人秖尚武，過客謾投文。", "馬怯奔渾水，鵰沈莽蒼雲。", "沙田積蒿艾，竟夕見燒焚。"]'),
('229d0658-f8bf-4d95-81dd-8d32ffa488a3','王母祠前寫望','喻鳧','唐','唐诗','tang','','[]','雲霞千古事，桃李舊花顏。',48,'全唐诗/poet.tang.29000.json','["雲霞千古事，桃李舊花顏。", "芳信沈青鳥，空祠掩暮山。", "香傳一座暗，柳匝萬家閑。", "那復傷神所，河昏落日間。"]'),
('ec9055aa-cee0-401e-b541-09d4f5273981','遊暖泉精舍','喻鳧','唐','唐诗','tang','','[]','塢木殿前空，山河澤國同。',48,'全唐诗/poet.tang.29000.json','["塢木殿前空，山河澤國同。", "鳥閑沙影上，泉落樹陰中。", "纜舸蒲花水，縈幡柳絮風。", "翛然方寸地，何事更悲蓬。"]'),
('16fde343-ca5b-4c39-8c78-415f168206ea','懷鄉','喻鳧','唐','唐诗','tang','','[]','秋風江上家，釣艇泊蘆花。',48,'全唐诗/poet.tang.29000.json','["秋風江上家，釣艇泊蘆花。", "斷岸綠楊蔭，疎籬紅槿遮。", "鼉鳴積雨窟，鶴步夕陽沙。", "抱疾僧窗夜，歸心過月斜。"]'),
('f2258cfa-0427-4fa7-b26d-6816c1e22b96','岫禪師南溪蘭若','喻鳧','唐','唐诗','tang','','[]','錫影配瓶光，孤溪照草堂。',48,'全唐诗/poet.tang.29000.json','["錫影配瓶光，孤溪照草堂。", "水懸青石磴，鐘動白雲牀。", "樹色含殘雨，河流帶夕陽。", "唯應無月夜，瞑目見他方。"]'),
('9fde34ab-2f79-43e0-997d-3f75722068a9','龍翔寺寄李頻','喻鳧','唐','唐诗','tang','','[]','鐘聲南北寺，不道往來遙。',48,'全唐诗/poet.tang.29000.json','["鐘聲南北寺，不道往來遙。", "人事因循過，時光荏苒銷。", "懸燈灑砌雨，上閣遶雲鵰。", "即是洲中柳，嘶蟬急暮條。"]'),
('fe6bb71f-ad93-4d03-85ba-ce9c7fab240d','送武瑴之邠寧','喻鳧','唐','唐诗','tang','','[]','戍路少人蹤，邊煙澹復濃。',48,'全唐诗/poet.tang.29000.json','["戍路少人蹤，邊煙澹復濃。", "詩寧寫別恨，酒不上離容。", "燕拂沙河柳，鵶高石窟鐘。", "悠然一暌阻，山疊虜雲重。"]'),
('c23437ce-78a0-4748-8169-310d097a3d77','夏日題岫禪師房','喻鳧','唐','唐诗','tang','','[]','朝朝聲磬罷，童子掃藤陰。',48,'全唐诗/poet.tang.29000.json','["朝朝聲磬罷，童子掃藤陰。", "花過少游客，日長無事心。", "迴山閉院直，落水下橋深。", "安得開方便，容身老此林。"]'),
('1c503cfd-d02a-42a6-9001-88b0a6d8cc07','夏日因懷陽羨舊遊寄裴書記','喻鳧','唐','唐诗','tang','','["\u592a\u6e56"]','落日太湖西，波涵萬象低。',48,'全唐诗/poet.tang.29000.json','["落日太湖西，波涵萬象低。", "藕花熏浦溆，菱蔓匿鳧鷖。", "樹及長橋盡，灘迴七里迷。", "還應坐籌暇，時一夢荆溪。"]'),
('0c313e45-0757-47d9-abeb-bddd4a4596d1','呈薛博士','喻鳧','唐','唐诗','tang','','[]','辛勤長在學，一室少曾開。',48,'全唐诗/poet.tang.29000.json','["辛勤長在學，一室少曾開。", "時憶暮山寺，獨登衰草臺。", "名期五字立，迹媿九年來。", "此意今聊寫，還希君子哀。"]'),
('7ba029c7-be9f-40e0-81bf-a3fefd3cb75b','即事','喻鳧','唐','唐诗','tang','','[]','抱杖立溪口，迎秋看塞門。',48,'全唐诗/poet.tang.29000.json','["抱杖立溪口，迎秋看塞門。", "連山互蒼翠，二水各清渾。", "笛發孤煙戍，鵶歸夕照村。", "萋萋芳草色，終是憶王孫。"]'),
('3bf3f45d-1866-4c5f-afe3-0a2025fc04f3','龍翔寺閣夜懷渭南張少府','喻鳧','唐','唐诗','tang','','[]','春城帶病別，秋塞見除書。',48,'全唐诗/poet.tang.29000.json','["春城帶病別，秋塞見除書。", "況是神仙吏，仍非塵土居。", "河風吹鳥迥，嶽雨滴桐疎。", "坐閣馳思夕，沙東涼月虛。"]'),
('ba261c33-9ac6-4b4a-9ef8-d3f1c46e6b66','夏日龍翔寺居即事寄崔侍御','喻鳧','唐','唐诗','tang','','[]','古剎一幡斜，吹門水過沙。',48,'全唐诗/poet.tang.29000.json','["古剎一幡斜，吹門水過沙。", "數聲鐘裏飯，雙影樹間茶。", "落日窮荒雨，微風古塹花。", "何當戴豸客，復此問生涯。"]'),
('0f2e2859-7c3f-4065-b9a9-ee6253ca3679','龍翔寺居喜胡權見訪因宿','喻鳧','唐','唐诗','tang','','[]','林棲無異歡，煮茗就花欄。',48,'全唐诗/poet.tang.29000.json','["林棲無異歡，煮茗就花欄。", "雀啅北岡曉，僧開西閣寒。", "衝橋二水急，扣月一鐘殘。", "明發還分手，徒悲行路難。"]'),
('b5f6b748-3e06-4e2a-9778-6b5b3e315737','宿石窟寺','喻鳧','唐','唐诗','tang','','[]','一剎古岡南，孤鐘撼夕嵐。',48,'全唐诗/poet.tang.29000.json','["一剎古岡南，孤鐘撼夕嵐。", "客閑明月閣，僧閉白雲菴。", "野鶴立枯枿，天龍吟淨潭。", "因知不生理，合自此中探。"]'),
('17ee7094-c667-40c0-a923-b9cb9988df60','夏日龍翔寺寄張侍御','喻鳧','唐','唐诗','tang','','[]','沙西林杪寺，殿倚石稜開。',48,'全唐诗/poet.tang.29000.json','["沙西林杪寺，殿倚石稜開。", "曉月僧汲井，殘陽鐘殷臺。", "河衝綠野去，鳥背白雲來。", "日夕唯增思，京關未想迴。"]'),
('2f90ade9-bf36-46e6-b89d-f7f4d1386f2e','秋日將歸長安留別王尚書','喻鳧','唐','唐诗','tang','','[]','朔漠正秋霖，西風傳夕砧。',48,'全唐诗/poet.tang.29000.json','["朔漠正秋霖，西風傳夕砧。", "滄洲未歸迹，華髪受恩心。", "露色岡莎冷，蟬聲塢木深。", "清晨鈇鉞內，只獻白雲吟。"]'),
('854cbca4-e192-405c-92cf-c402bc2126fc','龍翔寺言懷','喻鳧','唐','唐诗','tang','','[]','眠雲喜道存，讀易過朝昏。',48,'全唐诗/poet.tang.29000.json','["眠雲喜道存，讀易過朝昏。", "喬木青連郭，長河白瀉門。", "鐘沈殘月塢，鳥去夕陽村。", "搜此成閑句，期逢作者論。"]'),
('14592c94-949d-4adb-8e5c-834ccf0bc08b','龍翔寺居夏日寄獻王尚書','喻鳧','唐','唐诗','tang','','[]','那期高斾下，得遇重臣知。',48,'全唐诗/poet.tang.29000.json','["那期高斾下，得遇重臣知。", "泉石容居止，風沙免路岐。", "河兼落下望，句入大荒思。", "無復愁煩暑，迴山翠閣危。"]'),
('62884693-ae3c-4a9e-a0fc-1595fb2c3ab6','題弘濟寺不出院僧','喻鳧','唐','唐诗','tang','','[]','楚鞋應此世，祇遶砌苔休。',48,'全唐诗/poet.tang.29000.json','["楚鞋應此世，祇遶砌苔休。", "色相栽花視，身心坐石修。", "聲寒通節院，城黑見烽樓。", "欲取閑雲並，閑雲有去留。"]'),
('5127db9b-4afa-4697-8b2c-d4d560bc9c71','寄劉錄事','喻鳧','唐','唐诗','tang','','[]','城西青島寺，累夏漱寒泉。',48,'全唐诗/poet.tang.29000.json','["城西青島寺，累夏漱寒泉。", "今在提綱所，應難掃石眠。", "風沙榆塞迥，波浪橘洲偏。", "重整瀟湘棹，心期更幾年。"]'),
('90be1917-c155-4ef7-8fe8-6584c1a45137','酬王檀見寄','喻鳧','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','馳心棲杳冥，何物比清冷。',48,'全唐诗/poet.tang.29000.json','["馳心棲杳冥，何物比清冷。", "夜月照巫峽，秋風吹洞庭。", "酬難塵鬢皓，坐久壁燈青。", "竟晚蒼山詠，喬枝有鶴聽。"]'),
('18d07f5b-2e76-4874-8ad2-aa27a1c0f464','寺居秋日對雨有懷','喻鳧','唐','唐诗','tang','','[]','修修復雭雭，黃葉此時飛。',48,'全唐诗/poet.tang.29000.json','["修修復雭雭，黃葉此時飛。", "隱几客吟斷，鄰房僧話稀。", "鴿寒棲樹定，螢濕在窗微。", "即事瀟湘渚，漁翁披草衣。"]'),
('cfc41b8f-f284-403a-bd48-06765f526724','答劉錄事夜月懷湘西友人見寄','喻鳧','唐','唐诗','tang','','[]','相逢仍朔漠，相問即波濤。',48,'全唐诗/poet.tang.29000.json','["相逢仍朔漠，相問即波濤。", "江思葦花折，笛聲關月高。", "簿書君閱倦，章句我吟勞。", "竟夕空凭閣，長河漴石壕。"]'),
('a750206e-ee88-4e0b-9bc3-4fc745032274','上高侍御','喻鳧','唐','唐诗','tang','','[]','舊隱白雲峰，生涯落葉同。',48,'全唐诗/poet.tang.29000.json','["舊隱白雲峰，生涯落葉同。", "關河一棲旅，楊柳十東風。", "迹處龍鍾內，聲居汩沒中。", "酬恩若有地，寧止殺微躬。"]'),
('8e56a5e4-4d13-47b1-837d-39fe1676f20d','冬日寄友人','喻鳧','唐','唐诗','tang','','[]','空爲梁甫吟，誰竟是知音。',48,'全唐诗/poet.tang.29000.json','["空爲梁甫吟，誰竟是知音。", "風雪坐閑夜，鄉園來舊心。", "滄江孤棹迥，落日一鐘深。", "君子久忘我，此誠甘自沈。"]'),
('337e9742-7a04-42c4-82d0-cfea2c2a95b3','冬夜宿余正字靜恭里閑居','喻鳧','唐','唐诗','tang','','[]','每來多便宿，不負白雲言。',48,'全唐诗/poet.tang.29000.json','["每來多便宿，不負白雲言。", "古木朔風動，寒城疎雪翻。", "微燈懸刻漏，舊夢返湘沅。", "先是琴邊起，知爲閣務繁。"]'),
('97e51284-1ded-45d7-8444-fee7da266d28','得子姪書','喻鳧','唐','唐诗','tang','','[]','遠書來阮巷，闕下見江東。',48,'全唐诗/poet.tang.29000.json','["遠書來阮巷，闕下見江東。", "不得經史力，枉拋耕稼功。", "鴈天霞脚雨，漁夜葦條風。", "無復琴桮興，開懷向爾同。"]'),
('de19af25-fc83-42bd-a05b-38c4cfea9796','獻知己','喻鳧','唐','唐诗','tang','','[]','亦忝受恩身，當殊投刺新。',48,'全唐诗/poet.tang.29000.json','["亦忝受恩身，當殊投刺新。", "竟蒙分玉石，終不離埃塵。", "大谷非無暖，幽枝自未春。", "昏昏過朝夕，應念苦吟人。"]'),
('cb4a385c-778a-42b9-92c9-2e6294d5e302','贈張濆處士','喻鳧','唐','唐诗','tang','','[]','露白覆棋宵，林青讀易朝。',48,'全唐诗/poet.tang.29000.json','["露白覆棋宵，林青讀易朝。", "道高天子問，名重四方招。", "許鶴歸華頂，期僧過石橋。", "雖然在京國，心跡自逍遙。"]'),
('b268a5ae-de77-43f2-9f61-22ad746a3f3f','早秋寺居酬張侍御六韻見寄','喻鳧','唐','唐诗','tang','','[]','六十上清冥，曉緘東越藤。',72,'全唐诗/poet.tang.29000.json','["六十上清冥，曉緘東越藤。", "山光紫衣陟，寺影白雲凝。", "濕葉起寒鳥，深林驚古僧。", "微風窗靜展，細雨閣吟登。", "清韻嶽磬遠，佳音湖水澄。", "却思前所獻，何以豸冠稱。"]'),
('588b124d-9213-448e-9875-bffd63febf7e','和段學士對雪','喻鳧','唐','唐诗','tang','','[]','盈尺知豐稔，開窗對酒壺。',72,'全唐诗/poet.tang.29000.json','["盈尺知豐稔，開窗對酒壺。", "飄當大野匝，灑到急流無。", "密際西風盡，凝間朔氣扶。", "乾摧鳥棲枿，冷射夜殘罏。", "贊月澄斜漢，兼沙攪北湖。", "慙於郢客坐，一此調巴歈。"]'),
('5a880973-a905-4a16-8127-6d6a1348c8a2','監試夜雨滴空堦','喻鳧','唐','唐诗','tang','','[]','霎霎復淒淒，飄松又灑槐。',72,'全唐诗/poet.tang.29000.json','["霎霎復淒淒，飄松又灑槐。", "氣濛蛛網檻，聲疊蘚花堦。", "古壁青燈動，深庭濕葉埋。", "徐垂舊夗瓦，競歷小茅齋。", "冷與陰蟲間，清將玉漏諧。", "病身唯展轉，誰見此時懷。"]'),
('87acee2c-c3bc-4d63-8b68-4c79cea0fdbe','春雨如膏','喻鳧','唐','唐诗','tang','','[]','冪冪斂輕塵，濛濛濕野春。',72,'全唐诗/poet.tang.29000.json','["冪冪斂輕塵，濛濛濕野春。", "細光添柳重，幽點濺花勻。", "慘淡游絲景，陰沈落絮辰。", "迴低飛蝶翅，寒滴語禽身。", "灑岳摧餘雪，吹江疊遠蘋。", "東城與西陌，晴後趣何新。"]'),
('144e5455-814b-4c56-bd48-47f598aba26b','送友人南中訪舊知','喻鳧','唐','唐诗','tang','','[]','春盡大方遊，思君便白頭。',48,'全唐诗/poet.tang.29000.json','["春盡大方遊，思君便白頭。", "地蒸川有毒，天暖樹無秋。", "水急三巴險，猨分五嶺愁。", "爲緣知己分，南國必淹留。"]'),
('a8437a0b-6675-4d49-829a-08d9a543c90d','玄都觀李尊師','喻鳧','唐','唐诗','tang','','[]','蘚幘翠髯公，存思古觀空。',48,'全唐诗/poet.tang.29000.json','["蘚幘翠髯公，存思古觀空。", "曉壇檉葉露，晴圃柳花風。", "壽已將椿並，碁難見局終。", "何當與高鶴，飛去海光中。"]'),
('bace5027-79a4-46a3-b6b2-ac15930c5c3e','送石賁歸吳興','喻鳧','唐','唐诗','tang','','[]','同志幸同年，高堂君獨還。',48,'全唐诗/poet.tang.29000.json','["同志幸同年，高堂君獨還。", "齊榮恩未報，共隱事皆閑。", "訪寺臨河岸，開樓見海山。", "洛中推二陸，莫久戀鄉關。"]'),
('1b773ff0-e4d4-46bd-b85b-c4a2db753c84','感遇','喻鳧','唐','唐诗','tang','','[]','江鄉十年別，京國累日同。',24,'全唐诗/poet.tang.29000.json','["江鄉十年別，京國累日同。", "在客幾多事，俱付酒杯中。"]'),
('7f42def0-8c47-4b9e-90e7-d51293cfa951','晚思','喻鳧','唐','唐诗','tang','','[]','鶴下紫閣雲，沈沈翠微雨。',24,'全唐诗/poet.tang.29000.json','["鶴下紫閣雲，沈沈翠微雨。", "獨坐正無言，孤莊一聲杵。"]'),
('e6c10d4b-8872-4b2d-bc25-ce9803757ae3','贈空禪師','喻鳧','唐','唐诗','tang','','[]','虎見修行久，松知夏臘高。',24,'全唐诗/poet.tang.29000.json','["虎見修行久，松知夏臘高。", "寒堂坐風雨，瞑目尚波濤。"]'),
('127c839c-ba95-49f6-b7e0-07ece7bd0135','西山寒日逢韋侍御','喻鳧','唐','唐诗','tang','','[]','獬豸霜中貌，龍鍾病後顏。',24,'全唐诗/poet.tang.29000.json','["獬豸霜中貌，龍鍾病後顏。", "慘傷此身事，風雪動江山。"]'),
('f0952fff-6045-44ee-bc86-cf2192e23e7c','題禪院','喻鳧','唐','唐诗','tang','','[]','無花地亦香，有鶴松多直。',24,'全唐诗/poet.tang.29000.json','["無花地亦香，有鶴松多直。", "向此奚必孤，山僧盡相識。"]'),
('374cf837-fba4-4c2c-9767-0a954a0830d0','驚秋','喻鳧','唐','唐诗','tang','','[]','鶯囀纔間關，蟬鳴旋蕭屑。',24,'全唐诗/poet.tang.29000.json','["鶯囀纔間關，蟬鳴旋蕭屑。", "如何兩鬢毛，不作千枝雪。"]'),
('8be2e543-a1f4-4672-a0f2-25e6df8fa430','經劉校書墓','喻鳧','唐','唐诗','tang','','[]','遠冢松回曲渚風，一官聞是校書終。',32,'全唐诗/poet.tang.29000.json','["遠冢松回曲渚風，一官聞是校書終。", "霜情月思今何在，零落人間策子中。"]'),
('d15c747c-5963-4992-b8fa-b566613c89d0','蔣處士宅喜閑公至','喻鳧','唐','唐诗','tang','','[]','絕杯夏別螺江渡，單鉢春過處士齋。',32,'全唐诗/poet.tang.29000.json','["絕杯夏別螺江渡，單鉢春過處士齋。", "嘗茗議空經不夜，照花明月影侵堦。"]'),
('dbcf0b92-c243-49fc-b190-60d6de7379c6','絕句','喻鳧','唐','唐诗','tang','','[]','銀地無塵金菊開，紫棃紅棗墮莓苔。',32,'全唐诗/poet.tang.29000.json','["銀地無塵金菊開，紫棃紅棗墮莓苔。", "一泓秋水一輪月，今夜故人來不來。"]'),
('6c3dbecb-f90b-4757-afc5-cf09a49f8d67','句','喻鳧','唐','唐诗','tang','','[]','顏凋明鏡覺，思苦白雲知。',24,'全唐诗/poet.tang.29000.json','["顏凋明鏡覺，思苦白雲知。", "滄洲迷釣隱，紫閣負僧期。"]'),
('d028ccdf-9ef8-4777-bce8-fcae79085318','南陽道中作','張九齡','唐','唐诗','tang','','[]','登郢屬歲陰，及宛懵所適。',168,'全唐诗/poet.tang.3000.json','["登郢屬歲陰，及宛懵所適。", "復聞東漢主，遺此南都迹。", "佳氣藹厥初，霸圖紛在昔。", "茲邦稱貴近，與世嘗薰赫。", "遭遇感風雲，變衰空草澤。", "不識鄧公樹，猶傳陰后石。", "驅馬歷闉闍，荆榛翳阡陌。", "事去物無象，感來心不懌。", "懷古對窮秋，興言傷遠客。", "眇默遵岐路，辛勤弊行役。", "雲雁號相呼，林麕走自索。", "顧憶徇書劍，未嘗安枕席。", "豈暇墨突黔，空持遼豕白。", "迷復期非遠，歸歟賞農隙。"]'),
('eae14fba-87b5-48d1-b270-353f76d2b898','湘中作','張九齡','唐','唐诗','tang','','["\u8861\u5c71"]','湘流繞南嶽，絕目轉青青。',60,'全唐诗/poet.tang.3000.json','["湘流繞南嶽，絕目轉青青。", "懷祿未能已，瞻途屢所經。", "煙嶼宜春望，林猿莫夜聽。", "永路日多緒，孤舟天復冥。", "浮沒從此去，嗟嗟勞我形。"]'),
('f5b4ad26-6af5-4125-b43a-7840fc865f33','彭蠡湖上','張九齡','唐','唐诗','tang','','["\u5e90\u5c71"]','沿涉經大湖，湖流多行泆。',96,'全唐诗/poet.tang.3000.json','["沿涉經大湖，湖流多行泆。", "決晨趨北渚，逗浦已西日。", "所適雖淹曠，中流且閑逸。", "瑰詭良復多，感見乃非一。", "廬山直陽滸，孤石當陰術。", "一水雲際飛，數峰湖心出。", "象類何交乣，形言豈深悉。", "且知皆自然，高下無相恤。"]'),
('dda856a1-8f74-47cf-bf5a-978a277d670c','入廬山仰望瀑布水','張九齡','唐','唐诗','tang','','["\u5e90\u5c71"]','絕頂有懸泉，喧喧出煙杪。',96,'全唐诗/poet.tang.3000.json','["絕頂有懸泉，喧喧出煙杪。", "不知幾時歲，但見無昏曉。", "閃閃青崖落，鮮鮮白日皎。", "灑流濕行雲，濺沫驚飛鳥。", "雷吼何噴薄，箭馳入窈窕。", "昔聞山下蒙，今乃林巒表。", "物情有詭激，坤元曷紛矯。", "默然置此去，變化誰能了。"]'),
('14514787-b0e7-4d45-81cb-7998ec8c49a6','出爲豫章郡途次廬山東巖下','張九齡','唐','唐诗','tang','','["\u5e90\u5c71"]','茲山鎮何所，乃在澄湖陰。',168,'全唐诗/poet.tang.3000.json','["茲山鎮何所，乃在澄湖陰。", "下有蛟螭伏，上與虹蜺尋。", "靈仙未始曠，窟宅何其深。", "雙闕出雲峙，三宮入煙沈。", "攀崖猶昔境，種杏非舊林。", "想像終古跡，惆悵獨往心。", "紛吾嬰世網，數載忝朝簪。", "孤根自靡託，量力況不任。", "多謝周身防，常恐橫議侵。", "豈匪鵷鴻列，惕如泉壑臨。", "迨茲刺江郡，來此滌塵襟。", "有趣逢樵客，忘懷狎野禽。", "棲閑義未果，用拙歡在今。", "願言答休命，歸事丘中琴。"]'),
('c91e4c59-f6e7-4764-b866-083c2f4f2b13','巡屬縣道中作','張九齡','唐','唐诗','tang','','[]','春令夙所奉，駕言遵此行。',144,'全唐诗/poet.tang.3000.json','["春令夙所奉，駕言遵此行。", "途中却郡掾，林下招村氓。", "至邑無紛劇，來人但歡迎。", "豈伊念邦政，爾實在時清。", "短才濫符竹，弱歲起柴荆。", "再入江村道，永懷山藪情。", "矧逢陽節獻，默聽時禽鳴。", "迹與素心別，感從幽思盈。", "流芳日不待，夙志蹇無成。", "知命且何欲，所圖唯退耕。", "華簪極身泰，衰鬢慙木榮。", "苟得不可遂，吾其謝世嬰。"]'),
('3751feb5-8327-48f9-ad32-101a6b23ed7a','夏日奉使南海在道中作','張九齡','唐','唐诗','tang','','["\u957f\u6c5f"]','緬然萬里露，赫曦三伏時。',120,'全唐诗/poet.tang.3000.json','["緬然萬里露，赫曦三伏時。", "飛走逃深林，流爍恐生疵。", "行李豈無苦，而我方自怡。", "肅事誠在公，拜慶遂及私。", "展力慙淺效，銜恩感深慈。", "且欲湯火蹈，況無鬼神欺。", "朝發高山阿，夕濟長江湄。", "秋瘴寧我毒，夏水胡不夷。", "信知道存者，但問心所之。", "呂梁有出入，乃覺非虛詞。"]'),
('2546b734-e622-4e0d-9251-588bea723a85','巡按自灕水南行','張九齡','唐','唐诗','tang','','[]','理棹雖云遠，飲冰寧有惜。',96,'全唐诗/poet.tang.3000.json','["理棹雖云遠，飲冰寧有惜。", "況乃佳山川，怡然傲潭石。", "奇峰岌前轉，茂樹隈中積。", "猿鳥聲自呼，風泉氣相激。", "目因詭容逆，心與清暉滌。", "紛吾謬執簡，行郡將移檄。", "即事聊獨歡，素懷豈兼適。", "悠悠詠靡盬，庶以窮日夕。"]'),
('0551aa37-4b0b-4818-9966-c4dc46f08a35','使還都湘東作','張九齡','唐','唐诗','tang','','[]','倉庚昨歸候，陽鳥今去時。',108,'全唐诗/poet.tang.3000.json','["倉庚昨歸候，陽鳥今去時。", "感物遽如此，勞生安可思。", "養真無上格，圖進豈前期。", "清節往來苦，壯容離別衰。", "盛明非不遇，弱操自云私。", "孤楫清川泊，征衣寒露滋。", "風朝津樹落，日夕嶺猿悲。", "牽役而無悔，坐愁秪自怡。", "當須報恩已，終爾謝塵緇。"]'),
('1cf44e73-4b66-4a18-b591-324ef9879cd5','冬中至玉泉山寺屬窮陰冰閉崖谷無色及仲春行縣復往焉故有此作','張九齡','唐','唐诗','tang','','[]','靈境信幽絕，芳時重暄妍。',96,'全唐诗/poet.tang.3000.json','["靈境信幽絕，芳時重暄妍。", "再來及茲勝，一遇非無緣。", "萬木柔可結，千花敷欲然。", "松間鳴好鳥，竹下流清泉。", "石壁開精舍，金光照法筵。", "真空本自寂，假有聊相宣。", "復此灰心者，仍追巢頂禪。", "簡書雖有畏，身世亦相捐。"]'),
('3f47878a-5560-49b3-b5bd-ba3d9a67af39','郢城西北有大古冢數十觀其封域多是楚時諸王而年代久遠不復可識唯直西有樊妃冢因後人爲植松柏故行路盡知之','張九齡','唐','唐诗','tang','','[]','蘋藻生南澗，蕙蘭秀中林。',120,'全唐诗/poet.tang.3000.json','["蘋藻生南澗，蕙蘭秀中林。", "嘉名有所在，芳氣無幽深。", "楚子初逞志，樊妃嘗獻箴。", "能令更擇士，非直罷從禽。", "舊國皆湮滅，先王亦莫尋。", "唯傳賢媛隴，猶結後人心。", "牢落山川意，蕭疎松柏陰。", "破牆時直上，荒徑或斜侵。", "惠問終不絕，風流獨至今。", "千春思窈窕，黃鳥復哀音。"]'),
('af03a160-91d9-4287-a65c-280c55f25067','荆州作二首 一','張九齡','唐','唐诗','tang','','[]','先達志其大，求意不約文。',144,'全唐诗/poet.tang.3000.json','["先達志其大，求意不約文。", "士伸在知己，已況仕於君。", "微誠夙所尚，細故不足云。", "時來忽易失，事往良難分。", "顧念凡近姿，焉欲殊常勳。", "亦以行則是，豈必素有聞。", "千慮且猶失，萬緒何其紛。", "進士苟非黨，免相安得羣。", "衆口金可鑠，孤心絲共棼。", "意忠仗朋信，語勇同敗軍。", "古劍徒有氣，幽蘭秪自薰。", "高秩向所忝，於義如浮雲。"]'),
('af6305ad-f7e9-46fb-8b7b-5de448d3800d','荆州作二首 二','張九齡','唐','唐诗','tang','','[]','千載一遭遇，往賢所至難。',156,'全唐诗/poet.tang.3000.json','["千載一遭遇，往賢所至難。", "問余奚爲者，無階忽上摶。", "明聖不世出，翼亮非苟安。", "崇高自有配，孤陋何足干。", "遇恩一時來，竊位三歲寒。", "誰謂誠不盡，知窮力亦殫。", "雖至負乘寇，初無挾術鑽。", "浩蕩出江湖，翻覆如波瀾。", "心傷不材樹，自念獨飛翰。", "徇義在匹夫，報恩猶一餐。", "況乃山海澤，效無毫髮端。", "內訟已慙沮，積毀今摧殘。", "胡爲復惕息，傷鳥畏虛彈。"]'),
('40c2882a-7e79-4915-a77a-95acb7cc4715','在郡秋懷二首 一','張九齡','唐','唐诗','tang','','[]','秋風入前林，蕭瑟鳴高枝。',120,'全唐诗/poet.tang.3000.json','["秋風入前林，蕭瑟鳴高枝。", "寂寞遊子思，寤歎何人知。", "宦成名不立，志存歲已馳。", "五十而無聞，古人深所疵。", "平生去外飾，直道如不羈。", "未得操割效，忽復寒暑移。", "物情自古然，身退毀亦隨。", "悠悠滄江渚，望望白雲涯。", "露下霜且降，澤中草離披。", "蘭艾若不分，安用馨香爲。"]'),
('c7ed65df-dd08-4ffd-b3b5-82911b882ad1','在郡秋懷二首 二','張九齡','唐','唐诗','tang','','[]','庭蕪生白露，歲候感遐心。',84,'全唐诗/poet.tang.3000.json','["庭蕪生白露，歲候感遐心。", "策蹇慙遠途，巢枝思故林。", "小人恐致寇，終日如臨深。", "魚鳥好自逸，池籠安所欽。", "挂冠東都門，採蕨南山岑。", "議道誠愧昔，覽分還愜今。", "憮然憂成老，空爾白頭吟。"]'),
('0e50a01e-f87e-467f-aae6-a4afe5522f07','忝官二十年盡在內職及爲郡嘗積戀因賦詩焉','張九齡','唐','唐诗','tang','','[]','江流去朝宗，晝夜茲不舍。',120,'全唐诗/poet.tang.3000.json','["江流去朝宗，晝夜茲不舍。", "仲尼在川上，子牟存闕下。", "聖達有由然，孰是無心者。", "一郡苟能化，百城豈云寡。", "愛禮誰爲羊，戀主吾猶馬。", "感初時不載，思奮翼無假。", "閑宇常自閉，沈心何用寫。", "攬衣步前庭，登陴臨曠野。", "白水生迢遞，清風寄瀟灑。", "願言采芳澤，終朝不盈把。"]'),
('2911bb59-187e-4e5c-849f-5933d8d352df','二弟宰邑南海見羣鴈南飛因成詠以寄','張九齡','唐','唐诗','tang','','[]','鴻雁自北來，嗷嗷度煙景。',60,'全唐诗/poet.tang.3000.json','["鴻雁自北來，嗷嗷度煙景。", "常懷稻粱惠，豈憚江山永。", "小大每相從，羽毛當自整。", "雙鳧侶晨泛，獨鶴參宵警。", "爲我更南飛，因書至梅嶺。"]'),
('e87b912d-caf9-43b6-b564-8a9449982353','將發還鄉示諸弟','張九齡','唐','唐诗','tang','','[]','歲陽亦頹止，林意日蕭摵。',84,'全唐诗/poet.tang.3000.json','["歲陽亦頹止，林意日蕭摵。", "云胡當此時，緬邁復爲客。", "至愛孰能捨，名義來相迫。", "負德良不貲，輸誠靡所惜。", "一木逢廈構，纖塵願山益。", "無力主君恩，寧利客卿璧。", "去去榮歸養，憮然歎行役。"]'),
('147f1ae8-029a-4488-8cbe-5e3674106bef','敘懷二首 一','張九齡','唐','唐诗','tang','','[]','弱歲讀羣史，抗迹追古人。',48,'全唐诗/poet.tang.3000.json','["弱歲讀羣史，抗迹追古人。", "被褐有懷玉，佩印從負薪。", "志合豈兄弟，道行無賤貧。", "孤根亦何賴，感激此爲鄰。"]'),
('53bec44c-161e-45a2-8382-56f62206125a','敘懷二首 二','張九齡','唐','唐诗','tang','','[]','晚節從卑秩，岐路良非一。',60,'全唐诗/poet.tang.3000.json','["晚節從卑秩，岐路良非一。", "既聞持兩端，復見挾三術。", "木瓜誠有報，玉楮論無實。", "已矣直躬者，平生壯圖失。", "去去勿重陳，歸來茹芝朮。"]'),
('3c490328-1b81-4bbc-9eaf-a23be0a8d648','題畫山水障','張九齡','唐','唐诗','tang','','[]','心累猶不盡，果爲物外牽。',144,'全唐诗/poet.tang.3000.json','["心累猶不盡，果爲物外牽。", "偶因耳目好，復假丹青妍。", "嘗抱野間意，而迫區中緣。", "塵事固已矣，秉意終不遷。", "良工適我願，妙墨揮巖泉。", "變化合羣有，高深侔自然。", "置陳北堂上，倣像南山前。", "靜無戶庭出，行已茲地偏。", "萱草憂可樹，合歡忿益蠲。", "所因本微物，況乃憑幽筌。", "言象會自泯，意色聊自宣。", "對玩有佳趣，使我心渺綿。"]'),
('da66e474-0818-4e11-9b65-2a775faaff04','奉和聖製瑞雪篇','張九齡','唐','唐诗','tang','','[]','萬年春，三朝日，上御明臺旅庭實。',222,'全唐诗/poet.tang.3000.json','["萬年春，三朝日，上御明臺旅庭實。", "初瑞雪兮霏微，俄同雲兮蒙密。", "此時騷切陰風生，先過金殿有餘清。", "信宿嬋娟飛雪度，能使玉人俱掩嫮。", "皓皓樓前月初白，紛紛陌上塵皆素。", "昨訝驕陽積數旬，始知和氣待迎新。", "匪惟在人利，曾是扶天意。", "天意豈云遙，雪下不崇朝。", "皇情玩無斁，雪委方盈尺。", "草樹紛早榮，京坻宛先積。", "君恩誠謂何，歲稔復人和。", "預數斯箱慶，應如此雪多。", "朝冕旒兮載悅，想籉笠兮農節。", "倚瑤琴兮或歌，續薰風兮瑞雪。", "福浸昌，應尤盛，瑞雪年年常感聖。", "願以柏梁作，長爲柳花詠。"]'),
('a2d1123c-827f-4953-a766-5aa6a24f41dd','奉和聖製溫泉歌','張九齡','唐','唐诗','tang','','[]','有時神物待聖人，去後湯還冷，來時樹亦春。',104,'全唐诗/poet.tang.3000.json','["有時神物待聖人，去後湯還冷，來時樹亦春。", "今茲十月自東歸，羽斾逶迤上翠微。", "溫谷葱葱佳氣色，離宮奕奕叶光輝。", "臨渭川，近天邑。", "浴日溫泉復在茲，羣仙洞府那相及。", "吾君利物心，玄澤浸蒼黔。", "漸漬神湯無疾苦，薰歌一曲感人深。"]'),
('b4c9badb-abd9-4465-a1cb-d4aeed309f3b','南郊太尉酌獻武舞作凱安之樂','張九齡','唐','唐诗','tang','','[]','馨香惟后德，明命光天保。',48,'全唐诗/poet.tang.3000.json','["馨香惟后德，明命光天保。", "肅祀崇聖靈，陳信表黃道。", "玉戚初蹈厲，金匏既靜好。", "介福何穰穰，精誠格穹昊。"]'),
('7516502b-d130-4549-899a-8ff5b15b16dd','奉和聖製經孔子舊宅','張九齡','唐','唐诗','tang','','[]','孔門太山下，不見登封時。',48,'全唐诗/poet.tang.3000.json','["孔門太山下，不見登封時。", "徒有先王法，今爲明主思。", "恩加萬乘幸，禮致一牢祠。", "舊宅千年外，光華空在茲。"]'),
('1de3ff7e-d9ec-41f8-ba0c-968b9b27be1c','奉和聖製次瓊嶽韻','張九齡','唐','唐诗','tang','','[]','山祗亦望幸，雲雨見靈心。',48,'全唐诗/poet.tang.3000.json','["山祗亦望幸，雲雨見靈心。", "嶽館逢朝霽，關門解宿陰。", "咸京天上近，清渭日邊臨。", "我武因冬狩，何言是即禽。"]'),
('2edca147-372f-465b-9481-f3d056cd0494','奉和聖製送李尚書入蜀','張九齡','唐','唐诗','tang','','[]','眷言感忠義，何有間山川。',48,'全唐诗/poet.tang.3000.json','["眷言感忠義，何有間山川。", "徇節今如此，離情空復然。", "皇心在勤恤，德澤委昭宣。", "周月成功後，明年或勞還。"]'),
('0eb324f2-ca2a-41e3-bffd-db9a439962ac','奉和聖製初出洛城','張九齡','唐','唐诗','tang','','[]','東土淹龍駕，西人望翠華。',48,'全唐诗/poet.tang.3000.json','["東土淹龍駕，西人望翠華。", "山川祗詢物，宮觀豈爲家。", "十月回星斗，千官捧日車。", "洛陽無怨思，巡幸更非賒。"]'),
('f9c2b5e9-57eb-442f-91a8-aa3a804ed45d','奉和聖製途次陝州作','張九齡','唐','唐诗','tang','','[]','馳道當河陝，陳詩問國風。',48,'全唐诗/poet.tang.3000.json','["馳道當河陝，陳詩問國風。", "川原三晉別，襟帶兩京同。", "後殿函關盡，前旌闕塞通。", "行看洛陽陌，光景麗天中。"]'),
('d344c2d7-81fe-429e-83d6-903921727435','勅賜寧王池宴','張九齡','唐','唐诗','tang','','[]','賢王有池館，明主賜春遊。',48,'全唐诗/poet.tang.3000.json','["賢王有池館，明主賜春遊。", "淑氣林間發，恩光水上浮。", "徒慙和鼎地，終謝巨川舟。", "皇澤空如此，輕生莫可酬。"]'),
('e005d1a3-5710-4762-aa77-b40479deb759','天津橋東旬宴得歌字韻','張九齡','唐','唐诗','tang','','[]','清洛象天河，東流形勝多。',36,'全唐诗/poet.tang.3000.json','["清洛象天河，東流形勝多。", "朝來逢宴喜，春盡却妍和。", "泉鮪歡時躍，林鶯醉裏歌。"]'),
('188162e3-1363-4abf-adc6-76367dcbc45a','上陽水窗旬宴得移字韻','張九齡','唐','唐诗','tang','','[]','河漢非應到，汀洲忽在斯。',48,'全唐诗/poet.tang.3000.json','["河漢非應到，汀洲忽在斯。", "仍逢帝樂下，如逐海槎窺。", "春賞時將換，皇恩歲不移。", "今朝遊宴所，莫比天泉池。"]'),
('d41a9682-a3ed-4712-9bd4-dd04debe2a42','折楊柳','張九齡','唐','唐诗','tang','','[]','纖纖折楊柳，持此寄情人。',48,'全唐诗/poet.tang.3000.json','["纖纖折楊柳，持此寄情人。", "一枝何足貴，憐是故園春。", "遲景那能久，芳菲不及新。", "更愁征戍客，容鬢老邊塵。"]'),
('19a55ab9-3ecd-4a29-a3da-9c39965d34d3','剪綵','張九齡','唐','唐诗','tang','','[]','姹女矜容色，爲花不讓春。',48,'全唐诗/poet.tang.3000.json','["姹女矜容色，爲花不讓春。", "既爭芳意早，誰待物華真。", "葉作參差發，枝從點綴新。", "自然無限態，長在豔陽晨。"]'),
('9cf781b5-1221-4251-99ab-10b0e82ff8b1','和崔黃門寓直夜聽蟬之作','張九齡','唐','唐诗','tang','','[]','蟬嘶玉樹枝，向夕惠風吹。',48,'全唐诗/poet.tang.3000.json','["蟬嘶玉樹枝，向夕惠風吹。", "幸入連宵聽，應緣飲露知。", "思深秋欲近，聲靜夜相宜。", "不是黃金飾，清香徒爾爲。"]'),
('d9f94e75-7799-4224-b67d-46dc4a82fda6','和姚令公從幸溫湯喜雪','張九齡','唐','唐诗','tang','','[]','萬乘飛黃馬，千金狐白裘。',48,'全唐诗/poet.tang.3000.json','["萬乘飛黃馬，千金狐白裘。", "正逢銀霰積，如向玉京遊。", "瑞色鋪馳道，花文拂綵旒。", "還聞吉甫頌，不共郢歌儔。"]'),
('4fb78b5e-232d-42ef-87a6-f47c68e8782f','立春日晨起對積雪','張九齡','唐','唐诗','tang','','[]','忽對林亭雪，瑤華處處開。',48,'全唐诗/poet.tang.3000.json','["忽對林亭雪，瑤華處處開。", "今年迎氣始，昨夜伴春回。", "玉潤窗前竹，花繁院裏梅。", "東郊齋祭所，應見五神來。"]'),
('9073ebeb-6c93-4eee-82d1-552596d2c299','三月三日申王園亭宴集','張九齡','唐','唐诗','tang','','[]','稽亭追往事，睢苑勝前聞。',48,'全唐诗/poet.tang.3000.json','["稽亭追往事，睢苑勝前聞。", "飛閣凌芳樹，華池落綵雲。", "藉草人留酌，銜花鳥赴羣。", "向來同賞處，惟恨碧林曛。"]'),
('11d5c4f4-3e16-46ff-9b0d-49af0d413412','三月三日登龍山','張九齡','唐','唐诗','tang','','[]','伊川與灞津，今日祓除人。',48,'全唐诗/poet.tang.3000.json','["伊川與灞津，今日祓除人。", "豈似龍山上，還同湘水濱。", "衰顏憂更老，淑景望非春。", "禊飲豈吾事，聊將偶俗塵。"]'),
('cca1d03f-9fc2-4224-9538-1353ebea09e9','和王司馬折梅寄京邑昆弟','張九齡','唐','唐诗','tang','','[]','離別念同嬉，芬榮欲共持。',48,'全唐诗/poet.tang.3000.json','["離別念同嬉，芬榮欲共持。", "獨攀南國樹，遙寄北風時。", "林惜迎春早，花愁去日遲。", "還聞折梅處，更有棣華詩。"]'),
('b3c37ba4-57d4-4878-8b68-a2a4dd510fbf','晚霽登王六東閣','張九齡','唐','唐诗','tang','','[]','試上江樓望，初逢山雨晴。',48,'全唐诗/poet.tang.3000.json','["試上江樓望，初逢山雨晴。", "連空青嶂合，向晚白雲生。", "彼美要殊觀，蕭條見遠情。", "情來不可極，日暮水流清。"]'),
('5a42ae27-27d3-4ee0-a186-61359c052d0d','蘇侍郎紫薇庭各賦一物得芍藥','張九齡','唐','唐诗','tang','','[]','仙禁生紅藥，微芳不自持。',48,'全唐诗/poet.tang.3000.json','["仙禁生紅藥，微芳不自持。", "幸因清切地，還遇豔陽時。", "名見桐君籙，香聞鄭國詩。", "孤根若可用，非直愛華滋。"]'),
('13df8265-8a72-4922-876d-f84a855147fe','和黃門盧侍御詠竹','張九齡','唐','唐诗','tang','','[]','清切紫庭垂，葳蕤防露枝。',48,'全唐诗/poet.tang.3000.json','["清切紫庭垂，葳蕤防露枝。", "色無玄月變，聲有惠風吹。", "高節人相重，虛心世所知。", "鳳皇佳可食，一去一來儀。"]'),
('6033ba59-b72c-464e-905f-402fd9815ce7','和韋尚書答梓州兄南亭宴集','張九齡','唐','唐诗','tang','','[]','棠棣聞餘興，烏衣有舊遊。',48,'全唐诗/poet.tang.3000.json','["棠棣聞餘興，烏衣有舊遊。", "門前杜城陌，池上曲江流。", "暇日嘗繁會，清風詠阻修。", "始知西峙嶽，同氣此相求。"]'),
('d5efb2a8-0a4b-417e-9e6a-b4143f7c873b','答陳拾遺贈竹簪','張九齡','唐','唐诗','tang','','[]','與君嘗此志，因物復知心。',48,'全唐诗/poet.tang.3000.json','["與君嘗此志，因物復知心。", "遺我龍鍾節，非無玳瑁簪。", "幽素宜相重，雕華豈所任。", "爲君安首飾，懷此代兼金。"]'),
('97898374-3327-49fe-b8be-ed6b11467aed','贈澧陽韋明府','張九齡','唐','唐诗','tang','','[]','君有百鍊刃，堪斷七重犀。',48,'全唐诗/poet.tang.3000.json','["君有百鍊刃，堪斷七重犀。", "誰開太阿匣，持割武城雞。", "竟與尚書佩，遙應天子提。", "何時遇操宰，當使玉如泥。"]'),
('a139bdc0-f4d6-48f1-9307-fec05f07cc38','在洪州答綦毋學士','張九齡','唐','唐诗','tang','','[]','旬雨不愆期，由來自若時。',48,'全唐诗/poet.tang.3000.json','["旬雨不愆期，由來自若時。", "爾無言郡政，吾豈欲天欺。", "常念涓塵益，惟歡草樹滋。", "課成非所擬，人望在東菑。"]'),
('1c5a804a-eddf-4b2b-8c7b-619262e61644','酬王六霽後書懷見示','張九齡','唐','唐诗','tang','','[]','雲雨俱行罷，江天已洞開。',48,'全唐诗/poet.tang.3000.json','["雲雨俱行罷，江天已洞開。", "炎氛霽後滅，邊緒望中來。", "作驥君垂耳，爲魚我曝鰓。", "更憐湘水賦，還是洛陽才。"]'),
('fc671646-3d93-42f6-a6d4-d5372b7b6c98','酬王六寒朝見詒','張九齡','唐','唐诗','tang','','[]','賈生流寓日，揚子寂寥時。',48,'全唐诗/poet.tang.3000.json','["賈生流寓日，揚子寂寥時。", "在物多相背，唯君獨見思。", "漁爲江上曲，雪作郢中詞。", "忽枉兼金訊，長懷伐木詩。"]'),
('ba228114-4d41-4101-94ee-b52c283ff21b','林亭詠','張九齡','唐','唐诗','tang','','[]','穿築非求麗，幽閑欲寄情。',48,'全唐诗/poet.tang.3000.json','["穿築非求麗，幽閑欲寄情。", "偶懷因壤石，真意在蓬瀛。", "苔益山文古，池添竹氣清。", "從茲果蕭散，無事亦無營。"]'),
('fb4d6479-b750-43ee-ae45-b0437fe1c2fe','晨出郡舍林下','張九齡','唐','唐诗','tang','','[]','晨興步北林，蕭散一開襟。',48,'全唐诗/poet.tang.3000.json','["晨興步北林，蕭散一開襟。", "復見林上月，娟娟猶未沈。", "片雲自孤遠，叢篠亦清深。", "無事由來貴，方知物外心。"]'),
('4e4866df-2a83-41a2-8efa-58ee7cdb40a6','園中時蔬盡皆鋤理唯秋蘭數本委而不顧彼雖一物有足悲者遂賦二章 一','張九齡','唐','唐诗','tang','','[]','場藿已成歲，園葵亦向陽。',48,'全唐诗/poet.tang.3000.json','["場藿已成歲，園葵亦向陽。", "蘭時獨不偶，露節漸無芳。", "旨異菁爲蓄，甘非蔗有漿。", "人多利一飽，誰復惜馨香。"]'),
('3f97a646-fec0-4cf6-9046-0d0036d6a8c5','園中時蔬盡皆鋤理唯秋蘭數本委而不顧彼雖一物有足悲者遂賦二章 二','張九齡','唐','唐诗','tang','','[]','幸得不鋤去，孤苗守舊根。',48,'全唐诗/poet.tang.3000.json','["幸得不鋤去，孤苗守舊根。", "無心羨旨蓄，豈欲近名園。", "遇賞寧充佩，爲生莫礙門。", "幽林芳意在，非是爲人論。"]'),
('23e2d526-e11f-41ef-981b-57f7370a74a8','林亭寓言','張九齡','唐','唐诗','tang','','[]','林居逢歲晏，遇物使情多。',48,'全唐诗/poet.tang.3000.json','["林居逢歲晏，遇物使情多。", "蘅茝不時與，芬榮奈汝何。", "更憐籬下菊，無如松上蘿。", "因依自有命，非是隔陽和。"]'),
('dfc774df-bb8d-44ab-a247-2bc9489b53a5','送使廣州','張九齡','唐','唐诗','tang','','[]','家在湘源住，君今海嶠行。',48,'全唐诗/poet.tang.3000.json','["家在湘源住，君今海嶠行。", "經過正中道，相送倍爲情。", "心逐書郵去，形隨世網嬰。", "因聲謝遠別，緣義不緣名。"]'),
('bbe82cd9-bd55-436d-9679-dd020a7f6351','送姚評事入蜀各賦一物得卜肆','張九齡','唐','唐诗','tang','','[]','蜀嚴化已久，沈冥空所思。',48,'全唐诗/poet.tang.3000.json','["蜀嚴化已久，沈冥空所思。", "嘗聞賣卜處，猶憶下簾時。", "驅傳應經此，懷賢倘問之。", "歸來說往事，歷歷偶心期。"]'),
('6a55d88c-4103-4c14-ac32-3f32dc37165c','送竇校書見餞得雲中辨江樹','張九齡','唐','唐诗','tang','','[]','江水天連色，無涯淨野氛。',48,'全唐诗/poet.tang.3000.json','["江水天連色，無涯淨野氛。", "微明岸傍樹，凌亂渚前雲。", "舉棹形徐轉，登艫意漸分。", "渺茫從此去，空復惜離羣。"]'),
('b12c6595-cb59-4fb0-8ca0-d7d968f1b80b','餞王司馬入計同用洲字','張九齡','唐','唐诗','tang','','[]','元僚行上計，舉餞出林丘。',48,'全唐诗/poet.tang.3000.json','["元僚行上計，舉餞出林丘。", "忽望題輿遠，空思解榻遊。", "別筵鋪柳岸，征棹倚蘆洲。", "獨歎湘江水，朝宗向北流。"]'),
('34f23f2b-7a80-457f-bf9d-b70627c5f87a','東湖臨泛餞王司馬','張九齡','唐','唐诗','tang','','[]','南土秋雖半，東湖草未黃。',48,'全唐诗/poet.tang.3000.json','["南土秋雖半，東湖草未黃。", "聊乘風日好，來汎芰荷香。", "蘭棹無勞速，菱歌不厭長。", "忽懷京洛去，難與共清光。"]'),
('1558a170-9f05-4a1a-b907-b9f6061f4772','餞濟陰梁明府各探一物得荷葉','張九齡','唐','唐诗','tang','','[]','荷葉生幽渚，芳華信在茲。',48,'全唐诗/poet.tang.3000.json','["荷葉生幽渚，芳華信在茲。", "朝朝空此地，采采欲因誰。", "但恐星霜改，還將蒲稗衰。", "懷君美人別，聊以贈心期。"]'),
('e5e6b70c-4597-432b-a708-f5ada9e13f24','餞陳學士還江南同用徵字','張九齡','唐','唐诗','tang','','[]','荷蓧旋江澳，銜杯餞霸陵。',48,'全唐诗/poet.tang.3000.json','["荷蓧旋江澳，銜杯餞霸陵。", "別前林鳥息，歸處海煙凝。", "風土鄉情接，雲山客念憑。", "聖朝巖穴選，應待鶴書徵。"]'),
('ca7182a2-f81a-421d-bc68-0c0bae3fd6f7','通化門外送別','張九齡','唐','唐诗','tang','','[]','屢別容華改，長愁意緒微。',48,'全唐诗/poet.tang.3000.json','["屢別容華改，長愁意緒微。", "義將私愛隔，情與故人歸。", "薄宦無時賞，勞生有事機。", "離魂今夕夢，先繞舊林飛。"]'),
('5f5da44a-6a8d-4b0f-a9a5-857a973c415e','送楊道士往天台','張九齡','唐','唐诗','tang','','[]','鬼谷還成道，天台去學仙。',48,'全唐诗/poet.tang.3000.json','["鬼谷還成道，天台去學仙。", "行應松子化，留與世人傳。", "此地煙波遠，何時羽駕旋？", "當須一把袂，城郭共依然。"]'),
('7c1ec5aa-1eb4-4032-8579-42bbbd7c8670','送楊府李功曹','張九齡','唐','唐诗','tang','','[]','平生屬良友，結綬望光輝。',48,'全唐诗/poet.tang.3000.json','["平生屬良友，結綬望光輝。", "何知人事拙，相與宦情非。", "別路穿林盡，征帆際海歸。", "居然已多意，況復兩鄉違。"]'),
('b6bcc932-0955-4662-b64b-9ea6a2a73e66','送宛句趙少府','張九齡','唐','唐诗','tang','','[]','解巾行作吏，尊酒謝離居。',48,'全唐诗/poet.tang.3000.json','["解巾行作吏，尊酒謝離居。", "修竹含清景，華池澹碧虛。", "地將幽興愜，人與舊遊疎。", "林下紛相送，多逢長者車。"]'),
('a7dd5fb5-96d1-4f6b-a198-c2e605d0b359','送韋城李少府','張九齡','唐','唐诗','tang','','[]','送客南昌尉，離亭西候春。',48,'全唐诗/poet.tang.3000.json','["送客南昌尉，離亭西候春。", "野花看欲盡，林鳥聽猶新。", "別酒青門路，歸軒白馬津。", "相知無遠近，萬里尚爲鄰。"]'),
('a5b88d32-d064-4302-86ba-19c61fc38ee0','送蘇主簿赴偃師','張九齡','唐','唐诗','tang','','[]','我與文雄別，胡然邑吏歸。',48,'全唐诗/poet.tang.3000.json','["我與文雄別，胡然邑吏歸。", "賢人安下位，鷙鳥欲卑飛。", "激節輕華冕，移官徇綵衣。", "羨君行樂處，從此拜庭闈。"]'),
('4b187d7e-54d5-4cc5-a628-ca6ff1e8aff2','送廣州周判官','張九齡','唐','唐诗','tang','','[]','海郡雄蠻落，津亭壯越臺。',48,'全唐诗/poet.tang.3000.json','["海郡雄蠻落，津亭壯越臺。", "城隅百雉映，水曲萬家開。", "里樹桄榔出，時禽翡翠來。", "觀風猶未盡，早晚使車回。"]'),
('d8dc1ddd-7118-41a3-890d-87f1bab28bd5','郡江南上別孫侍御','張九齡','唐','唐诗','tang','','[]','雲嶂天涯盡，川途海縣窮。',48,'全唐诗/poet.tang.3000.json','["雲嶂天涯盡，川途海縣窮。", "何言此地僻，忽與故人同。", "身負邦君弩，情紆御史驄。", "王程不我駐，離思逐秋風。"]'),
('a57157fe-1c91-4a8e-aadf-8e7fb3960359','道逢北使題贈京邑親知','張九齡','唐','唐诗','tang','','[]','征驂稍靡靡，去國方遲遲。',36,'全唐诗/poet.tang.3000.json','["征驂稍靡靡，去國方遲遲。", "路遶南登岸，情搖北上旗。", "故人憐別日，旅雁逐歸時。"]'),
('a723ee45-fd85-45da-a5b2-d6b7b1eea48f','江上使風呈裴宣州耀卿','張九齡','唐','唐诗','tang','','[]','江路與天連，風帆何淼然。',48,'全唐诗/poet.tang.3000.json','["江路與天連，風帆何淼然。", "遙林浪出沒，孤舫鳥聯翩。", "常愛千鈞重，深思萬事捐。", "報恩非徇祿，還逐賈人船。"]'),
('1d24c666-2922-4463-af1b-d48f6478c5e6','溪行寄王震','張九齡','唐','唐诗','tang','','[]','山氣朝來爽，溪流日向清。',48,'全唐诗/poet.tang.3000.json','["山氣朝來爽，溪流日向清。", "遠心何處愜，閑棹此中行。", "叢桂林間待，羣鷗水上迎。", "徒然適我願，幽獨爲誰情。"]'),
('88477520-e0c5-4d15-a954-9f9220baf4e9','自豫章南還江上作','張九齡','唐','唐诗','tang','','[]','歸去南江水，磷磷見底清。',48,'全唐诗/poet.tang.3000.json','["歸去南江水，磷磷見底清。", "轉逢空闊處，聊洗滯留情。", "浦樹遙如待，江鷗近若迎。", "津途別有趣，況乃濯吾纓。"]'),
('61fe0569-f66c-4834-9ca8-5eb868ea75a8','將至岳陽有懷趙二','張九齡','唐','唐诗','tang','','[]','湘岸多深林，青冥晝結陰。',48,'全唐诗/poet.tang.3000.json','["湘岸多深林，青冥晝結陰。", "獨無謝客賞，況復賈生心。", "草色雖云發，天光或未臨。", "江潭非所遇，爲爾白頭吟。"]'),
('5c815659-b86f-4140-9788-9793892a5186','使還湘水','張九齡','唐','唐诗','tang','','[]','歸舟宛何處，正值楚江平。',48,'全唐诗/poet.tang.3000.json','["歸舟宛何處，正值楚江平。", "夕逗煙村宿，朝緣浦樹行。", "于役已彌歲，言旋今愜情。", "鄉郊尚千里，流目夏雲生。"]'),
('c19a2ef2-1c93-4628-9e8e-5f2aa9af14eb','初發道中寄遠','張九齡','唐','唐诗','tang','','[]','日夜鄉山遠，秋風復此時。',48,'全唐诗/poet.tang.3000.json','["日夜鄉山遠，秋風復此時。", "舊聞胡馬思，今聽楚猿悲。", "念別朝昏苦，懷歸歲月遲。", "壯圖空不息，常恐髮如絲。"]'),
('3ed6cca5-92e3-4d79-95b3-30fe0233ea46','自湘水南行','張九齡','唐','唐诗','tang','','[]','落日摧行舫，逶迤洲渚間。',48,'全唐诗/poet.tang.3000.json','["落日摧行舫，逶迤洲渚間。", "雖云有物役，乘此更休閑。", "暝色生前浦，清暉發近山。", "中流澹容與，唯愛鳥飛還。"]'),
('7891eecb-7315-4992-8d23-dc1bc1670655','初入湘中有喜','張九齡','唐','唐诗','tang','','[]','征鞍窮郢路，歸棹入湘流。',48,'全唐诗/poet.tang.3000.json','["征鞍窮郢路，歸棹入湘流。", "望鳥唯貪疾，聞猿亦罷愁。", "兩邊楓作岸，數處橘爲洲。", "却記從來意，翻疑夢裏遊。"]'),
('300b1a29-6dbc-4978-8ae7-ec7d96df209c','耒陽溪夜行','張九齡','唐','唐诗','tang','','[]','乘夕棹歸舟，緣源路轉幽。',48,'全唐诗/poet.tang.3000.json','["乘夕棹歸舟，緣源路轉幽。", "月明看嶺樹，風靜聽溪流。", "嵐氣船間入，霜華衣上浮。", "猿聲雖此夜，不是別家愁。"]'),
('c95cedce-aa0e-438e-9beb-90a4ed153f90','江上','張九齡','唐','唐诗','tang','','[]','長林何繚繞，遠水復悠悠。',48,'全唐诗/poet.tang.3000.json','["長林何繚繞，遠水復悠悠。", "盡日餘無見，爲心那不愁。", "憶將親愛別，行爲主恩酬。", "感激空如此，芳時屢已遒。"]'),
('a042fcab-021e-4560-9dd1-d476d3e2328a','自彭蠡湖初入江','張九齡','唐','唐诗','tang','','[]','江岫殊空闊，雲煙處處浮。',48,'全唐诗/poet.tang.3000.json','["江岫殊空闊，雲煙處處浮。", "上來羣噪鳥，中去獨行舟。", "牢落誰相顧，逶迤日自愁。", "更將心問影，于役復何求。"]'),
('13ee2e38-b7b8-4dba-90b2-b5738ac9bee1','赴使瀧峽','張九齡','唐','唐诗','tang','','[]','溪路日幽深，寒空入兩嶔。',48,'全唐诗/poet.tang.3000.json','["溪路日幽深，寒空入兩嶔。", "霜清百丈水，風落萬重林。", "夕鳥聯歸翼，秋猿斷去心。", "別離多遠思，況乃歲方陰。"]'),
('e9632216-d53c-4548-9fd7-da40dabefaba','湖口望廬山瀑布泉','張九齡','唐','唐诗','tang','','["\u5e90\u5c71", "\u7011\u5e03", "\u5c71\u6c34", "\u6c34"]','萬丈洪泉落，迢迢半紫氛。',48,'全唐诗/poet.tang.3000.json','["萬丈洪泉落，迢迢半紫氛。", "奔飛流雜樹，灑落出重雲。", "日照虹蜺似，天清風雨聞。", "靈山多秀色，空水共氤氳。"]'),
('9bab835c-8def-41e0-8c90-f1fe9a2daded','湞陽峽','張九齡','唐','唐诗','tang','','[]','行舟傍越岑，窈窕越溪深。',48,'全唐诗/poet.tang.3000.json','["行舟傍越岑，窈窕越溪深。", "水闇先秋冷，山晴當晝陰。", "重林間五色，對壁聳千尋。", "惜此生遐遠，誰知造化心。"]'),
('95b1af8f-0e27-4687-913c-9c3e79dc9ee4','使至廣州','張九齡','唐','唐诗','tang','','[]','昔年嘗不調，茲地亦邅回。',48,'全唐诗/poet.tang.3000.json','["昔年嘗不調，茲地亦邅回。", "本謂雙鳧少，何知駟馬來。", "人非漢使橐，郡是越王臺。", "去去雖殊事，山川長在哉。"]'),
('ad75cadd-fdf6-4c6b-a5bd-f12486a2ecd7','春江晚景','張九齡','唐','唐诗','tang','','[]','江林多秀發，雲日復相鮮。',48,'全唐诗/poet.tang.3000.json','["江林多秀發，雲日復相鮮。", "征路那逢此，春心益渺然。", "興來秪自得，佳氣莫能傳。", "薄暮津亭下，餘花滿客船。"]'),
('37d74b17-1103-41a3-b832-e32f2b03cdb5','與王六履震廣州津亭曉望','張九齡','唐','唐诗','tang','','[]','明發臨前渚，寒來淨遠空。',48,'全唐诗/poet.tang.3000.json','["明發臨前渚，寒來淨遠空。", "水紋天上碧，日氣海邊紅。", "景物紛爲異，人情賴此同。", "乘槎自有適，非欲破長風。"]'),
('1557ae63-96b7-4dc5-b746-ccdcdb4894b8','初發曲江溪中','張九齡','唐','唐诗','tang','','[]','溪流清且深，松石復陰臨。',48,'全唐诗/poet.tang.3000.json','["溪流清且深，松石復陰臨。", "正爾可嘉處，胡爲無賞心。", "我由不忍別，物亦有緣侵。", "自匪常行邁，誰能知此音。"]'),
('c3d15485-8c59-4c34-8dd6-6af82c3850ef','旅宿淮陽亭口號','張九齡','唐','唐诗','tang','','[]','日暮荒亭上，悠悠旅思多。',48,'全唐诗/poet.tang.3000.json','["日暮荒亭上，悠悠旅思多。", "故鄉臨桂水，今夜渺星河。", "暗草霜華發，空亭雁影過。", "興來誰與晤，勞者自爲歌。"]'),
('2c152693-c25f-45ce-8ef2-cbedce1a62bc','望月懷遠','張九齡','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u4e2d\u79cb\u8282", "\u4e2d\u79cb", "\u601d\u4e61", "\u4e94\u8a00\u5f8b\u8bd7"]','海上生明月，天涯共此時。',48,'全唐诗/poet.tang.3000.json','["海上生明月，天涯共此時。", "情人怨遙夜，竟夕起相思。", "滅燭憐光滿，披衣覺露滋。", "不堪盈手贈，還寢夢佳期。"]'),
('d5c133e9-5a0b-4a8b-b9e5-dae5a857d1ab','秋夕望月','張九齡','唐','唐诗','tang','','[]','清逈江城月，流光萬里同。',48,'全唐诗/poet.tang.3000.json','["清逈江城月，流光萬里同。", "所思如夢裏，相望在庭中。", "皎潔青苔露，蕭條黃葉風。", "含情不得語，頻使桂華空。"]'),
('72f8a535-743c-42b8-ae57-d7d132468013','詠燕','張九齡','唐','唐诗','tang','','["\u5bd3\u4eba", "\u548f\u7269", "\u8bbd\u523a", "\u5199\u9e1f", "\u548f\u7269\u8bd7", "\u9e1f"]','海燕何微眇，乘春亦蹔來。',48,'全唐诗/poet.tang.3000.json','["海燕何微眇，乘春亦蹔來。", "豈知泥滓賤，秪見玉堂開。", "繡戶時雙入，華軒日幾回。", "無心與物競，鷹隼莫相猜。"]'),
('7acd3a73-d651-4c92-a43a-296916662ff3','故刑部李尚書荆谷山集會','張九齡','唐','唐诗','tang','','[]','嘗聞繼老耼，身退道彌耽。',48,'全唐诗/poet.tang.3000.json','["嘗聞繼老耼，身退道彌耽。", "結宇倚青壁，疎泉噴碧潭。", "苔石隨人古，煙花寄酒酣。", "山光紛向夕，歸興杜城南。"]'),
('203572ad-e792-4418-9ea5-fe0683a817b7','戲題春意','張九齡','唐','唐诗','tang','','[]','一作江南守，江林三四春。',48,'全唐诗/poet.tang.3000.json','["一作江南守，江林三四春。", "相鳴不及鳥，相樂喜關人。", "日守朱絲直，年催華髮新。", "淮陽秪有臥，持此度芳辰。"]'),
('27c8012f-a33e-46aa-88aa-39d936052b42','庭梅詠','張九齡','唐','唐诗','tang','','[]','芳意何能早，孤榮亦自危。',48,'全唐诗/poet.tang.3000.json','["芳意何能早，孤榮亦自危。", "更憐花蔕弱，不受歲寒移。", "朝雪那相妬，陰風已屢吹。", "馨香雖尚爾，飄蕩復誰知。"]'),
('41083533-dfc2-4cd9-8fcf-c556295c1561','聽箏','張九齡','唐','唐诗','tang','','[]','端居正無緒，那復發秦箏。',48,'全唐诗/poet.tang.3000.json','["端居正無緒，那復發秦箏。", "纖指傳新意，繁絃起怨情。", "悠揚思欲絕，掩抑態還生。", "豈是聲能感，人心自不平。"]'),
('72e57a19-316e-4a1c-98fd-021000e9faaa','初秋憶金均兩弟','張九齡','唐','唐诗','tang','','[]','江渚秋風至，他鄉離別心。',48,'全唐诗/poet.tang.3000.json','["江渚秋風至，他鄉離別心。", "孤雲愁自遠，一葉感何深。", "憂喜嘗同域，飛鳴忽異林。", "青山西北望，堪作白頭吟。"]'),
('7f724f80-bfea-4a7a-9389-89f2cbba6ecb','秋懷','張九齡','唐','唐诗','tang','','[]','感惜芳時換，誰知客思懸。',36,'全唐诗/poet.tang.3000.json','["感惜芳時換，誰知客思懸。", "憶隨鴻向煖，愁學馬思邊。", "留滯機還息，紛拏網自牽。"]'),
('d8639576-404f-4384-ad76-055f85aafc23','故刑部李尚書挽詞三首 一','張九齡','唐','唐诗','tang','','[]','仙宗出趙北，相業起山東。',48,'全唐诗/poet.tang.3000.json','["仙宗出趙北，相業起山東。", "明德嘗爲禮，嘉謀屢作忠。", "論經白虎殿，獻賦甘泉宮。", "與善今何在？蒼生望已空。"]'),
('cb22f551-1b39-4c82-9a56-e5f17de07a59','故刑部李尚書挽詞三首 二','張九齡','唐','唐诗','tang','','[]','宿昔三台踐，榮華駟馬歸。',48,'全唐诗/poet.tang.3000.json','["宿昔三台踐，榮華駟馬歸。", "印從青瑣拜，翰入紫宸揮。", "題劍恩方重，藏舟事已非。", "龍門不可望，感激涕沾衣。"]'),
('f664c11b-b1cd-42b9-b4f0-68b47e616ec7','故刑部李尚書挽詞三首 三','張九齡','唐','唐诗','tang','','[]','永歎常山寶，沈埋京兆阡。',48,'全唐诗/poet.tang.3000.json','["永歎常山寶，沈埋京兆阡。", "同盟會五月，華表記千年。", "渺漫野中草，微茫空裏煙。", "共悲人事絕，唯對杜陵田。"]'),
('4046bbe3-745d-4653-a42b-af497a04c4b1','故徐州刺史贈吏部侍郎蘇公挽歌詞三首 一','張九齡','唐','唐诗','tang','','[]','韋玄方繼相，荀爽復齊名。',48,'全唐诗/poet.tang.3000.json','["韋玄方繼相，荀爽復齊名。", "在貴兼天爵，能賢出世卿。", "學聞金馬詔，神見玉人清。", "藏壑今如此，爲山遂不成。"]'),
('b517389a-315d-479e-8ee5-6aaa35c5cb93','故徐州刺史贈吏部侍郎蘇公挽歌詞三首 二','張九齡','唐','唐诗','tang','','[]','相如只謝病，子敬忽云亡。',48,'全唐诗/poet.tang.3000.json','["相如只謝病，子敬忽云亡。", "豈悟瑤臺雪，分彫玉樹行。", "清規留草議，故事在封章。", "本謂山公啓，而今歿始揚。"]'),
('f882d209-a819-41aa-b0e7-eefa30d620f0','故徐州刺史贈吏部侍郎蘇公挽歌詞三首 三','張九齡','唐','唐诗','tang','','[]','返葬長安陌，秋風簫鼓悲。',48,'全唐诗/poet.tang.3000.json','["返葬長安陌，秋風簫鼓悲。", "奈何相送者，不是平生時。", "寒影催年急，哀歌助晚遲。", "寧知建旟罷，丹旐向京師。"]'),
('b13ce6a7-15ab-46be-864e-316461c5dac4','故滎陽君蘇氏挽歌詞三首 一','張九齡','唐','唐诗','tang','','[]','門緒公侯列，嬪風詩禮行。',48,'全唐诗/poet.tang.3000.json','["門緒公侯列，嬪風詩禮行。", "松蘿方有寄，桃李忽無成。", "劍去雙龍別，雛哀九鳳鳴。", "何言嶧山樹，還似半心生。"]'),
('cc61c182-9db8-40d1-8303-40632cb307e3','故滎陽君蘇氏挽歌詞三首 二','張九齡','唐','唐诗','tang','','[]','永歎芳魂斷，行看草露滋。',36,'全唐诗/poet.tang.3000.json','["永歎芳魂斷，行看草露滋。", "二宗榮盛日，千古別離時。", "竟罷生芻贈，空留畫扇悲。"]'),
('606510b9-3076-41d4-84ce-5506da876a38','故滎陽君蘇氏挽歌詞三首 三','張九齡','唐','唐诗','tang','','[]','縞服紛相送，玄扃翳不開。',48,'全唐诗/poet.tang.3000.json','["縞服紛相送，玄扃翳不開。", "更悲泉火滅，徒見柳車回。", "舊室容衣奠，新塋拱樹栽。", "唯應月照簟，潘岳此時哀。"]'),
('7fa31da6-049e-47e3-a047-bc04819324f7','眉州康司馬挽歌詞','張九齡','唐','唐诗','tang','','[]','家受專門學，人稱入室賢。',48,'全唐诗/poet.tang.3000.json','["家受專門學，人稱入室賢。", "劉楨徒有氣，管輅獨無年。", "謫去長沙國，魂歸京兆阡。", "從茲匣中劒，埋沒罷衝天。"]'),
('269d23e5-8f96-4b3b-91ff-a2132b3b1b5e','奉和聖製早發三鄉山行','張九齡','唐','唐诗','tang','','[]','羽衞森森西向秦，山川歷歷在清晨。',64,'全唐诗/poet.tang.3000.json','["羽衞森森西向秦，山川歷歷在清晨。", "晴雲稍卷寒巖樹，宿雨能銷御路塵。", "聖德由來合天道，靈符即此應時巡。", "遺賢一一皆羈致，猶欲高深訪隱淪。"]'),
('5be90f21-23ca-4bb2-bc76-7f0d3a4d1673','奉和聖製龍池篇','張九齡','唐','唐诗','tang','','[]','天啓神龍生碧泉，泉水靈源浸迤延。',64,'全唐诗/poet.tang.3000.json','["天啓神龍生碧泉，泉水靈源浸迤延。", "飛龍已向珠潭出，積水仍將銀漢連。", "岸傍花柳看勝畫，浦上樓臺問是仙。", "我后元符從此得，方爲萬歲壽圖川。"]'),
('8719e483-1fbe-4129-a9a8-f8dcc36c30db','奉和聖製南郊禮畢酺宴','張九齡','唐','唐诗','tang','','[]','配天昭聖業，率土慶輝光。',96,'全唐诗/poet.tang.3000.json','["配天昭聖業，率土慶輝光。", "春發三條路，酺開百戲場。", "流恩均庶品，縱觀聚康莊。", "妙舞來平樂，新聲出建章。", "分曹日抱戴，赴節鳳歸昌。", "幸奏承雲樂，同晞湛露陽。", "氣和皆有感，澤厚自無疆。", "飽德君臣醉，連歌奉柏梁。"]'),
('2db5d9c4-0672-4c67-a17c-3d62ed5d766f','奉和聖製早渡蒲津關','張九齡','唐','唐诗','tang','','[]','魏武中流處，軒皇問道回。',72,'全唐诗/poet.tang.3000.json','["魏武中流處，軒皇問道回。", "長堤春樹發，高掌曙雲開。", "龍負王舟渡，人占仙氣來。", "河津會日月，天仗役風雷。", "東顧重關盡，西馳萬國陪。", "還聞股肱郡，元首詠康哉。"]'),
('c1c5152c-16ba-4e50-a59d-2a53fe35727e','奉和聖製同二相南出雀鼠谷','張九齡','唐','唐诗','tang','','[]','設險諸侯地，承平聖主巡。',72,'全唐诗/poet.tang.3000.json','["設險諸侯地，承平聖主巡。", "東君朝二月，南斾擁三辰。", "寒出重關盡，年隨行漏新。", "瑞雲叢捧日，芳樹曲迎春。", "舞詠先馳道，恩華及從臣。", "汾川花鳥意，併奉屬車塵。"]'),
('210fff42-e5ab-417b-892b-b7a8a00ca875','奉和聖製經河上公廟','張九齡','唐','唐诗','tang','','[]','昔者河邊叟，誰知隱與仙。',72,'全唐诗/poet.tang.3000.json','["昔者河邊叟，誰知隱與仙。", "姓名終不識，章句此空傳。", "跡爲坐忘晦，言猶强著詮。", "精靈竟何所，祠宇獨依然。", "道在紆宸睠，風行動睿篇。", "從茲化天下，清淨復何先。"]'),
('9d419996-527b-4c14-ba4c-4afac74fdf3f','奉和聖製送尚書燕國公赴朔方','張九齡','唐','唐诗','tang','','["\u79bb\u522b", "\u5199\u4eba"]','宗臣事有征，廟筭在休兵。',120,'全唐诗/poet.tang.3000.json','["宗臣事有征，廟筭在休兵。", "天與三台座，人當萬里城。", "朔南方偃革，河右暫揚旌。", "寵錫從仙禁，光華出漢京。", "山川勤遠畧，原隰軫皇情。", "爲奏薰琴唱，仍題寶劒名。", "聞風六郡伏，計日五戎平。", "山甫歸應疾，留侯功復成。", "歌鍾旋可望，袵席豈難行。", "四牡何時入？吾君憶履聲。"]'),
('7a247db3-7220-4022-8dde-432207780fdf','奉和聖製途經華山','張九齡','唐','唐诗','tang','','[]','萬乘華山下，千巖雲漢中。',72,'全唐诗/poet.tang.3000.json','["萬乘華山下，千巖雲漢中。", "靈居雖窅密，睿覽忽玄同。", "日月臨高掌，神仙仰大風。", "攢峯勢岌岌，翊輦氣雄雄。", "揆物知幽贊，銘勳表聖衷。", "會應陪玉檢，來此告成功。"]'),
('a3037a96-1e76-4013-81e5-0dfd06cfb7e1','奉和聖製早登太行山率爾言志','張九齡','唐','唐诗','tang','','[]','孟月攝提貞，乘時我后征。',96,'全唐诗/poet.tang.3000.json','["孟月攝提貞，乘時我后征。", "晨嚴九折度，暮戒六軍行。", "日御馳中道，風師卷太清。", "戈鋋林表出，組練雪間明。", "動植希皇豫，高深奉睿情。", "陪遊七聖列，望幸百神迎。", "氣色煙猶喜，恩光草尚榮。", "之罘稱萬歲，今此復同聲。"]'),
('9257c85b-961c-4165-a20e-bb58fd8bd2b5','奉和聖製登封禮畢洛城酺宴','張九齡','唐','唐诗','tang','','[]','大君畢能事，端扆樂成功。',72,'全唐诗/poet.tang.3000.json','["大君畢能事，端扆樂成功。", "運與千齡合，歡將萬國同。", "漢酺歌聖酒，韶樂舞薰風。", "河洛榮光遍，雲煙喜氣通。", "春華頓覺早，天澤倍知崇。", "草木皆沾被，猶言不在躬。"]'),
('04dc7abc-8daa-4bcb-9742-401b0794ee12','恩賜樂遊園宴應制','張九齡','唐','唐诗','tang','','[]','寶筵延厚命，供帳序羣公。',72,'全唐诗/poet.tang.3000.json','["寶筵延厚命，供帳序羣公。", "形勝宜春接，威儀建禮同。", "晞陽人似露，解慍物從風。", "朝慶千齡始，年華二月中。", "輝光遍草木，和氣發絲桐。", "歲歲無爲化，寧知樂九功。"]'),
('c61bcca0-a99e-4fab-a50f-5946a66d74f1','奉和聖製過王濬墓','張九齡','唐','唐诗','tang','','[]','漢王思鉅鹿，晉將在弘農。',72,'全唐诗/poet.tang.3000.json','["漢王思鉅鹿，晉將在弘農。", "入蜀舉長筭，平吳成大功。", "與渾雖不協，歸皓實爲雄。", "孤績淪千載，流名感聖衷。", "萬乘度荒隴，一顧凜生風。", "古節猶不棄，今人爭效忠。"]'),
('715a22f8-0e05-4628-a8f4-f791f59b40a5','奉和吏部崔尚書雨後大明朝堂望南山','張九齡','唐','唐诗','tang','','[]','迢遞終南頂，朝朝閶闔前。',168,'全唐诗/poet.tang.3000.json','["迢遞終南頂，朝朝閶闔前。", "朅來青綺外，高在翠微先。", "雙鳳褰爲闕，羣龍儼若仙。", "還知到玄圃，更是謁甘泉。", "夜雨塵初滅，秋空月正懸。", "詭容紛入望，霽色宛成妍。", "東極華陰踐，西彌嶓冢連。", "奔峰出嶺外，瀑水落雲邊。", "漢帝宮將苑，商君陌與阡。", "林華鋪近甸，煙靄遶晴川。", "既庶仁斯及，分憂政已宣。", "山公啓事罷，吉甫頌聲傳。", "濟濟金門步，洋洋玉樹篇。", "徒歌雖有屬，清越豈同年。"]'),
('3a9517b6-1069-4c7e-8094-748f968d753b','和崔尚書喜雨','張九齡','唐','唐诗','tang','','[]','積陽雖有晦，經月未爲灾。',120,'全唐诗/poet.tang.3000.json','["積陽雖有晦，經月未爲灾。", "上念人天重，先祈雲漢回。", "仁心及草木，號令起風雷。", "照爛陰霞止，交紛瑞雨來。", "三辰破黍稷，四達屏氛埃。", "池溜因添滿，林芳爲灑開。", "聽中聲滴瀝，望處影徘徊。", "惠澤成豐歲，昌言發上才。", "無論驗石鼓，不是御雲臺。", "直頌皇恩浹，崇朝遍九垓。"]'),
('babd64aa-067a-412e-bd4c-c3b648d1073c','和許給事中直夜簡諸公','張九齡','唐','唐诗','tang','','[]','未央鐘漏晚，仙宇藹沈沈。',96,'全唐诗/poet.tang.3000.json','["未央鐘漏晚，仙宇藹沈沈。", "武衞千廬合，嚴扃萬戶深。", "左掖知天近，南窗見月臨。", "樹搖金掌露，庭徙玉樓陰。", "他日聞更直，中宵屬所欽。", "聲華大國寶，夙夜近臣心。", "逸興乘高閣，雄飛在禁林。", "寧思竊抃者，情發爲知音。"]'),
('7dfb6a8c-7ed7-4465-81a8-1cabe04b849d','和蘇侍郎小園夕霽寄諸弟','張九齡','唐','唐诗','tang','','[]','清風閶闔至，軒蓋承明歸。',72,'全唐诗/poet.tang.3000.json','["清風閶闔至，軒蓋承明歸。", "雲月愛秋景，林堂開夜扉。", "何言兼濟日，尚與宴私違。", "興逐蒹葭變，文因棠棣飛。", "人倫用忠孝，帝德已光輝。", "贈弟今爲貴，方知陸氏微。"]'),
('c453b832-1154-4a91-9e86-0779f5be008c','酬宋使君見贈之作','張九齡','唐','唐诗','tang','','[]','時來不自意，宿昔謬樞衡。',72,'全唐诗/poet.tang.3000.json','["時來不自意，宿昔謬樞衡。", "翊聖負明主，妨賢媿友生。", "罷歸猶右職，待罪尚南荆。", "政有留棠舊，風因繼組成。", "高軒問疾苦，烝庶荷仁明。", "衰廢時所薄，秪言僚故情。"]'),
('fba326d3-cb69-495b-8612-790a89eca98c','酬宋使君見詒','張九齡','唐','唐诗','tang','','[]','陟鄰初稟訓，獻策幸逢時。',72,'全唐诗/poet.tang.3000.json','["陟鄰初稟訓，獻策幸逢時。", "朝列且云忝，君恩復若茲。", "庭闈際海曲，軺傳荷天慈。", "顧己歡烏鳥，聞君泣素絲。", "才明應主召，福善豈神欺。", "但願白心在，終然湼不淄。"]'),
('4302630e-3456-4ecd-95c7-d4f05d69ed86','酬通事舍人寓直見示篇中兼起居陸舍人景獻','張九齡','唐','唐诗','tang','','[]','軒掖殊清秘，才華固在斯。',96,'全唐诗/poet.tang.3000.json','["軒掖殊清秘，才華固在斯。", "興因膏澤灑，情與惠風吹。", "所美應人譽，何私亦我儀。", "同聲感喬木，比翼謝長離。", "價以陸生減，賢慙鮑叔知。", "薄遊嘗獨媿，芳訊乃兼施。", "此夜金閨籍，伊人瓊樹枝。", "飛鳴復何遠，相顧幸媞媞。"]'),
('21ab2af9-7d1e-4ddb-ac11-d98f8ebac600','與袁補闕尋蔡拾遺會此公出行後蔡有五韻詩見贈以此篇答焉','張九齡','唐','唐诗','tang','','[]','轍迹陳家巷，詩書孟子鄰。',48,'全唐诗/poet.tang.3000.json','["轍迹陳家巷，詩書孟子鄰。", "偶來乘興者，不值草玄人。", "契是忘年合，情非累日申。", "聞君還薄暮，見眷及茲辰。"]'),
('28b38efa-5ae8-4a62-a1fd-bbe1fb46841f','酬趙二侍御使西軍贈兩省舊僚之作','張九齡','唐','唐诗','tang','','[]','石室先鳴者，金門待制同。',96,'全唐诗/poet.tang.3000.json','["石室先鳴者，金門待制同。", "操刀嘗願割，持斧竟稱雄。", "應敵兵初起，緣邊虜欲空。", "使車經隴月，征斾繞河風。", "忽枉兼金訊，非徒秣馬功。", "氣清蒲海曲，聲滿柏臺中。", "顧己塵華省，欣君震遠戎。", "明時獨匪報，嘗欲退微躬。"]'),
('7f5f278a-dde9-4ec0-84b0-9a15110bc045','武司功初有幽庭春暄見貽夏首獲見以詩報焉','張九齡','唐','唐诗','tang','','[]','芳月盡離居，幽懷重起予。',72,'全唐诗/poet.tang.3000.json','["芳月盡離居，幽懷重起予。", "雖言春事晚，尚想物華初。", "遲日皦方照，高齋澹復虛。", "笋成林向密，花落樹應疎。", "贈鯉情無間，求鶯思有餘。", "暄妍不相待，含歎欲焉如。"]'),
('bda16b93-239d-418f-b1d6-bb842bb88d22','酬王履震遊園林見貽','張九齡','唐','唐诗','tang','','[]','宅生惟海縣，素業守郊園。',180,'全唐诗/poet.tang.3000.json','["宅生惟海縣，素業守郊園。", "中覽霸王說，上徼明主恩。", "一行罷蘭徑，數載歷金門。", "既負潘生拙，俄從周任言。", "逶迤戀軒陛，蕭散反丘樊。", "舊逕稀人跡，前池耗水痕。", "併看芳樹老，唯覺敝廬存。", "自我棲幽谷，逢君翳覆盆。", "孟軻應有命，賈誼得無冤。", "江上行傷遠，林間偶避喧。", "地偏人事絕，時霽鳥聲繁。", "獨善心俱閉，窮居道共尊。", "樂因南澗藻，憂豈北堂萱。", "幽意加投漆，新詩重贈軒。", "平生徇知己，窮達與君論。"]'),
('b404320a-cd54-40b0-a061-33d056514162','餞王尚書出邊','張九齡','唐','唐诗','tang','','[]','漢相推人傑，殷宗伐鬼方。',120,'全唐诗/poet.tang.3000.json','["漢相推人傑，殷宗伐鬼方。", "還聞出將重，坐見即戎良。", "上策應爲豫，中權且用光。", "令申兵氣倍，威憺虜魂亡。", "樹比公孫大，城如道濟長。", "夏雲登隴首，秋露泫遼陽。", "武德舒宸睠，文思餞樂章。", "感恩身既許，激節膽猶嘗。", "祖帳傾朝列，軍麾駐道傍。", "詩人何所詠，尚父欲鷹揚。"]'),
('bfcd275c-5a0c-43e6-9ecf-265ccab08b7b','送趙都護赴安西','張九齡','唐','唐诗','tang','','[]','將相有更踐，簡心良獨難。',96,'全唐诗/poet.tang.3000.json','["將相有更踐，簡心良獨難。", "遠圖嘗畫地，超拜乃登壇。", "戎即崑山序，車同渤海單。", "義無中國費，情必遠人安。", "他日文兼武，而今栗且寬。", "自然來月窟，何用刺樓蘭。", "南至三冬晚，西馳萬里寒。", "封侯自有處，征馬去嘽嘽。"]'),
('0cc342c6-de4a-4bb8-bd8a-aa10cb9ba715','奉使自藍田玉山南行','張九齡','唐','唐诗','tang','','[]','征驂入雲壑，始憶步金門。',144,'全唐诗/poet.tang.3000.json','["征驂入雲壑，始憶步金門。", "通籍微軀幸，歸途明主恩。", "匪唯徇行役，兼得慰晨昏。", "是節暑云熾，紛吾心所尊。", "海縣且悠緬，山郵日駿奔。", "徒知惡囂事，未暇息陰論。", "嶢武經陳迹，衡湘指故園。", "水聞南澗險，煙望北林繁。", "遠靄千巖合，幽聲百籟喧。", "陰泉夏猶凍，陽景晝方暾。", "懿此高深極，徒令夢想存。", "盛明期有報，長往復奚言。"]'),
('a6ef17e6-53df-41a1-8b83-dde7dffbcf27','賀給事嘗詣蔡起居郊館有詩因命同作','張九齡','唐','唐诗','tang','','[]','記言聞直史，築室面層阿。',60,'全唐诗/poet.tang.3000.json','["記言聞直史，築室面層阿。", "豈不承明入，終云幽意多。", "沈冥高士致，休澣故人過。", "前嶺遊氛滅，中林芳氣和。", "茲辰阻佳趣，望美獨如何。"]'),
('83c77296-bbc6-4528-84cf-d52b67fead5a','南山下舊居閑放','張九齡','唐','唐诗','tang','','[]','秪役已云久，乘閑返服初。',120,'全唐诗/poet.tang.3000.json','["秪役已云久，乘閑返服初。", "塊然屏塵事，幽獨坐林閭。", "清曠前山遠，紛喧此地疎。", "喬木凌青靄，修篁媚綠渠。", "耳和繡翼鳥，目暢錦鱗魚。", "寂寞心還間，飄颻體自虛。", "興來命旨酒，臨罷閱仙書。", "但樂多幽意，寧知有毀譽。", "尚想爭名者，誰云要路居。", "都忘下流歎，傾奪竟何如。"]'),
('8c445310-bbba-4296-89aa-e2bf7c7976a6','高齋閑望言懷','張九齡','唐','唐诗','tang','','[]','高齋復晴景，延眺屬清秋。',72,'全唐诗/poet.tang.3000.json','["高齋復晴景，延眺屬清秋。", "風物動歸思，煙林生遠愁。", "紛吾自窮海，薄宦此中州。", "取路無高足，隨波適下流。", "歲華空冉冉，心曲且悠悠。", "坐惜芳時歇，胡然久滯留。"]'),
('ee8be0b9-f285-47aa-bfa6-74c9feda6dac','別鄉人南還','張九齡','唐','唐诗','tang','','[]','橘柚南中暖，桑榆北地陰。',72,'全唐诗/poet.tang.3000.json','["橘柚南中暖，桑榆北地陰。", "何言榮落異，因見別離心。", "吾亦江鄉子，思歸夢寐深。", "聞君去水宿，結思渺雲林。", "牽綴從浮事，遲回謝所欽。", "東南行舫遠，秋浦念猿吟。"]'),
('bcf7db91-d7f3-486d-9807-167aa32d25bc','初發江陵有懷','張九齡','唐','唐诗','tang','','[]','極望涔陽浦，江天渺不分。',72,'全唐诗/poet.tang.3000.json','["極望涔陽浦，江天渺不分。", "扁舟從此去，鷗鳥自爲羣。", "他日懷真賞，中年負俗紛。", "適來果微尚，倏爾會斯文。", "復想金閨籍，何如夢渚雲。", "我行多勝寄，浩思獨氛氳。"]'),
('f9a41ff5-2b5b-4cc7-92d6-b4635c404196','同綦毋學士月夜聞雁','張九齡','唐','唐诗','tang','','[]','棲宿豈無意，飛飛更遠尋。',72,'全唐诗/poet.tang.3000.json','["棲宿豈無意，飛飛更遠尋。", "長途未及半，中夜有遺音。", "月思關山笛，風號流水琴。", "空聲兩相應，幽感一何深。", "避繳歸南浦，離羣呌北林。", "聯翩俱不定，憐爾越鄉心。"]'),
('333dbe31-11a2-47fb-be67-3f5e921453be','登總持寺閣','張九齡','唐','唐诗','tang','','[]','香閣起崔嵬，高高沙版開。',72,'全唐诗/poet.tang.3000.json','["香閣起崔嵬，高高沙版開。", "攀躋千仞上，紛詭萬形來。", "草間商君陌，雲重漢后臺。", "山從函谷斷，川向斗城回。", "林裏春容變，天邊客思催。", "登臨信爲美，懷遠獨悠哉。"]'),
('74db8f91-a97e-41ee-8f4e-f44f28ad1c03','晚憩王少府東閣','張九齡','唐','唐诗','tang','','[]','披軒肆流覽，雲壑見深重。',72,'全唐诗/poet.tang.3000.json','["披軒肆流覽，雲壑見深重。", "空水秋彌淨，林煙晚更濃。", "坐隅分洞府，簷際列羣峰。", "窈窕生幽意，參差多異容。", "還慙大隱跡，空想列仙蹤。", "賴此昇攀處，蕭條得所從。"]'),
('8fe5a07c-c814-40ba-86d1-97edf1524e92','登城樓望西山作','張九齡','唐','唐诗','tang','','[]','城樓枕南浦，日夕顧西山。',84,'全唐诗/poet.tang.3000.json','["城樓枕南浦，日夕顧西山。", "宛宛鸞鶴處，高高煙霧間。", "仙井今猶在，洪厓久不還。", "金編莫我授，羽駕亦難攀。", "簷際千峰出，雲中一鳥閑。", "縱觀窮水國，游思徧人寰。", "勿復塵埃事，歸來且閉關。"]'),
('00532c2f-0a00-4d72-9983-54ab4f6aa63f','祠紫蓋山經玉泉山寺','張九齡','唐','唐诗','tang','','[]','指塗躋楚望，策馬傍荆岑。',122,'全唐诗/poet.tang.3000.json','["指塗躋楚望，策馬傍荆岑。", "稍稍松篁入，泠泠磵谷深。", "觀奇逐幽暎，歷險忘嶇嶔。", "上界投佛影，中天揚梵音。", "焚香懺在昔，禮足誓來今。", "靈異若有對，神仙真可尋。", "高僧聞逝者，遠俗是初心。", "蘚駁經行處，猿啼燕坐林。", "歸真已寂滅，留迹豈[湮沈]。", "法地自茲廣，何云千萬金。"]'),
('846fe4c1-7800-4c19-bd05-9d1e0e72fda9','洪州西山祈雨是日輒應因賦詩言事','張九齡','唐','唐诗','tang','','[]','茲山蘊靈異，走望良有歸。',156,'全唐诗/poet.tang.3000.json','["茲山蘊靈異，走望良有歸。", "丘禱雖已久，甿心難重違。", "遲明申藻薦，先夕旅巖扉。", "獨宿雲峰下，蕭條人吏稀。", "我來不外適，幽抱自中微。", "靜入風泉奏，涼生松栝圍。", "窮年滯遠想，寸晷閱清暉。", "虛美悵無屬，素情緘所依。", "詭隨嫌弱操，羇束謝貞肥。", "義濟亦吾道，誠存爲物祈。", "靈心倏已應，甘液幸而飛。", "閉閣且無責，隨車安敢希。", "多慙德不感，知復是耶非。"]'),
('3ddb2f27-5e26-445e-b486-59bad0c9df97','經江寧覽舊跡至玄武湖','張九齡','唐','唐诗','tang','','[]','南國更數世，北湖方十洲。',168,'全唐诗/poet.tang.3000.json','["南國更數世，北湖方十洲。", "天清華林苑，日晏景陽樓。", "果下回仙騎，津傍駐綵斿。", "鳧鷖喧鳳管，荷芰鬬龍舟。", "七子陪詩賦，千人和棹謳。", "應言在鎬樂，不讓橫汾秋。", "風俗因紓慢，江山成易由。", "駒王信不武，孫叔是無謀。", "佳氣日將歇，霸功誰與修。", "桑田東海變，麋鹿姑蘇遊。", "否運爭三國，康時劣九州。", "山雖幕府在，館豈豫章留。", "水淀還相閱，菱歌亦故遒。", "雄圖不足問，唯想事風流。"]'),
('b19be9f9-c4b5-4350-a9ca-3282d42a1876','登襄陽峴山','張九齡','唐','唐诗','tang','','[]','昔年亟攀踐，征馬復來過。',96,'全唐诗/poet.tang.3000.json','["昔年亟攀踐，征馬復來過。", "信若山川舊，誰如歲月何。", "蜀相吟安在，羊公碣已磨。", "令圖猶寂寞，嘉會亦蹉跎。", "宛宛樊城岸，悠悠漢水波。", "逶迤春日遠，感寄客情多。", "地本原林秀，朝來煙景和。", "同心不同賞，留歎此巖阿。"]'),
('c6a7496f-f4ae-47b8-9a60-4cce8b3e9514','登荆州城樓','張九齡','唐','唐诗','tang','','[]','天宇何其曠，江城坐自拘。',168,'全唐诗/poet.tang.3000.json','["天宇何其曠，江城坐自拘。", "層樓百餘尺，迢遞在西隅。", "暇日時登眺，荒郊臨故都。", "纍纍見陳迹，寂寂想雄圖。", "古往山川在，今來郡邑殊。", "北疆雖入鄭，東距豈防吳。", "幾代傳荆國，當時敵陝郛。", "上流空有處，中土復何虞。", "枕席夷三峽，關梁豁五湖。", "承平無異境，守隘莫論夫。", "自罷金門籍，來參竹使符。", "端居向林藪，微尚在桑榆。", "直似王陵戇，非如甯武愚。", "今茲對南浦，乘雁與雙鳧。"]'),
('ad6efc28-bd02-431b-a9f6-ed68b86c32e1','登樂遊原春望書懷','張九齡','唐','唐诗','tang','','[]','城隅有樂遊，表裏見皇州。',120,'全唐诗/poet.tang.3000.json','["城隅有樂遊，表裏見皇州。", "策馬既長遠，雲山亦悠悠。", "萬壑清光滿，千門喜氣浮。", "花間直城路，草際曲江流。", "憑眺茲爲美，離居方獨愁。", "已驚玄髮換，空度綠荑柔。", "奮翼籠中鳥，歸心海上鷗。", "既傷日月逝，且欲桑榆收。", "豹變焉能及，鶯鳴非可求。", "願言從所好，初服返林丘。"]'),
('607a04c7-d6b4-438b-b053-28330e5edee6','候使登石頭驛樓作','張九齡','唐','唐诗','tang','','[]','山檻憑南望，川途眇北流。',96,'全唐诗/poet.tang.3000.json','["山檻憑南望，川途眇北流。", "遠林天翠合，前浦日華浮。", "萬井緣津渚，千艘咽渡頭。", "漁商多末事，耕稼少良疇。", "自守陳蕃榻，嘗登王粲樓。", "徒然騁目處，豈是獲心遊。", "向跡雖愚谷，求名異盜丘。", "息陰芳木所，空復越鄉憂。"]'),
('df9eafc9-2f72-4d49-95e5-e6cfc390b67d','登臨沮樓','張九齡','唐','唐诗','tang','','[]','高深不可厭，巡屬復來過。',84,'全唐诗/poet.tang.3000.json','["高深不可厭，巡屬復來過。", "本與衆山絕，況茲韶景和。", "危樓入水倒，飛檻向空摩。", "雜樹緣青壁，樛枝掛綠蘿。", "潭清能徹底，魚樂好跳波。", "有象言雖具，無端思轉多。", "同懷不在此，孤賞欲如何。"]'),
('42fbff3e-da06-41ca-a472-7fd4fcca0476','陪王司馬登薛公逍遙臺','張九齡','唐','唐诗','tang','','[]','嘗聞薛公淚，非直雍門琴。',120,'全唐诗/poet.tang.3000.json','["嘗聞薛公淚，非直雍門琴。", "竄逐留遺迹，悲涼見此心。", "府中因暇豫，江上幸招尋。", "人事已成古，風流獨至今。", "閑情多感歎，清景暫登臨。", "無復甘棠在，空餘蔓草深。", "晴光送遠目，勝氣入幽襟。", "水去朝滄海，春來換碧林。", "賦懷湘浦弔，碑想漢川沈。", "曾是陪遊日，徒爲梁父吟。"]'),
('2306ecf4-6204-48b4-bf1b-471f5b0d2f96','嘗與大理丞袁公太府丞田公偶詣一所林沼尤勝因並坐其次相得甚歡遂賦詩焉以詠其事','張九齡','唐','唐诗','tang','','[]','方駕與吾友，同懷不異尋。',96,'全唐诗/poet.tang.3000.json','["方駕與吾友，同懷不異尋。", "偶逢池竹處，便會江湖心。", "夏近林方密，春餘水更深。", "清華兩輝暎，閑步亦窺臨。", "蘋藻復佳色，鳧鷖亦好音。", "韶芳媚洲渚，蕙氣襲衣襟。", "蕭散皆爲樂，裴回從所欽。", "謂予成夙志，歲晚共抽簪。"]'),
('bb02eaa9-b1ff-4334-94b6-d4bae0364548','與弟遊家園','張九齡','唐','唐诗','tang','','[]','定省榮君賜，來歸是晝遊。',72,'全唐诗/poet.tang.3000.json','["定省榮君賜，來歸是晝遊。", "林烏飛舊里，園果讓新秋。", "枝長南庭樹，池臨北澗流。", "星霜屢爾別，蘭麝爲誰幽。", "善積家方慶，恩深國未酬。", "棲棲將義動，安得久情留。"]'),
('d67944c6-1a69-4e14-8a34-d1e81adb5d30','郡內閑齋','張九齡','唐','唐诗','tang','','[]','郡閣晝常掩，庭蕪日復滋。',60,'全唐诗/poet.tang.3000.json','["郡閣晝常掩，庭蕪日復滋。", "簷風落鳥毳，窗葉掛蟲絲。", "拙病宦情少，羇閑秋氣悲。", "理人無異績，爲郡但經時。", "唯有江湖意，沈冥空在茲。"]'),
('4e5c4641-1081-43ab-bad5-09758953056f','城南隅山池春中田袁二公盛稱其美夏首獲賞果會夙言故有此詠','張九齡','唐','唐诗','tang','','[]','憶昨聞佳境，駕言尋昔蹊。',120,'全唐诗/poet.tang.3000.json','["憶昨聞佳境，駕言尋昔蹊。", "非惟初物變，亦與舊遊暌。", "幽渚爲君說，清晨即我攜。", "途深獨睥睨，歷險共攀躋。", "林笋苞青籜，津楊委綠荑。", "荷香初出浦，草色復緣堤。", "樂處將鷗狎，譚端用馬齊。", "且言臨海郡，兼話武陵溪。", "異壤風煙絕，空山巖逕迷。", "如何際朝野，從此待金閨。"]'),
('32ae4c66-5f9c-4c4e-99a5-f3f96a6bc680','西江夜行','張九齡','唐','唐诗','tang','','["\u601d\u5ff5"]','遙夜人何在，澄潭月裏行。',60,'全唐诗/poet.tang.3000.json','["遙夜人何在，澄潭月裏行。", "悠悠天宇曠，切切故鄉情。", "外物寂無擾，中流澹自清。", "念歸林葉換，愁坐露華生。", "猶有汀洲鶴，宵分乍一鳴。"]'),
('a7d247e1-9365-4ae1-a8a6-3cfb3a00c64d','南還湘水言懷','張九齡','唐','唐诗','tang','','[]','拙宦今何有？勞歌念不成。',72,'全唐诗/poet.tang.3000.json','["拙宦今何有？勞歌念不成。", "十年乖夙志，一別悔前行。", "歸去田園老，倘來軒冕輕。", "江間稻正熟，林裏桂初榮。", "魚意思在藻，鹿心懷食苹。", "時哉苟不達，取樂遂吾情。"]'),
('070a223a-8a82-4657-b6b8-c4e1f43dedad','商洛山行懷古','張九齡','唐','唐诗','tang','','[]','園綺值秦末，嘉遁此山阿。',108,'全唐诗/poet.tang.3000.json','["園綺值秦末，嘉遁此山阿。", "陳迹向千古，荒途始一過。", "碩人久淪謝，喬木自森羅。", "故事昔嘗覽，遺風今豈訛。", "泌泉空活活，樵叟獨皤皤。", "是處清暉滿，從中幽興多。", "長懷赤松意，復憶紫芝歌。", "避世辭軒冕，逢時解薜蘿。", "盛明今在運，吾道竟如何。"]'),
('6bba0358-1035-49e3-a711-8a527144a9f5','南還以詩代書贈京師舊僚','張九齡','唐','唐诗','tang','','[]','薄宦晨昏闕，尊尊義取斯。',288,'全唐诗/poet.tang.3000.json','["薄宦晨昏闕，尊尊義取斯。", "窮愁年貌改，寂歷爾胡爲。", "不諂詞多忤，無容禮益卑。", "微生尚何有？遠跡固其宜。", "思擾梁山曲，情遙越鳥枝。", "故園從海上，良友邈天涯。", "雲雨歎一別，川原勞載馳。", "上慙伯樂顧，中負叔牙知。", "去國誠寥落，經途弊險巇。", "歲逢霜雪苦，林屬蕙蘭萎。", "欲贈幽芳歇，行悲舊賞移。", "一從關作限，兩見月成規。", "苒苒窮年籥，行行盡路岐。", "征鞍稅北渚，歸帆指南垂。", "樹晚猶葱蒨，江寒尚渺瀰。", "土風從楚別，山水入湘奇。", "石瀨相奔觸，煙林更蔽虧。", "層崖夾洞浦，輕舸汎澄漪。", "松篠行皆傍，禽魚動輙隨。", "惜哉邊地隔，不與故人窺。", "疇昔陪鵷鷺，朝陽振羽儀。", "來音雖寂寞，接景每逶迤。", "朝罷冥塵事，賓來話酒巵。", "邀歡逐芳草，結興選華池。"]'),
('ae688214-c442-4f7e-9a74-d2e9d79579c6','初發道中贈王司馬兼寄諸公','張九齡','唐','唐诗','tang','','[]','昔歲嘗陳力，中年退屏居。',216,'全唐诗/poet.tang.3000.json','["昔歲嘗陳力，中年退屏居。", "承顏方弄鳥，放性或觀魚。", "曾是安疵拙，誠非議卷舒。", "林園事益簡，煙月賞恆餘。", "不意棲愚谷，無階奉詔書。", "湛恩均大造，弱植媿空虛。", "肅命趨仙闕，僑裝撫傳車。", "念行開祖帳，憐別降題輿。", "誰謂風期許，叨延禮數殊。", "義沾投分末，情及解攜初。", "追餞扶江介，光輝燭里閭。", "子雲應寂寞，公叔爲吹噓。", "景物春來異，音容日向疎。", "川原行稍穩，鐘鼓聽猶徐。", "林隔王公轝，雲迷班氏廬。", "戀親唯委咽，思德更躊躇。", "徇義當由此，懷安乃闕如。", "願酬明主惠，行矣豈徒歟。"]'),
('04bfef48-2092-46e2-b281-691f11218f6a','自始興溪夜上赴嶺','張九齡','唐','唐诗','tang','','[]','嘗蓄名山意，茲爲世網牽。',84,'全唐诗/poet.tang.3000.json','["嘗蓄名山意，茲爲世網牽。", "征途屢及此，初服已非然。", "日落青巖際，溪行綠篠邊。", "去舟乘月後，歸鳥息人前。", "數曲迷幽嶂，連圻觸闇泉。", "深林風緒結，遙夜客情懸。", "非梗胡爲泛，無膏亦自煎。"]'),
('9c4fd614-e2f8-40f5-ae94-0631da4aae47','當塗界寄裴宣州','張九齡','唐','唐诗','tang','','[]','故人宣城守，亦在江南偏。',108,'全唐诗/poet.tang.3000.json','["故人宣城守，亦在江南偏。", "如何分虎竹，相與間山川。", "章綬胡爲者，形骸非自然。", "含情津渡闊，倚望脰空延。", "遠近聞佳政，平生仰大賢。", "推心徒有屬，會面良無緣。", "日夕遵前渚，江村投暮煙。", "念行秪意默，懷遠豈言宣。", "委曲風波事，難爲尺素傳。"]'),
('cf065298-f718-445a-b21c-58400a224299','郡中每晨興輙見羣鶴東飛至暮又行列而返哢唳雲路甚和樂焉予媿獨處江城常目送此意有所羨遂賦以詩','張九齡','唐','唐诗','tang','','["\u957f\u6c5f"]','雲間有數鶴，撫翼意無違。',72,'全唐诗/poet.tang.3000.json','["雲間有數鶴，撫翼意無違。", "曉日東田去，煙霄北渚歸。", "歡呼良自適，羅列好相依。", "遠集長江靜，高翔衆鳥稀。", "豈煩仙子馭，何畏野人機。", "却念乘軒者，拘留不得飛。"]'),
('14ba7616-50c4-4e67-b70c-0bdfe7bf8853','和裴侍中承恩拜掃旋轡途中有懷寄州縣官僚鄉國親故','張九齡','唐','唐诗','tang','','[]','嵩嶽神惟降，汾川鼎氣雄。',96,'全唐诗/poet.tang.3000.json','["嵩嶽神惟降，汾川鼎氣雄。", "生才作霖雨，繼代有清通。", "天下稱賢相，朝端挹至公。", "自家來佐國，移孝入爲忠。", "霜露多前感，丘園想舊風。", "扈巡過晉北，問俗到河東。", "便道恩華降，還鄉禮教崇。", "野尊延故老，朝服見兒童。"]'),
('94b9c1e7-9b5f-4925-bd3d-9499f3f1e4ec','和姚令公哭李尚書乂','張九齡','唐','唐诗','tang','','[]','貴賤雖殊等，平生竊下風。',120,'全唐诗/poet.tang.3000.json','["貴賤雖殊等，平生竊下風。", "雲泥勢已絕，山海納還通。", "忽歎登龍者，翻將弔鶴同。", "琴詩猶可託，劍履獨成空。", "疇昔嘗論禮，興言每匪躬。", "人思崔琰議，朝掩祭遵公。", "作善神何酷，依仁命不融。", "天文虛北斗，人事罷南宮。", "上幸既傷舊，下流彌感衷。", "無恩報國士，徒欲問玄穹。"]'),
('867975bd-fcc1-4ee1-8deb-c622153a120d','奉和聖製經函谷關作','張九齡','唐','唐诗','tang','','["\u9ec4\u6cb3"]','函谷雖云險，黃河已復清。',24,'全唐诗/poet.tang.3000.json','["函谷雖云險，黃河已復清。", "聖心無所隔，空此置關城。"]'),
('bfbc2f65-71d4-4e4e-9302-860a216c61ad','奉和聖製度潼關口號','張九齡','唐','唐诗','tang','','[]','嶙嶙故城壘，荒涼空戍樓。',24,'全唐诗/poet.tang.3000.json','["嶙嶙故城壘，荒涼空戍樓。", "在德不在險，方知王道休。"]'),
('2fd7e235-ba25-4420-972b-404e43b902d3','答太常靳博士見贈一絕','張九齡','唐','唐诗','tang','','[]','上苑春先入，中園花盡開。',24,'全唐诗/poet.tang.3000.json','["上苑春先入，中園花盡開。", "唯餘幽徑草，尚待日光催。"]'),
('5ee8b55c-6446-4693-910e-b05e72617faa','登荆州城望江二首 一','張九齡','唐','唐诗','tang','','[]','滔滔大江水，天地相終始。',24,'全唐诗/poet.tang.3000.json','["滔滔大江水，天地相終始。", "經閱幾世人，復歎誰家子。"]'),
('47703350-cf8c-46e9-82a3-0b8e5a1c3963','登荆州城望江二首 二','張九齡','唐','唐诗','tang','','[]','東望何悠悠，西來晝夜流。',24,'全唐诗/poet.tang.3000.json','["東望何悠悠，西來晝夜流。", "歲月既如此，爲心那不愁。"]'),
('e2535853-d394-4b17-ac90-30bfc859324f','賦得自君之出矣','張九齡','唐','唐诗','tang','','["\u95fa\u6028", "\u76f8\u601d", "\u5987\u5973", "\u4e50\u5e9c"]','自君之出矣，不復理殘機。',24,'全唐诗/poet.tang.3000.json','["自君之出矣，不復理殘機。", "思君如滿月，夜夜減清輝。"]'),
('bbe33e07-c234-4caa-bd28-60991e3e5312','荅陸澧','張九齡','唐','唐诗','tang','','["\u7530\u56ed"]','松葉堪爲酒，春來釀幾多。',24,'全唐诗/poet.tang.3000.json','["松葉堪爲酒，春來釀幾多。", "不辭山路遠，踏雪也相過。"]'),
('d56f2525-ba42-4af3-98f8-d95adc8364aa','奉和上元酺宴應詔','楊炯','唐','唐诗','tang','','[]','甲乙遇災年，周隋送上弦。',288,'全唐诗/poet.tang.3000.json','["甲乙遇災年，周隋送上弦。", "妖星六丈出，沴氣七重懸。", "赤縣空無主，蒼生欲問天。", "龜龍開寶命，雲火昭靈慶。", "萬物覩真人，千秋逢聖政。", "祖宗玄澤遠，文武休光盛。", "大號域中平，皇威天下驚。", "參辰昭文物，宇宙浹聲名。", "漢后三章令，周王五伐兵。", "匈奴窮地角，本自遠正朔。", "驕子起天街，由來虧禮樂。", "一衣掃風雨，再戰夷屯剝。", "清明日月旦，蕭索煙雲渙。", "寒暑既平分，陰陽復貞觀。", "惟神諧妙物，乃聖符幽贊。", "下武發禎祥，平階屬會昌。", "金泥封日觀，璧水匝明堂。", "業盛勳華德，興包天地皇。", "孝思義罔極，易禮光前式。", "天煥三辰輝，靈書五雲色。", "敬時窮發歛，卜代盈千億。", "五緯聚華軒，重光入望園。", "公卿論至道，天子拜昌言。", "雷解初開出，星空即便元。"]'),
('079f54bb-8a3f-472d-a683-014ae7949c7d','廣溪峽','楊炯','唐','唐诗','tang','','[]','廣溪三峽首，曠望兼川陸。',120,'全唐诗/poet.tang.3000.json','["廣溪三峽首，曠望兼川陸。", "山路遶羊腸，江城鎮魚腹。", "喬林百丈偃，飛水千尋瀑。", "驚浪回高天，盤渦轉深谷。", "漢氏昔云季，中原爭逐鹿。", "天下有英雄，襄陽有龍伏。", "常山集軍旅，永安興版築。", "池臺忽已傾，邦家遽淪覆。", "庸才若劉禪，忠佐爲心腹。", "設險猶可存，當無賈生哭。"]'),
('f35edb07-a3de-4188-812f-6066e9b83d33','巫峽','楊炯','唐','唐诗','tang','','[]','三峽七百里，唯言巫峽長。',96,'全唐诗/poet.tang.3000.json','["三峽七百里，唯言巫峽長。", "重巖窅不極，疊嶂凌蒼蒼。", "絕壁橫天險，莓苔爛錦章。", "入夜分明見，無風波浪狂。", "忠信吾所蹈，泛舟亦何傷。", "可以涉砥柱，可以浮呂梁。", "美人今何在？靈芝徒有芳。", "山空夜猿嘯，征客淚沾裳。"]'),
('d4e76a73-6330-478d-8502-83458e18c416','西陵峽','楊炯','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','絕壁聳萬仞，長波射千里。',120,'全唐诗/poet.tang.3000.json','["絕壁聳萬仞，長波射千里。", "盤薄荆之門，滔滔南國紀。", "楚都昔全盛，高丘烜望祀。", "秦兵一旦侵，夷陵火潛起。", "四維不復設，關塞良難恃。", "洞庭且忽焉，孟門終已矣。", "自古天地闢，流爲峽中水。", "行旅相贈言，風濤無極已。", "及余踐斯地，瓌奇信爲美。", "江山若有靈，千載伸知己。"]'),
('c989738d-cb18-4f0d-a353-56e6bc3a3ab3','從軍行','楊炯','唐','唐诗','tang','','["\u6218\u4e89", "\u52b1\u5fd7", "\u521d\u4e2d\u53e4\u8bd7", "\u8fb9\u585e", "\u4e5d\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5916)"]','烽火照西京，心中自不平。',48,'全唐诗/poet.tang.3000.json','["烽火照西京，心中自不平。", "牙璋辭鳳闕，鐵騎繞龍城。", "雪暗凋旗畫，風多雜鼓聲。", "寧爲百夫長，勝作一書生。"]'),
('a66b667d-75bd-4ee9-87ac-773b125d5b29','劉生','楊炯','唐','唐诗','tang','','[]','卿家本六郡，年長入三秦。',48,'全唐诗/poet.tang.3000.json','["卿家本六郡，年長入三秦。", "白璧酬知己，黃金謝主人。", "劍鋒生赤電，馬足起紅塵。", "日暮歌鐘發，喧喧動四鄰。"]'),
('eb0204e5-3ee1-4b08-b0ea-b5480d7af7c8','驄馬','楊炯','唐','唐诗','tang','','[]','驄馬鐵連錢，長安俠少年。',48,'全唐诗/poet.tang.3000.json','["驄馬鐵連錢，長安俠少年。", "帝畿平若水，官路直如弦。", "夜玉妝車軸，秋金鑄馬鞭。", "風霜但自保，窮達任皇天。"]'),
('153ddc69-4ed3-4c91-a13f-01fd8abab905','出塞','楊炯','唐','唐诗','tang','','[]','塞外欲紛紜，雌雄猶未分。',48,'全唐诗/poet.tang.3000.json','["塞外欲紛紜，雌雄猶未分。", "明堂占氣色，華蓋辨星文。", "二月河魁將，三千太乙軍。", "丈夫皆有志，會見立功勳。"]'),
('3389307a-0db9-437e-a686-58794ccd18dc','有所思','楊炯','唐','唐诗','tang','','[]','賤妾留南楚，征夫向北燕。',48,'全唐诗/poet.tang.3000.json','["賤妾留南楚，征夫向北燕。", "三秋方一日，少別比千年。", "不掩嚬紅樓，無論數綠錢。", "相思明月夜，迢遞白雲天。"]'),
('d3b5a394-f179-471b-8855-8b9b6a6ce39d','梅花落','楊炯','唐','唐诗','tang','','["\u601d\u5ff5", "\u548f\u7269\u8bd7", "\u5199\u4eba", "\u548f\u7269"]','窗外一株梅，寒花五出開。',48,'全唐诗/poet.tang.3000.json','["窗外一株梅，寒花五出開。", "影隨朝日遠，香逐便風來。", "泣對銅鈎障，愁看玉鏡臺。", "行人斷消息，春恨幾裴回。"]'),
('82514788-2ea1-4930-80e4-f9ee3fad85fd','折楊柳','楊炯','唐','唐诗','tang','','[]','邊地遙無極，征人去不還。',48,'全唐诗/poet.tang.3000.json','["邊地遙無極，征人去不還。", "秋容凋翠羽，別淚損紅顏。", "望斷流星驛，心馳明月關。", "藁砧何處在？楊柳自堪攀。"]'),
('5d5bda08-dd9e-43cd-820e-ed52b77f35fd','紫騮馬','楊炯','唐','唐诗','tang','','[]','俠客重周遊，金鞭控紫騮。',48,'全唐诗/poet.tang.3000.json','["俠客重周遊，金鞭控紫騮。", "蛇弓白羽箭，鶴轡赤茸鞦。", "發跡來南海，長鳴向北州。", "匈奴今未滅，畫地取封侯。"]'),
('4a19c95f-68ad-4c38-8c03-a3365f32b547','戰城南','楊炯','唐','唐诗','tang','','["\u7231\u56fd", "\u519b\u65c5"]','塞北途遼遠，城南戰苦辛。',48,'全唐诗/poet.tang.3000.json','["塞北途遼遠，城南戰苦辛。", "旛旗如鳥翼，甲胄似魚鱗。", "凍水寒傷馬，悲風愁殺人。", "寸心明白日，千里暗黃塵。"]'),
('4b049fac-a802-4c1d-a741-d8b7a3465d83','送臨津房少府','楊炯','唐','唐诗','tang','','[]','岐路三秋別，江津萬里長。',48,'全唐诗/poet.tang.3000.json','["岐路三秋別，江津萬里長。", "煙霞駐征蓋，弦奏促飛觴。", "階樹含斜日，池風泛早涼。", "贈言未終竟，流涕忽沾裳。"]'),
('7c48e67c-df64-4b13-9de4-7e0dd79d2aef','送豐城王少府','楊炯','唐','唐诗','tang','','[]','愁結亂如麻，長天照落霞。',48,'全唐诗/poet.tang.3000.json','["愁結亂如麻，長天照落霞。", "離亭隱喬樹，溝水浸平沙。", "左尉才何屈，東關望漸賒。", "行看轉牛斗，持此報張華。"]'),
('40eead5d-1119-4d45-b4c5-37152b06a285','送鄭州周司空','楊炯','唐','唐诗','tang','','[]','漢國臨清渭，京城枕濁河。',48,'全唐诗/poet.tang.3000.json','["漢國臨清渭，京城枕濁河。", "居人下珠淚，賓御促驪歌。", "望極關山遠，秋深煙霧多。", "唯餘三五夕，明月暫經過。"]'),
('9bbc999e-ece5-4074-9f2a-ad75a35be097','送梓州周司功','楊炯','唐','唐诗','tang','','[]','御溝一相送，征馬屢盤桓。',48,'全唐诗/poet.tang.3000.json','["御溝一相送，征馬屢盤桓。", "言笑方無日，離憂獨未寬。", "舉杯聊勸酒，破涕暫爲歡。", "別後風清夜，思君蜀路難。"]'),
('5237dd8e-694f-481f-9a00-ef2248894867','送楊處士反初卜居曲江','楊炯','唐','唐诗','tang','','[]','雁門歸去遠，垂老脫袈裟。',48,'全唐诗/poet.tang.3000.json','["雁門歸去遠，垂老脫袈裟。", "蕭寺休爲客，曹溪便寄家。", "綠琪千歲樹，黃槿四時花。", "別怨應無限，門前桂水斜。"]');
